import mapboxgl from 'mapbox-gl';
import type { FeatureCollection, LineString, Point as GeoJsonPoint } from 'geojson';
import type { RouteType } from '../mapbox/mapbox-gl.js';
import type { CoordinatesArray } from '../utility/index.js';

export interface LayerDefinition {
    source: {
        id: string;
        geoJsonData: FeatureCollection<LineString> | FeatureCollection<GeoJsonPoint>;
    };
    layer: mapboxgl.LayerSpecification;
};

export interface Waypoint {
    longitude: number;
    latitude: number;
    name: string | undefined;
    showPin: boolean;
    isRoutable?: boolean; // does this waypoint lie on, or near, a routable line that the directions API can use?
};
export type WayPoints = Waypoint[];

export interface RouteParameters {
    routeType?: RouteType;
    waypoints?: WayPoints;
    showSummary?: "simple" | "detailed";
    showElevationProfile?: boolean;
};

export interface DirectionsParameters {
    geometries: string;
    steps: boolean;
    access_token: string;
    walkway_bias?: number;
    walking_speed?: number;
};

export interface RouteStepData {
    maneuver: {
        location: [number, number];
        instruction: string;
    };
    geometry: {
        coordinates: CoordinatesArray;
    };
    distance: number;
    duration: number;
    name: string;
}

export interface RouteLegData {
    steps: RouteStepData[];
    duration: number;
    distance: number;
};

export interface RouteData {
    geometry: {
        coordinates: CoordinatesArray;
        type: "LineString";
    };
    legs: RouteLegData[];
    distance: number;
    duration: number;
    weight_name: string;
    weight: number;
};

export interface DirectionsResponse {
    routes: RouteData[];
    waypoints: {
        location: [number, number];
        name: string;
    }[];
    code: string;
};