import axios from 'axios';
import mapboxgl from 'mapbox-gl';
import nearestPointOnLine from '@turf/nearest-point-on-line';
import Pbf from 'pbf';
import type { DefinedRouteType, FoundRouteResult, RouteType, SnappedPoint } from '../types.js';
import type { Feature, LineString, MultiLineString } from 'geojson';
import { GEO, MAPBOX } from '../constants.js';
import { getMapboxAccessToken } from '../utility/utility.js';
import { point as turfPoint } from '@turf/helpers';
import { VectorTile } from '../types.js';


/**
 * Utility class for determining the routability of geographic locations on a map
 * for different transportation modes (walking, cycling, driving) using Mapbox vector tiles
 * and rendered map features.
 *
 * The `Routable` class provides static methods to:
 * - Check if a given longitude/latitude point is routable for a specified route type.
 * - Snap points to the nearest routable road or path feature.
 * - Query both rendered map features and Mapbox vector tiles for routable candidates.
 * - Handle different OpenStreetMap (OSM) road/path classes and exclude unsuitable types.
 *
 * Supported route types include walking, cycling, driving, and driving-traffic, each mapped
 * to a set of OSM classes considered routable for that mode.
 *
 * @remarks
 * This class is designed for use with Mapbox GL JS and the Mapbox vector tiles API.
 * It leverages Turf.js for geometric operations such as snapping points to lines.
 * The class is stateless and all methods are static.
 *
 * @example
 * ```typescript
 * const result = await Routable.isRoutable(lngLat, map, accessToken, 'walking');
 * if (result.found) {
 *   // Use result.lngLat as the snapped, routable point
 * }
 * ```
 */
export class Routable {
    /**
     * Maps each route type to a set of OSM (OpenStreetMap) road or path classes that are considered routable for that mode.
     *
     * - `walking`: Includes classes suitable for pedestrian navigation, such as 'pedestrian', 'path', and 'residential'.
     * - `cycling`: Includes classes suitable for bicycles, such as 'track', 'path', and 'residential'.
     * - `driving` and `driving-traffic`: Include classes suitable for motor vehicles, such as 'motorway', 'primary', and 'service'.
     *
     * This mapping is used to determine which road or path types are valid for routing based on the selected mode of transportation.
     *
     * @remarks
     * The keys correspond to route types, and the values are sets of string identifiers representing OSM way classes.
     */
    private static readonly ROUTABLE_CLASSES_BY_MODE: Record<DefinedRouteType, Set<string>> = {
        walking: new Set([
            'trunk', 'pedestrian', 'path', 'track', 'residential', 'service', 'street', 'tertiary', 'secondary', 'unclassified'
        ]),
        cycling: new Set([
            'trunk', 'path', 'track', 'residential', 'service', 'street', 'tertiary', 'secondary', 'unclassified'
        ]),
        driving: new Set([
            'motorway', 'trunk', 'primary', 'secondary', 'tertiary', 'street', 'residential', 'service', 'unclassified'
        ]),
        "driving-traffic": new Set([
            'motorway', 'trunk', 'primary', 'secondary', 'tertiary', 'street', 'residential', 'service', 'unclassified'
        ]),
    };

    /**
     * Set of way types the directions API will ignore and should be considered not routable.
     *
     * These types represent paths or roads that are not suitable for general routing,
     * such as bridleways (for horses), raceways, escape lanes, and roads under construction.
     */
    private static readonly EXCLUDED_TYPES: Set<string> = new Set([
        'bridleway', 'raceway', 'escape', 'construction'
    ]);

    /**
     * Determines if a given geographic location (`lngLat`) is routable based on rendered map features
     * or, if not found, by querying the Mapbox API for nearby routable features.
     *
     * The method first checks rendered features on the map for routability. If no suitable feature is found,
     * it falls back to querying the Mapbox API. The result indicates whether a routable feature was found,
     * along with additional debug information if requested.
     *
     * @param lngLat - The longitude and latitude to check for routability.
     * @param map - The Mapbox GL map instance to query rendered features from.
     * @param accessToken - The Mapbox access token used for API requests.
     * @param routeType - The type of route to check for (e.g., driving, walking). If undefined, returns not found.
     * @param maxGap - The maximum allowed distance (in metres) from the point to a routable feature. Defaults to 40.
     * @param debug - If true, logs debug information to the console. Defaults to false.
     * @returns A promise that resolves to a `FoundRouteResult` indicating if a routable feature was found and related details.
     */
    public static isRoutable = async ({
        lngLat,
        map,
        accessToken,
        routeType,
        maxGap = MAPBOX.DEFAULT_ROUTABLE_MAX_GAP,
        debug = false
    }: {
        lngLat: mapboxgl.LngLat;
        map: mapboxgl.Map;
        routeType: RouteType;
        accessToken?: string;
        maxGap?: number;
        debug?: boolean;
    }): Promise<FoundRouteResult> => {
        if (!routeType) return { found: false };
        if (!accessToken) accessToken = getMapboxAccessToken();

        let result: FoundRouteResult = this._checkRenderedFeatures(
            lngLat,
            map.querySourceFeatures('composite', { sourceLayer: 'road' }),
            routeType,
            maxGap,
            debug
        );

        if (result.found) {
            if (debug) console.debug("Found routable feature in rendered map", result);
            return result;
        } else {
            result = await this._checkApiFeatures(lngLat, accessToken, routeType, maxGap, debug);
            if (debug) console.debug(`${result.found ? "Found" : "No"} routable feature near waypoint via API`, result);
            return result;
        }
    };


    /**
     * Checks a list of rendered GeoJSON features to find the closest routable feature to a given geographic location.
     *
     * @param lngLat - The target geographic location as a `mapboxgl.LngLat` object.
     * @param features - An array of GeoJSON features to search for routable candidates.
     * @param routeType - The type of route to match against feature properties.
     * @param maxGap - The maximum allowed snapping distance (in map units) to consider a feature as a match.
     * @param debug - If true, enables debug logging for failed searches.
     * @returns An object indicating whether a routable feature was found, and if so, the snapped location and optional feature name.
     */
    private static _checkRenderedFeatures = (
        lngLat: mapboxgl.LngLat,
        features: mapboxgl.GeoJSONFeature[],
        routeType: DefinedRouteType,
        maxGap: number,
        debug: boolean
    ): FoundRouteResult => {
        let closest: { dist: number, point: SnappedPoint, name?: string } | null = null;

        for (const feature of features) {
            if (this._isFeatureRoutable(feature.properties, routeType) && feature.geometry) {
                const snapped = this._snapToFeatureGeometry(feature.geometry, lngLat, maxGap, debug);
                if (snapped && (closest === null || snapped.properties.dist < closest.dist)) {
                    closest = {
                        dist: snapped.properties.dist,
                        point: snapped,
                        name: feature.properties?.name as string | undefined
                    };
                }
            }
        }

        if (closest) {
            return {
                found: true,
                lngLat: new mapboxgl.LngLat(closest.point.geometry.coordinates[0], closest.point.geometry.coordinates[1]),
                name: closest.name
            };
        }
        if (debug) console.debug(`Failed to find rendered routable line for ${lngLat.toArray()}`);
        return { found: false };
    };

    /**
     * Checks for routable features near a given geographic point using vector tiles from the Mapbox API.
     *
     * @param lngLat - The longitude and latitude to search around.
     * @param accessToken - The Mapbox access token for API requests.
     * @param routeType - The type of route to check for (e.g., driving, walking).
     * @param maxGap - The maximum allowed distance (in meters) from the point to a routable feature.
     * @param debug - If true, enables debug logging for troubleshooting.
     * @returns A promise that resolves to a `FoundRouteResult` indicating whether a routable feature was found,
     *          and if so, the snapped point and its name.
     *
     * @remarks
     * This method searches for the closest routable road feature within a specified distance from the input point.
     * It fetches vector tiles around the point, checks each feature for routability, and uses Turf.js to find the
     * nearest point on a line. If a suitable feature is found within `maxGap`, it returns the snapped location.
     * Otherwise, it returns a result indicating no routable feature was found.
     */
    private static _checkApiFeatures = async (
        lngLat: mapboxgl.LngLat,
        accessToken: string,
        routeType: DefinedRouteType,
        maxGap: number,
        debug: boolean
    ): Promise<FoundRouteResult> => {
        const z = 14;
        const { x: tileX, y: tileY } = this._lngLatToTile(lngLat.lng, lngLat.lat, z);
        const delta = this._metresToTileDelta(lngLat.lat, maxGap, z);
        const tilesToCheck: { x: number; y: number }[] = [];

        for (let dx = -delta; dx <= delta; dx++) {
            for (let dy = -delta; dy <= delta; dy++) {
                tilesToCheck.push({ x: tileX + dx, y: tileY + dy });
            }
        }

        const searchPoint = turfPoint([lngLat.lng, lngLat.lat]);
        let closest: { dist: number, point: SnappedPoint, name?: string } | null = null;

        for (const { x, y } of tilesToCheck) {
            const tile = await this._fetchVectorTile(z, x, y, accessToken);
            if (!tile?.layers.road) continue;

            for (let i = 0; i < tile.layers.road.length; i++) {
                const feature = tile.layers.road.feature(i);
                const properties = feature.properties;

                if (!this._isFeatureRoutable(properties, routeType)) continue;
                if (feature.type !== 2) continue; // not a LineString

                const geojson = feature.toGeoJSON(x, y, z);
                if (geojson.geometry.type !== "LineString" && geojson.geometry.type !== "MultiLineString") continue;

                try {
                    const snapped = nearestPointOnLine(
                        geojson as Feature<LineString | MultiLineString>,
                        searchPoint,
                        { units: "meters" }
                    );
                    const dist = snapped.properties?.dist ?? Infinity;
                    if (dist <= maxGap && (closest === null || dist < closest.dist)) {
                        closest = {
                            dist,
                            point: snapped,
                            name: properties.name as string | undefined
                        };
                    }
                } catch (err) {
                    if (debug) console.warn(`isAPIRoutable failed for ${lngLat.toArray()}`, err);
                    continue;
                }
            }
        }

        if (closest) {
            return {
                found: true,
                lngLat: new mapboxgl.LngLat(closest.point.geometry.coordinates[0], closest.point.geometry.coordinates[1]),
                name: closest.name
            };
        }

        if (debug) console.debug(`Failed to find routable line for ${lngLat.toArray()} via API`);
        return { found: false };
    };

    /**
     * Determines if a feature is routable based on its properties and the specified route type.
     *
     * @param props - The properties of the feature, which may include `class`, `type`, `foot`, and `bicycle`.
     * @param routeType - The type of route to check for routability (e.g., 'walking', 'cycling').
     * @returns `true` if the feature is routable for the given route type, otherwise `false`.
     *
     * The method checks if the feature's class is included in the allowed classes for the route type.
     * If the feature's type is in the excluded types list, additional checks are performed based on the route type:
     * - For 'walking', the `foot` property must be one of 'yes', 'designated', or 'permissive'.
     * - For 'cycling', the `bicycle` property must be one of 'yes', 'designated', or 'permissive'.
     * If none of these conditions are met, the feature is not considered routable.
     */
    private static _isFeatureRoutable = (props: any, routeType: DefinedRouteType): boolean => {
        const cls = props?.class;
        const type = props?.type;
        const foot = props?.foot;
        const bicycle = props?.bicycle;
        if (!this.ROUTABLE_CLASSES_BY_MODE[routeType].has(cls)) return false;

        if (this.EXCLUDED_TYPES.has(type)) {
            if (routeType === 'walking') return ['yes', 'designated', 'permissive'].includes(foot);
            if (routeType === 'cycling') return ['yes', 'designated', 'permissive'].includes(bicycle);
            return false;
        }
        return true;
    };

    /**
     * Attempts to snap a given longitude/latitude point to the nearest point on a LineString or MultiLineString geometry.
     * 
     * @param geometry - The GeoJSON geometry object to snap to. Must be of type 'LineString' or 'MultiLineString'.
     * @param lngLat - The longitude and latitude to snap, as an object with `lng` and `lat` properties.
     * @param maxGap - The maximum allowed snapping distance in metres. If the nearest point is farther than this, returns null.
     * @param debug - If true, logs warnings to the console when snapping fails.
     * @returns The snapped point as a `SnappedPoint` if within `maxGap`, otherwise `null`.
     */
    private static _snapToFeatureGeometry = (geometry: any, lngLat: mapboxgl.LngLat, maxGap: number, debug: boolean): SnappedPoint | null => {
        try {
            if (geometry.type === 'LineString') {
                const snap = nearestPointOnLine({ type: 'Feature', geometry } as any, [lngLat.lng, lngLat.lat], { units: 'meters' });
                if (snap.properties.dist <= maxGap) return snap;
            } else if (geometry.type === 'MultiLineString') {
                for (const coords of geometry.coordinates) {
                    const snap = nearestPointOnLine(
                        { 
                            type: 'Feature', 
                            geometry: { type: 'LineString', coordinates: coords } 
                        } as any, 
                        [lngLat.lng, lngLat.lat], 
                        { units: 'meters' }
                    );
                    if (snap.properties.dist <= maxGap) return snap;
                }
            }
        } catch (err) {
            if (debug) console.warn("Snap to feature geometry failed", err);
        }
        return null;
    };

    /**
     * Converts geographic coordinates (longitude and latitude) to tile coordinates at a specific zoom level.
     *
     * @param lng - The longitude in degrees.
     * @param lat - The latitude in degrees.
     * @param z - The zoom level (non-negative integer).
     * @returns An object containing the x and y tile coordinates.
     *
     * @remarks
     * This function implements the Web Mercator projection to map geographic coordinates
     * to tile indices used in web mapping applications (e.g., slippy maps).
     */
    private static _lngLatToTile = (lng: number, lat: number, z: number): { x: number; y: number } => {
        const n = 2 ** z;
        const x = Math.floor(((lng + 180) / 360) * n);
        const lat_rad = (lat * Math.PI) / 180;
        const y = Math.floor((1 - Math.log(Math.tan(lat_rad) + 1 / Math.cos(lat_rad)) / Math.PI) / 2 * n);
        return { x, y };
    };

    /**
     * Converts a distance in metres to the equivalent number of map tile units (delta) at a given latitude and zoom level.
     *
     * @param lat - The latitude in degrees where the conversion is performed.
     * @param metres - The distance in metres to convert.
     * @param zoom - The zoom level of the map.
     * @returns The number of tile units (rounded up) that correspond to the given distance in meters at the specified latitude and zoom.
     */
    private static _metresToTileDelta = (lat: number, metres: number, zoom: number): number => {
        const metresPerTile = GEO.EARTH_CIRCUMFERENCE * Math.cos(lat * Math.PI / 180) / (2 ** zoom);
        return Math.ceil(metres / metresPerTile);
    };

    /**
     * Fetches a vector tile from the Mapbox API for the specified zoom level and tile coordinates.
     *
     * @param z - The zoom level of the tile.
     * @param x - The x coordinate of the tile.
     * @param y - The y coordinate of the tile.
     * @param token - The Mapbox access token for authentication.
     * @returns A promise that resolves to a `VectorTile` instance if successful, or `null` if the fetch fails.
     *
     * @remarks
     * The method constructs the tile URL using the provided coordinates and sends a GET request
     * with the access token as a query parameter. The response is expected as an array buffer,
     * which is then parsed into a `VectorTile` object using the `Pbf` library.
     * If the request fails, the error is logged and `null` is returned.
     */
    private static _fetchVectorTile = async (
        z: number,
        x: number,
        y: number,
        token: string
    ): Promise<VectorTile | null> => {
        const url = `${MAPBOX.API_URL}${MAPBOX.STREETS_TILESET_ID}/${z}/${x}/${y}.mvt`;
        try {
            const response = await axios.get(url, {
                params: { access_token: token },
                responseType: 'arraybuffer',
            });

            const buffer = new Uint8Array(response.data);
            return new VectorTile(new Pbf(buffer));
        } catch (error) {
            console.error(`Failed to fetch vector tile z:${z} x:${x} y:${y}`, error);
            return null;
        }
    };
}
