import axios from 'axios';
import mapboxgl from 'mapbox-gl';
import Offcanvas from './OffCanvas.js';
import type { Coordinates, FeatureLayer, FeatureLayerHandler, FeatureLayerSettings, FoundFeatureResult, QueryRenderedFeaturesParams } from '../types.js';
import { getMapboxAccessToken } from '../utility/utility.js';
import { MAPBOX, UI } from '../constants.js';


/**
 * Manages interactive feature layers on a Mapbox map, including event handling, feature querying,
 * and UI integration for displaying feature details.
 *
 * The `FeatureLayerManager` class provides a high-level API for managing a set of feature layers
 * defined by the user, synchronizing them with the current map style, and handling user interactions
 * such as clicks, double-clicks, and mouse events. It supports querying both rendered and unrendered
 * features, integrates with an off-canvas UI for displaying feature details, and dispatches custom
 * events for unmatched features.
 *
 * Key responsibilities:
 * - Tracks and synchronizes active feature layers with the loaded map style.
 * - Attaches and cleans up event listeners for map and feature layer interactions.
 * - Handles click, double-click, and mouse events to display feature information or trigger custom logic.
 * - Supports querying feature names at specific coordinates, using both rendered features and the Mapbox Tilequery API.
 * - Manages feature highlighting and pointer cursor changes on mouse hover.
 * - Integrates with an off-canvas UI component for displaying feature details.
 * - Dispatches custom events for unmatched features to allow external handling.
 *
 * Usage:
 * - Instantiate with a Mapbox map instance, map options, feature layer settings, and optional debug flag.
 * - Call `destroy()` when the manager is no longer needed to clean up resources and event listeners.
 *
 * Events:
 * - Dispatches a `"unmatchedFeature"` event when a click does not match any active feature layer,
 *   providing details about the clicked location and feature name (if available).
 *
 * Example:
 * ```typescript
 * const settings = {
 *   offCanvas: {
 *       classLists: {
 *           panel: ['offcanvas'],
 *           body: ['offcanvas-content'],
 *           closeBtn: ['offcanvas-close-btn'],
 *           overlay: ['offcanvas-overlay']
 *       },
 *       svg: {
 *           closeBtn: 'mapbox-assist--cancel-square'
 *       }
 *   },
 *   apiProximity: 100,
 *   layers: [
 *       {
 *           id: 'doc-huts',
 *           tileId: 'xxx',
 *           handler: docSymbolsHandler
 *       },
 *       {
 *           id: 'doc-campsites',
 *           tileId: 'yyy',
 *           handler: docSymbolsHandler
 *       },
 *   ]
 * }
 * const manager = new FeatureLayerManager(map, mapOptions, settings, true);
 * manager.addEventListener("unmatchedFeature", (e) => {
 *   // Handle unmatched feature click
 * });
 * // ... later
 * manager.destroy();
 * ```
 */
export class FeatureLayerManager extends EventTarget {
    activeFeatureLayers: FeatureLayer[] = []; // filtered set of feature layers present in the loaded style
    private _featureLayers: FeatureLayer[] = [];
    private _mapContainer: HTMLElement;
    private _hadVisibleMarkerOrPopup: boolean = false;
    private _hoveredFeatureId: string | number | null = null;
    private _offcanvas: Offcanvas;
    private _mapOnce?: () => void;
    private _interactionHandlers = new Map<string, {
        mouseenter: (e: mapboxgl.MapMouseEvent) => void;
        mouseleave: () => void;
    }>();
    private _clickTimeout: NodeJS.Timeout | null = null;

    /**
     * Constructs a new Feature instance.
     *
     * @param map - An instance of Mapbox map.
     * @param _mapOptions - A partial MapBox mapboxgl.MapOptions object.
     * @param settings - An instance of FeatureLayerSettings.
     * @param debug - Optional flag to enable debug mode. Defaults to false.
     *
     * Initializes feature layer settings, map references, and offcanvas UI.
     * Sets up event listeners for map style changes and user interactions (click, double-click, mousedown).
     * Ensures event handlers are attached only once after the map style is loaded.
     */
    constructor(
        private readonly map: mapboxgl.Map, 
        private readonly _mapOptions: Partial<mapboxgl.MapOptions>, 
        private readonly settings: FeatureLayerSettings,
        private readonly debug: boolean = false
    ) {
        super();
        this._mapContainer = this.map.getContainer();
        this._featureLayers = this.settings.layers ?? [];
        this._offcanvas = new Offcanvas(this._mapContainer, this.settings.offCanvas);
        this.map.on("styledata", this._handleStyleData);
        this._mapOnce = (): void => {
            this.map.on('click', this._mapClickHandler);
            this.map.on('dblclick', this._mapDblClickHandler);
            this.map.on('mousedown', this._mapMouseDownHandler);
            this.map.off("styledata", this._mapOnce!);
            this._mapOnce = undefined;
        }
        if (this.isStyleLoaded) {
            this._handleStyleData();
            this._mapOnce();
        } else {
            this.map.once("styledata", this._mapOnce);
        }
    }

    /**
     * Cleans up all event listeners and resources associated with the feature.
     *
     * This method:
     * - Clears any pending click timeouts.
     * - Destroys the offcanvas UI component.
     * - Removes all registered event listeners from the map, including style, click, double-click, and mouse events.
     * - Unregisters any one-time style event handlers if present.
     * - Iterates through all interaction handlers for each layer and removes their associated mouse event listeners.
     * - Clears the internal interaction handlers map.
     *
     * Call this method when the feature is no longer needed to prevent memory leaks and unintended behavior.
     */
    destroy(): void {
        this._clearClickTimeout();
        this._offcanvas.destroy();
        this.map.off("styledata", this._handleStyleData);
        this.map.off('click', this._mapClickHandler);
        this.map.off('dblclick', this._mapDblClickHandler);
        this.map.off('mousedown', this._mapMouseDownHandler);
        if (this._mapOnce) this.map.off("styledata", this._mapOnce);
        this._interactionHandlers.forEach((handlers, layerId) => {
            this.map.off("mouseenter", layerId, handlers.mouseenter);
            this.map.off("mouseleave", layerId, handlers.mouseleave);
        });
        this._interactionHandlers.clear();
    }

    /**
     * Handles updates to the map's style data by synchronizing the active feature layers.
     * Checks which of the feature layers are included in the newly loaded style.
     *
     * This method retrieves the current set of layer IDs from the map's style,
     * filters the feature layers to include only those present in the map,
     * and attaches mouse interaction handlers to each active feature layer.
     *
     * @private
     */
    private _handleStyleData = (): void => {
        const mapLayers = new Set(this.map.getStyle()!.layers.map(layer => layer.id));
        this.activeFeatureLayers = this._featureLayers.filter(fl => mapLayers.has(fl.id));
        this.activeFeatureLayers.forEach(layer => this._addMouseInteraction(layer));
    }

    /**
     * Handles the mouse down event on the map container.
     *
     * This method checks for any open and visible Mapbox popups or search markers within the map container
     * when a mouse down event occurs. It determines if any such elements are currently visible on the screen
     * and updates the `_hadVisibleMarkerOrPopup` property accordingly. This information is used by the click handler
     * to decide whether to return early or to show a feature, since popups are already dismissed when the click event is fired.
     *
     * @private
     */
    private _mapMouseDownHandler = (): void => {
        const foundItems = this._mapContainer.querySelectorAll('div.mapboxgl-popup, div.mapboxgl-marker.search-marker');
        const containerRect = this._mapContainer.getBoundingClientRect();
        this._hadVisibleMarkerOrPopup = false;
        foundItems.forEach(item => {
            const popupRect = item.getBoundingClientRect();
            const isOnScreen =
                popupRect.bottom > containerRect.top &&
                popupRect.right > containerRect.left &&
                popupRect.top < containerRect.bottom &&
                popupRect.left < containerRect.right;

            this._hadVisibleMarkerOrPopup = this._hadVisibleMarkerOrPopup || isOnScreen;
        });
    }

    /**
     * Handles the map's double-click event.
     * 
     * This handler suppresses the display of features when the map is double-clicked
     * by clearing any pending click timeouts.
     *
     * @param e - The map mouse event triggered by the double-click.
     */
    private _mapDblClickHandler = (e: mapboxgl.MapMouseEvent): void => {
        // supress showing the features if map double clicked
        this._clearClickTimeout();
    }

    /**
     * Handles map click events with debouncing to prevent multiple triggers from double clicks.
     * 
     * When a map click event occurs, this handler sets a timeout to delay the execution of the feature display logic.
     * If another click event is received before the timeout expires, the handler ignores it, effectively debouncing rapid clicks.
     * 
     * @param e - The map mouse event containing information about the click.
     */
    private _mapClickHandler = (e: mapboxgl.MapMouseEvent): void => {
        // debounce click in case of double click event
        if (this._clickTimeout) return;
        this._clickTimeout = setTimeout(() => {
            this._clickTimeout = null;
            this._showFeature(e);
        }, UI.DOUBLE_CLICK_DELAY);
    }

    /**
     * Clears the current click timeout, if one exists.
     * 
     * This method checks if a click timeout is set, and if so, clears it using `clearTimeout`
     * and resets the timeout reference to `null`. This helps prevent unintended execution
     * of delayed click handlers.
     *
     * @private
     */
    private _clearClickTimeout(): void {
        if (this._clickTimeout) {
            clearTimeout(this._clickTimeout);
            this._clickTimeout = null;
        }
    }

    /**
     * Handles the display of features when the map is clicked.
     *
     * This method searches for features at the clicked point on the map and determines how to handle them:
     * - If a feature from the active feature layers is found (excluding the "route-waypoints-layer"), it parses any stringified array properties,
     *   invokes the associated handler, and displays the resulting content in an off-canvas panel. It also clears any existing popups.
     * - If no active feature is found, it removes any search markers (unless the click was on a search marker), and checks if a marker or popup was visible,
     *   or if the search box was open, in which case it simply returns.
     * - Otherwise, it looks for a standard map feature with a name attribute, determines the appropriate coordinates and popup options,
     *   and dispatches a custom "unmatchedFeature" event with details about the clicked point.
     *
     * @param e - The map mouse event containing information about the click location and event target.
     * @returns A promise that resolves when the feature handling is complete.
     */
    private _showFeature = async (e: mapboxgl.MapMouseEvent): Promise<void> => {
        try {
            // Search for feature on clicked point
            const renderedFeatures = this.map.queryRenderedFeatures(e.point);
            // skip featured layers if route waypoint clicked
            if (renderedFeatures.at(0)?.layer?.id !== "route-waypoints-layer") {
                // search for feature in activeFeatureLayers
                const matchedFeature: mapboxgl.GeoJSONFeature | null = this._getMatchedFeature(renderedFeatures);
                if (matchedFeature) {
                    if (matchedFeature.properties) {
                        Object.keys(matchedFeature.properties).forEach(key => {
                            if (typeof matchedFeature.properties![key] === "string") {
                                try {
                                    const parsed = JSON.parse(matchedFeature.properties![key]);
                                    if (Array.isArray(parsed)) {
                                        matchedFeature.properties![key] = parsed;
                                    }
                                } catch (error) {
                                    // Not a JSON string, ignore
                                }
                            }
                        });
                        const featureLayer = this.activeFeatureLayers.find(layer => layer.id === matchedFeature.layer!.id)
                        const handler = featureLayer?.handler;
                        if (handler) {
                            const offCanvasBody: string | HTMLElement | DocumentFragment | undefined | null = await handler(matchedFeature, this.map);
                            if (offCanvasBody) {
                                this._offcanvas.show(offCanvasBody);
                            }
                            // clear any popups
                            this._mapContainer.querySelectorAll('div.mapboxgl-popup').forEach((item) => {
                                item.remove();
                            });
                            return;
                        }
                    }
                }
            }

            // no feature in activeFeatureLayers
            // remove any search markers
            if (!(e.originalEvent.target as HTMLElement).closest('div.mapboxgl-marker.search-marker'))
                this._mapContainer.querySelectorAll('div.mapboxgl-marker.search-marker').forEach((item) => {
                    item.remove();
                });
            // if popup or search marker had been open and visible on mouse down, just return (clicking on map dismisses open & visible popup)
            // if search box is open, just return (clicking map closes searchbox)
            if (this._hadVisibleMarkerOrPopup || this._mapContainer.querySelector('div.searchbox--focused')) {
                return;
            }
            // look for standard map feature - any type of feature with a name attribute
            const unmatchedFeature = this._getUnmatchedFeature(e.point, renderedFeatures);
            // snap to geometry coordinates of feature if point or symbol
            const lngLat: mapboxgl.LngLat = unmatchedFeature?.lngLat || e.lngLat;
            const options: mapboxgl.PopupOptions = (
                renderedFeatures.at(0)?.layer?.id === "route-waypoints-layer") 
                    ? { offset: MAPBOX.POPUP_OFFSET } 
                    : {};
            // dispatch event with clicked point details for handling on the wrapping class
            const unmatchedFeatureEvent = new CustomEvent(
                "unmatchedFeature", {
                detail: {
                    lngLat: lngLat,
                    label: unmatchedFeature?.name,
                    popupOptions: options
                }
            });
            this.dispatchEvent(unmatchedFeatureEvent);
        } catch (error) {
            console.error('FeatureLayerManager._showFeature() encountered an error', error);
        }
    }

    /**
     * Returns the first feature from the provided array whose layer ID matches the order of active feature layers.
     *
     * Iterates through the `activeFeatureLayers` in order, and for each layer, searches the `features` array
     * for a feature whose `layer.id` matches the current layer's ID. Returns the first matching feature found.
     * If no matching feature is found, returns `null`.
     *
     * @param features - An array of GeoJSON features to search through.
     * @returns The first matching GeoJSON feature based on the active layer order, or `null` if no match is found.
     */
    private _getMatchedFeature = (features: mapboxgl.GeoJSONFeature[]): mapboxgl.GeoJSONFeature | null => {
        const layerIdOrder = this.activeFeatureLayers.map(layer => layer.id);
        for (const layerId of layerIdOrder) {
            const match = features.find(f => f.layer?.id === layerId);
            if (match) return match;
        }
        return null;
    }

    /**
     * Attempts to find an unmatched feature from a list of GeoJSON features based on the presence of a `name` property.
     * If found, retrieves the localized name (based on the user's language or English fallback) and, if the feature is a point or symbol,
     * attempts to re-query the map for the full geometry to obtain precise coordinates.
     *
     * @param point - The screen point to use for querying rendered features.
     * @param features - An array of GeoJSON features to search for an unmatched feature.
     * @returns An object containing the feature's name and its coordinates as a `mapboxgl.LngLat` instance (or `null` if not available),
     *          or `null` if no unmatched feature is found.
     */
    private _getUnmatchedFeature = (point: mapboxgl.Point, features: mapboxgl.GeoJSONFeature[]): {
        name: string,
        lngLat: mapboxgl.LngLat | null
    } | null => {
        try {
            const unMatchedFeature = features.find(obj => obj?.properties?.name);
            if (unMatchedFeature) {
                let lngLat: mapboxgl.LngLat | null = null;
                const lang: string = navigator.language.slice(0, 2).toLowerCase();
                const name: string = unMatchedFeature.properties![`name_${lang}`] ||
                    unMatchedFeature.properties!['name_en'] ||
                    unMatchedFeature.properties!.name;
                if (["point", "symbol"].includes(unMatchedFeature.layer!.type)) {
                    // requery to get full geometry and snap to feature coordinates
                    if (unMatchedFeature?.layer?.id) {
                        let featureWithGeometry: mapboxgl.GeoJSONFeature | undefined;
                        const candidates = this.map.queryRenderedFeatures(point, {
                            layers: [unMatchedFeature.layer.id],
                        });

                        featureWithGeometry = candidates.find(f =>
                            f.properties?.id === unMatchedFeature.properties?.id ||
                            f.properties?.name === unMatchedFeature.properties?.name
                        );
                        if (featureWithGeometry?.geometry?.type === "Point") {
                            const position = (featureWithGeometry.geometry as GeoJSON.Point).coordinates;
                            if (Array.isArray(position) && position.length === 2) {
                                lngLat = new mapboxgl.LngLat(position[0], position[1]);
                            }
                        }
                    }
                }
                return { name: name, lngLat: lngLat };
            }
        } catch (error) {
            console.error('FeatureLayer:__getUnmatchedFeature() encountered an error', error)
        }
        return null;
    }

    /**
     * Finds the name of a feature at the given coordinates.
     *
     * This method attempts to retrieve the feature name by first checking rendered features
     * in the active feature layers. If no name is found, it queries an API for unrendered
     * active features. If still unsuccessful, it checks all rendered map features.
     *
     * @param coord - The [longitude, latitude] coordinates to search for a feature.
     * @returns A promise that resolves to an object containing the feature name (if found) and the corresponding mapboxgl.LngLat.
     */
    findFeatureNameAtCoord = async (coord: Coordinates): Promise<FoundFeatureResult> => {
        let name: string | undefined;
        let lngLat: mapboxgl.LngLat = new mapboxgl.LngLat(coord[0], coord[1]);
        if (this.activeFeatureLayers?.length > 0) {
            // try rendered active feature
            ({ name, lngLat } = this.getRenderedFeatureName(lngLat, { layers: this.activeFeatureLayers.map(layer => layer.id) }));
            // try api for unrendered active feature
            if (!name) ({ name, lngLat } = await this.getActiveFeatureNameByAPI(lngLat));
        }
        // try rendered map feature
        if (!name) ({ name, lngLat } = this.getRenderedFeatureName(lngLat));
        return { name, lngLat };
    }

    /**
     * Searches for a rendered feature at the given longitude and latitude (`lngLat`) that has a `name` property,
     * returning the topmost such feature's name and coordinates. If the feature is of type "point" or "symbol",
     * the method re-queries to obtain the full geometry and snaps the returned coordinates to the feature's actual location.
     *
     * @param lngLat - The longitude and latitude to query for rendered features.
     * @param options - Optional parameters for querying rendered features.
     * @returns An object containing the found feature's `name` (if any) and the possibly updated `lngLat`.
     */
    getRenderedFeatureName = (lngLat: mapboxgl.LngLat, options?: QueryRenderedFeaturesParams): FoundFeatureResult => {
        // search for a feature with name attribute, topmost one will be used
        // if symbol or point, set coordinates to match the feature coordinates
        const point = this.map.project(lngLat);
        let name: string | undefined;
        let clickedFeature = this.map.queryRenderedFeatures(
            point
        ).find(obj => obj?.properties?.name);
        if (clickedFeature) {
            name = clickedFeature.properties!.name;
            if (["point", "symbol"].includes(clickedFeature.layer!.type)) {
                // requery to get full geometry and snap to feature coordinates
                if (clickedFeature?.layer?.id) {
                    let featureWithGeometry: mapboxgl.GeoJSONFeature | undefined;
                    const candidates = this.map.queryRenderedFeatures(point, {
                        layers: [clickedFeature.layer.id],
                    });
                    featureWithGeometry = candidates.find(f =>
                        f.properties?.id === clickedFeature.properties?.id ||
                        f.properties?.name === clickedFeature.properties?.name
                    );
                    if (featureWithGeometry?.geometry?.type === "Point") {
                        const coords = (featureWithGeometry.geometry as GeoJSON.Point).coordinates;
                        lngLat = new mapboxgl.LngLat(coords[0], coords[1]);
                    }
                }
            }
            if (this.debug && name) console.debug('Feature.getRenderedFeatureName: found name', name);
        }
        return { name, lngLat };
    }

    /**
     * Queries Mapbox Tilequery API across active feature layers to find the first feature
     * near the given coordinate that contains a `name` property.
     *
     * @param lngLat - The longitude and latitude of the point to query.
     * @returns A promise that resolves to an object containing the found name (if any) and the original coordinate.
     *
     * The search respects the proximity radius defined in `this.settings.apiProximity`, and
     * only queries layers with a defined `tileId`. If multiple features are returned, the first
     * with a valid `name` property is selected.
     *
     * Logs the found name to console if `this.debug` is enabled.
     */
    getActiveFeatureNameByAPI = async (lngLat: mapboxgl.LngLat): Promise<FoundFeatureResult> => {
        if (!this.activeFeatureLayers) return { name: undefined, lngLat: lngLat };
        const requests = this.activeFeatureLayers
            .filter(layer => layer.tileId)
            .map(async layer => {
                const url = `${MAPBOX.API_URL}${layer.tileId}/tilequery/${lngLat.lng},${lngLat.lat}.json`;
                const params = {
                    radius: this.settings.apiProximity,
                    access_token: this._mapOptions.accessToken || getMapboxAccessToken()
                };

                try {
                    const response = await axios.get(url, { params });
                    return response.data.features ?? [];
                } catch (error) {
                    console.error("Error querying feature:", error);
                    return [];
                }
            });


        const results = await Promise.all(requests);

        // Flatten the results array (removing empty arrays) and return the first found feature with a name property
        const allFeatures = results.flat();
        const featureWithName = allFeatures.find(f => !!f.properties?.name);
        if (this.debug && featureWithName?.properties?.name) 
            console.debug('Feature.getActiveFeatureNameByAPI: found name', featureWithName?.properties?.name);
        const name: string | undefined = featureWithName?.properties?.name;
        return { name, lngLat };
    }

    /**
     * Adds mouse interaction event handlers to a specified feature layer on the map.
     *
     * This method sets up `mouseenter` and `mouseleave` event listeners for the given feature layer.
     * On mouse enter, it highlights the feature under the cursor by setting its feature state to `hover: true`
     * and changes the cursor to a pointer. On mouse leave, it removes the highlight and resets the cursor.
     * The event handler references are stored for later removal or management.
     *
     * @param featureLayer - The feature layer to which mouse interaction handlers will be attached.
     */
    private _addMouseInteraction = (featureLayer: FeatureLayer): void => {
        const layer = this.map.getLayer(featureLayer.id) as mapboxgl.LayerSpecification;
        if (!layer) return;
        // Define handlers and store references
        const mouseenterHandler = (e: mapboxgl.MapMouseEvent) => {
            if (!e.features || e.features.length === 0) return;
            const featureId = e.features[0].id;
            if (featureId !== undefined) {
                this._hoveredFeatureId = featureId;
                this.map.setFeatureState({
                    source: layer.source,
                    sourceLayer: (layer as any)['source-layer'],
                    id: featureId
                } as mapboxgl.FeatureSelector, { hover: true });
            }
            this.map.getCanvas().style.cursor = "pointer";
        };
        const mouseleaveHandler = () => {
            if (this._hoveredFeatureId !== null) {
                this.map.setFeatureState({
                    source: layer.source,
                    sourceLayer: (layer as any)['source-layer'],
                    id: this._hoveredFeatureId
                } as mapboxgl.FeatureSelector, { hover: false });
                this._hoveredFeatureId = null;
            }
            this.map.getCanvas().style.cursor = "";
        };
        // Add event listeners
        this.map.on("mouseenter", featureLayer.id, mouseenterHandler);
        this.map.on("mouseleave", featureLayer.id, mouseleaveHandler);
        // Save the handlers
        this._interactionHandlers.set(featureLayer.id, {
            mouseenter: mouseenterHandler,
            mouseleave: mouseleaveHandler,
        });
    }

    /**
     * Indicates whether the map's style has been successfully loaded.
     *
     * @returns `true` if `getStyle()` does not throw an error, implying the style is available;
     * otherwise, `false`.
     */
    get isStyleLoaded(): boolean {
        try {
            this.map?.getStyle();
            return true;
        } catch {
            return false;
        }
    }
}
