import mapboxgl from 'mapbox-gl';
import type { CoordsPopupSettings } from '../types.js';
import { svgFromId } from '../utility/utility.js';

/**
 * A custom popup class for displaying coordinates and elevation information on a Mapbox map.
 * 
 * Extends the base `mapboxgl.Popup` class to provide a formatted popup containing:
 * - Latitude and longitude (with optional label)
 * - A link to Google Maps for the coordinates
 * - A clipboard button to copy the coordinates
 * - Elevation information (if available from the map's terrain data)
 * 
 * @remarks
 * The popup's appearance and labels are customizable via the `CoordsPopupSettings` parameter.
 * 
 * @example
 * ```typescript
 * const popup = new CoordsPopup(map, settings);
 * popup.setCoordsHTML([lng, lat], "My Location").addTo(map);
 * ```
 * 
 * @param map - The Mapbox map instance to query for elevation and context.
 * @param settings - Configuration for class lists, labels, and icons used in the popup.
 * @param debug - Optional flag to enable debug mode.
 */
export class CoordsPopup extends mapboxgl.Popup {
    constructor(private map: mapboxgl.Map, public settings: CoordsPopupSettings, private debug: boolean = false) {
        super({ ...settings.options });
    }

    /**
     * Sets the HTML content of the popup to display coordinates, an optional label, and elevation information.
     *
     * This method creates a structured HTML fragment containing:
     * - An optional label as a title.
     * - The latitude and longitude as a clickable link to Google Maps.
     * - A clipboard button to copy the coordinates.
     * - The terrain elevation at the specified location, if available.
     *
     * @param lngLat - The geographic coordinates (latitude and longitude) to display. Accepts any value convertible by `mapboxgl.LngLat.convert`.
     * @param label - (Optional) A label to display above the coordinates.
     * @returns The current instance for method chaining.
     */
    setCoordsHTML(lngLat: mapboxgl.LngLatLike, label?: string): this {
        lngLat = mapboxgl.LngLat.convert(lngLat);
        const elevation = this.map.queryTerrainElevation(lngLat, { exaggerated: false });
        const coordinatesLabel = `${lngLat.lat.toFixed(5)},${lngLat.lng.toFixed(5)}`; // convert to lat,lng string
        const coordinatesString = `${lngLat.lat},${lngLat.lng}`; // convert to lat,lng string
        const contentsFragment: DocumentFragment = document.createDocumentFragment();
        const container: HTMLDivElement = document.createElement('div');
        container.classList.add(...this.settings.classlists.body);
        contentsFragment.append(container);
        if (label) {
            const labelContainer: HTMLDivElement = document.createElement('div');
            labelContainer.classList.add(...this.settings.classlists.title);
            labelContainer.textContent = label;
            container.append(labelContainer);
        }
        const coordsContainer: HTMLDivElement = document.createElement('div');
        coordsContainer.classList.add(...this.settings.classlists.coordsContainer);
        container.append(coordsContainer);
        const coordsLink: HTMLAnchorElement = document.createElement('a');
        coordsLink.classList.add(...this.settings.classlists.coordsLink);
        coordsLink.href = `https://www.google.com/maps?q=${coordinatesString}`;
        coordsLink.title = this.settings.labels.coordsLink;
        coordsLink.target = "_blank";
        coordsLink.textContent = coordinatesLabel.replace(',', ', ');
        const clipboardLink: HTMLAnchorElement = document.createElement('a');
        clipboardLink.classList.add(...this.settings.classlists.clipboardLink);
        clipboardLink.title = this.settings.labels.clipboardLink;
        clipboardLink.append(svgFromId(this.settings.icons.clipboardSVGid));
        clipboardLink.addEventListener('click', () => navigator.clipboard.writeText(coordinatesString));
        coordsContainer.append(coordsLink, clipboardLink);
        if (elevation) {
            const elevationContainer: HTMLDivElement = document.createElement('div');
            elevationContainer.classList.add(...this.settings.classlists.elevation);
            elevationContainer.textContent = `${Math.round(elevation)}${this.settings.labels.elevationUnits} `;
            const span = document.createElement('span');
            span.textContent = `(${this.settings.labels.estimated})`
            elevationContainer.append(span);
            container.append(elevationContainer);
        }
        super.setDOMContent(container);
        super.setLngLat(lngLat);
        return this;
    }
}
