import mapboxgl from 'mapbox-gl';

/**
 * Parameters for querying rendered features from a map layer.
 *
 * @property layers - Optional array of layer IDs to include in the query. If not specified, all layers are considered.
 * @property filter - Optional filter specification to limit the returned features based on certain criteria.
 * @property validate - Optional flag to enable or disable validation of the filter. Defaults to `false` if not provided.
 * @property target - Reserved for future use. Should not be set.
 */
export interface QueryRenderedFeaturesParams {
    layers?: string[];
    filter?: mapboxgl.FilterSpecification;
    validate?: boolean;
    target?: never;
};

/**
 * Represents the result of a feature search, containing the feature's name (if found)
 * and its geographic coordinates.
 *
 * @property name - The name of the found feature, or `undefined` if not available.
 * @property lngLat - The longitude and latitude coordinates of the found feature.
 */
export interface FoundFeatureResult {
    name: string | undefined;
    lngLat: mapboxgl.LngLat
}