import mapboxgl from 'mapbox-gl';
import type { Feature, Point as GeoJsonPoint } from 'geojson';

/**
 * Represents the result of attempting to find a route.
 *
 * @property found - Indicates whether a route was successfully found.
 * @property lngLat - The longitude and latitude of the closest point on the found route, if available.
 * @property name - The name of the found route, if available.
 */
export interface FoundRouteResult {
    found: boolean;
    lngLat?: mapboxgl.LngLat;
    name?: string | undefined;
}

/**
 * Represents a GeoJSON mapboxgl.Point feature that has been "snapped" to a route or geometry,
 * with additional metadata describing its relationship to the original geometry.
 *
 * @template TProperties - The properties object for the feature, extended with snapping metadata.
 * @property {number} dist - The distance from the original point to the snapped location.
 * @property {number} index - The index of the closest segment or point in the geometry.
 * @property {number} multiFeatureIndex - The index of the feature in a MultiFeature collection, if applicable.
 * @property {number} location - The position along the geometry (e.g., line distance or fraction).
 * @property {Record<string, any>} [key: string] - Additional arbitrary properties.
 */
export type SnappedPoint = Feature<GeoJsonPoint, {
    dist: number;
    index: number;
    multiFeatureIndex: number;
    location: number;
    [key: string]: any;
}>