import mapboxgl from 'mapbox-gl';
import type { 
    BoundingBox, Coordinates, CoordinatesArray, FitBoundsSettings, 
    GeoCircle, ScreenBox, Waypoint, WayPoints 
} from '../types.js';
import { GEO } from '../constants.js';
import { Rectangle } from '../utility/utility.js';


/**
 * A utility class for managing map bounds and fitting content to the viewport.
 * Extends EventTarget to dispatch custom events when bounds operations complete.
 * 
 * This class provides methods to:
 * - Calculate and manage map bounds for a set of geographic points
 * - Handle pitched and rotated map views
 * - Apply relative and absolute padding
 * - Convert between screen and geographic coordinates
 * - Debug bounds visualization
 * 
 * @fires fitScreenBoundsEnd - Dispatched when the map has finished fitting to bounds
 * 
 * @example
 * ```typescript
 * // Create instance with map and points
 * const bounds = new FitBounds(
 *   map,
 *   { relativePadding: { top: 10, bottom: 10, left: 10, right: 10 } },
 *   [[lng1, lat1], [lng2, lat2]],
 *   true // debug mode
 * );
 * 
 * // Fit map to points
 * bounds.fitScreenBounds();
 * 
 * // Listen for completion
 * bounds.addEventListener('fitScreenBoundsEnd', () => {
 *   console.debug('Finished fitting to bounds');
 * });
 * ```
 */
export default class FitBounds extends EventTarget {
    private mapContainer: HTMLElement;
    private _points: CoordinatesArray = [];
    private debug: boolean = false;
    private relativePadding?: mapboxgl.PaddingOptions;

    /**
     * Constructs a new instance of the class, initializing it with the provided Mapbox map,
     * optional fit bounds settings, points, and debug flag.
     *
     * @param map - The Mapbox map instance to operate on.
     * @param settings - Optional settings for fitting bounds, such as padding and animation options.
     * @param points - Optional points to be used for calculating bounds. Can be an array of coordinates,
     *   mapboxgl.LngLat objects, mapboxgl.LngLatBounds, WayPoints, GeoCircle, or undefined.
     * @param debug - Optional flag to enable debug mode. Defaults to false.
     */
    constructor(
        private map: mapboxgl.Map,
        settings: FitBoundsSettings = {},
        points: CoordinatesArray | mapboxgl.LngLat[] | mapboxgl.LngLatBounds | WayPoints | GeoCircle | undefined = undefined,
        debug: boolean = false
    ) {
        super();
        this.mapContainer = this.map.getContainer();
        if (points) this.points = points;

        if (settings.relativePadding) {
            this.relativePadding = this._normalizePadding(settings.relativePadding);
        }
        this.debug = debug;
    }
    
    /**
     * Cleans up the instance by resetting its properties to their default or empty states.
     * This method should be called when the instance is no longer needed to help with memory management.
     *
     * @remarks
     * - Sets `mapContainer` to `null`.
     * - Empties the `_points` array.
     * - Sets `relativePadding` to `undefined`.
     * - Disables debugging by setting `debug` to `false`.
     */
    destroy(): void {
        this.mapContainer = null!;
        this._points = [];
        this.relativePadding = undefined;
        this.debug = false;
    }

    /**
     * Sets the points for the bounds object.
     *
     * Accepts various types of input representing geographic coordinates, including:
     * - `CoordinatesArray`: An array of coordinate pairs.
     * - `mapboxgl.LngLat[]`: An array of longitude/latitude objects.
     * - `mapboxgl.LngLatBounds`: An object representing a bounding box.
     * - `WayPoints`: An array or object representing waypoints.
     * - `GeoCircle`: An object representing a geographic circle.
     *
     * The input is normalized and stored internally as an array of points.
     *
     * @param points - The geographic points or bounds to set.
     */
    set points(points: CoordinatesArray | mapboxgl.LngLat[] | mapboxgl.LngLatBounds | WayPoints | GeoCircle) {
        this._points = this._getPointsArray(points);
    }

    /**
     * Gets the array of coordinates that define the points of the bounds.
     *
     * @returns {CoordinatesArray} The array of coordinate points.
     */
    get points(): CoordinatesArray {
        return this._points;
    }


    /**
     * Converts various input types representing geographical points into a standardized array of coordinates.
     * 
     * @param points - The input data representing geographical points. It can be one of the following types:
     *   - `CoordinatesArray`: An array of `[longitude, latitude]` pairs.
     *   - `mapboxgl.LngLat[]`: An array of `mapboxgl.LngLat` objects.
     *   - `WayPoints`: An array of `Waypoint` objects, each containing `longitude` and `latitude` properties.
     *   - `GeoCircle`: An object representing a geographical circle with a `center` and `radiusKm`.
     * 
     * @returns A `CoordinatesArray`, which is an array of `[longitude, latitude]` pairs.
     * 
     * @throws An error if the input does not contain at least two points or is invalid.
     */
    private _getPointsArray = (points: CoordinatesArray | mapboxgl.LngLat[] | mapboxgl.LngLatBounds | WayPoints | GeoCircle): CoordinatesArray => {
        // ensure points in an array of [lng, lat] values
        const isWaypointArray = (points: any): points is WayPoints => {
            return points.length > 1 && typeof points[0].longitude === 'number' && typeof points[0].latitude === 'number';
        }
        const isLngLatArray = (points: any): points is mapboxgl.LngLat[] => {
            return points.length > 1 && points[0] instanceof mapboxgl.LngLat;
        }
        const isGeoCircle = (value: unknown): value is GeoCircle =>
            !!value &&
            typeof value === 'object' &&
            'center' in value &&
            typeof (value as GeoCircle).radiusKm === 'number';

        if (isGeoCircle(points)) {
            points = this.getCoordinatesArrayFromCircle(points)
        }
        if (isWaypointArray(points)) {
            // Waypoints array - convert to [lng, lat]
            return points.map(
                (waypoint: Waypoint) => [waypoint.longitude, waypoint.latitude]
            );
        } else if (isLngLatArray(points)) {
            // mapboxgl.LngLat array - convert to [lng, lat]
            console.debug('isLngLatArray')
            return points.map(
                (point: mapboxgl.LngLat) => point.toArray()
            );
        } else if (points instanceof mapboxgl.LngLatBounds) {
            // mapboxgl.LngLatBounds - convert to [lng, lat]
            return [
                points.getSouthWest().toArray(),
                points.getNorthEast().toArray()
            ];
        }
        if (!points || points.length < 2)
            throw new Error(`At least 2 points are required. Received points: ${points}`);
        return points;
    }

    /**
     * Calculates the absolute padding for the map container.
     * 
     * If `relativePadding` is not defined, it returns the current padding of the map
     * or `0` if no padding is set. Otherwise, it computes the absolute padding values
     * based on the `relativePadding` percentages and the dimensions of the map container.
     * 
     * @returns {mapboxgl.PaddingOptions} The absolute padding values for each side of the container.
     */
    get absolutePadding(): mapboxgl.PaddingOptions {
        if (!this.relativePadding) return this.map.getPadding() ?? 0;
        const { offsetHeight: height, offsetWidth: width } = this.mapContainer;
        return Object.fromEntries(
            Object.entries(this.relativePadding).map(([key, value]) => [
                key,
                ((key === 'top' || key === 'bottom') ? height : width) * value / 100
            ])
        );
    }

    /**
     * Generates an array of coordinates representing points on the circumference of a circle.
     * The circle is defined by its center and radius in kilometres.
     *
     * @param geoCircle - The GeoCircle object containing the center and radius.
     * @param pointCount - The number of points to generate around the circle. Defaults to 12.
     * @returns {CoordinatesArray} An array of coordinates representing points on the circle's circumference.
     */
    private getCoordinatesArrayFromCircle(geoCircle: GeoCircle, pointCount: number = 12): CoordinatesArray {
        const { center, radiusKm } = geoCircle;
        const lngLatCenter = center instanceof mapboxgl.LngLat ? center : new mapboxgl.LngLat(center[0], center[1]);
        const lat1 = (lngLatCenter.lat * Math.PI) / 180;
        const lon1 = (lngLatCenter.lng * Math.PI) / 180;

        const coordinates: CoordinatesArray = [];

        for (let i = 0; i < pointCount; i++) {
            const angle = (2 * Math.PI * i) / pointCount; // Bearing in radians
            const lat2 = Math.asin(
                Math.sin(lat1) * Math.cos(radiusKm / GEO.EARTH_RADIUS_KM) +
                Math.cos(lat1) * Math.sin(radiusKm / GEO.EARTH_RADIUS_KM) * Math.cos(angle)
            );
            const lon2 =
                lon1 +
                Math.atan2(
                    Math.sin(angle) * Math.sin(radiusKm / GEO.EARTH_RADIUS_KM) * Math.cos(lat1),
                    Math.cos(radiusKm / GEO.EARTH_RADIUS_KM) - Math.sin(lat1) * Math.sin(lat2)
                );

            // Convert back to degrees
            coordinates.push([lon2 * 180 / Math.PI, lat2 * 180 / Math.PI]);
        }

        return coordinates;
    }

    /**
     * Calculates and returns the aligned bounding box for a set of points.
     * This method assumes that the map's bearing and pitch are zero.
     *
     * @returns {mapboxgl.LngLatBounds} The bounding box that encompasses all the points,
     * aligned to the minimum and maximum x and y coordinates.
     *
     * @remarks
     * - The method iterates through all points to determine the southwest (minimum x, y)
     *   and northeast (maximum x, y) corners of the bounding box.
     * - If `this.debug` is enabled, the method logs the points and the resulting bounding box
     *   to the console for debugging purposes.
     */
    public getAlignedBounds(): mapboxgl.LngLatBounds {
        // simplified method to find bounds, assumes bearing and pitch are zero
        const { swX, neX, swY, neY } = (this.points).reduce(
            (acc, [x, y]) => ({
                swX: Math.min(acc.swX, x),
                neX: Math.max(acc.neX, x),
                swY: Math.min(acc.swY, y),
                neY: Math.max(acc.neY, y),
            }),
            { swX: Infinity, neX: -Infinity, swY: Infinity, neY: -Infinity }
        );
        const bbox: mapboxgl.LngLatBounds = new mapboxgl.LngLatBounds([[swX, swY], [neX, neY]])
        if (this.debug) {
            console.debug(
                'FitBounds.fitAlignedBounds(): ',
                'bbox: ', bbox
            );
        }
        return bbox;
    }

    /**
     * Adjusts the map view to fit the aligned bounds while preserving the current pitch and bearing,
     * unless explicitly overridden in the provided options. The method also applies absolute padding
     * to the fit bounds operation and optionally visualizes the bounds for debugging purposes.
     * 
     * Absolute padding is converted from the relativePadding attribute if set, otherwise the exiasting 
     * map padding is used
     *
     * @param options - Optional configuration for the `fitBounds` operation. Defaults to an empty object.
     *   - `pitch` - The pitch of the map view. Defaults to the current map pitch if not provided.
     *   - `bearing` - The bearing of the map view. Defaults to the current map bearing if not provided.
     *   - `padding` - Automatically set to the absolute padding of the map.
     *
     * @returns The `mapboxgl.Map` instance for chaining further operations.
     */
    public fitAlignedBounds(options: mapboxgl.MapOptions['fitBoundsOptions'] = {}): mapboxgl.Map {
        if (!options.pitch) options.pitch = this.map.getPitch();
        if (!options.bearing) options.bearing = this.map.getBearing();
        options.padding = this.absolutePadding;
        const bbox: mapboxgl.LngLatBounds = this.getAlignedBounds();
        if (this.debug) {
            this._drawBounds(
                bbox.getNorthEast().toArray(),
                bbox.getNorthWest().toArray(),
                bbox.getSouthWest().toArray(),
                bbox.getSouthEast().toArray(),
                'aligned-bounds',
                'red'
            );
        }
        return this.map.stop().fitBounds(bbox, options);
    }

    /**
     * Calculates and returns the bounding box of the points coordinates attribute in both screen space and geographic coordinates.
     *
     * @returns {BoundingBox} An object containing the bounding box information:
     * - `screen`: The bounding box in screen space, including vertices and center point.
     * - `geo`: The bounding box in geographic coordinates, including vertices, center point, and a `mapboxgl.LngLatBounds` object.
     *
     * The method performs the following steps:
     * 1. Projects the geographic points to screen space to determine the minimum and maximum x/y values.
     * 2. Constructs a screen-space bounding box with vertices and center point.
     * 3. Converts the screen-space vertices and center point back to geographic coordinates.
     * 4. Constructs a geographic bounding box with vertices, center point, and a `mapboxgl.LngLatBounds` object.
     *
     * If debugging is enabled, the resulting bounding box is logged to the console.
     */
    public getScreenBounds(): BoundingBox {
        // Use to calculate min/max x/y values in screen space
        const { minX, maxX, minY, maxY }: { minX: number; maxX: number; minY: number; maxY: number } = this.points.reduce(
            (acc, point) => {
                const screenPos: mapboxgl.Point = this.map.project([point[0], point[1]]);
                return {
                    minX: Math.min(acc.minX, screenPos.x),
                    maxX: Math.max(acc.maxX, screenPos.x),
                    minY: Math.min(acc.minY, screenPos.y),
                    maxY: Math.max(acc.maxY, screenPos.y),
                };
            },
            { minX: Infinity, maxX: -Infinity, minY: Infinity, maxY: -Infinity }
        );
        // attributes in the screen space
        const screen: ScreenBox = {
            vertices: {
                topLeft: new mapboxgl.Point(minX, minY),
                topRight: new mapboxgl.Point(maxX, minY),
                bottomLeft: new mapboxgl.Point(minX, maxY),
                bottomRight: new mapboxgl.Point(maxX, maxY)
            },
            center: new mapboxgl.Point((minX + maxX) / 2, (minY + maxY) / 2)
        };
        // geo coordinates for the screen values
        const coords: Record<string, mapboxgl.LngLat> = {
            topLeft: this.map.unproject(screen.vertices.topLeft),
            topRight: this.map.unproject(screen.vertices.topRight),
            bottomRight: this.map.unproject(screen.vertices.bottomRight),
            bottomLeft: this.map.unproject(screen.vertices.bottomLeft),
            center: this.map.unproject(screen.center)
        }
        const boundingBox: BoundingBox = {
            screen: screen,
            geo: {
                vertices: {
                    topLeft: coords.topLeft,
                    topRight: coords.topRight,
                    bottomRight: coords.bottomRight,
                    bottomLeft: coords.bottomLeft
                },
                // geo bounding box MapBox object
                bounds: new mapboxgl.LngLatBounds([
                    coords.bottomLeft,
                    coords.topRight
                ]),
                center: coords.center
            }
        }
        if (this.debug)
            console.debug('Fitbounds.getScreenBounds(): BoundingBox: ', boundingBox)
        return boundingBox;
    }

    /**
     * Custom event dispatched to signal the end of a "fit screen bounds" operation.
     *
     * @event fitScreenBoundsEnd
     * @remarks
     * This event can be listened to in order to perform actions after the screen bounds have been adjusted.
     */
    fitScreenBoundsEvent = new CustomEvent("fitScreenBoundsEnd", {});

    /**
     * Adjusts the map view to fit the current bounds within the visible screen area,
     * accounting for pitch, bearing, and custom padding. This method is a replacement
     * for `map.fitScreenCoordinates()`, addressing its issues with pitch, bearing,
     * and underzooming (see https://github.com/mapbox/mapbox-gl-js/issues/13347).
     *
     * The method:
     * - Waits for any ongoing map movement to finish before proceeding.
     * - Uses the current map pitch and bearing if not specified in options.
     * - Applies absolute padding to the fit operation.
     * - Calculates the effective map area and aspect ratio after padding.
     * - Animates the map to fit the bounds, adjusting zoom to ensure the bounds
     *   fill the screen as much as possible.
     * - Optionally optimizes the fit for pitched maps.
     * - Dispatches a custom event upon completion.
     *
     * @param options Optional. Configuration for fitting bounds, including pitch, bearing, padding, and animation duration.
     * @returns The Mapbox map instance for chaining.
     */
    public fitScreenBounds(options: mapboxgl.MapOptions['fitBoundsOptions'] = {}): mapboxgl.Map {
        // method to replace faulty map.fitScreenCoordinates() which does not handle pitch and bearing correctly
        // additionally, the fit from that method is grossly underzoomed, tending to the central 1/9th of the map
        // see issue https://github.com/mapbox/mapbox-gl-js/issues/13347

        if (this.map.isMoving()) {
            this.map.once(
                'moveend', (() => { this.fitScreenBounds(options) })
            );
            return this.map;
        }
        options.pitch = options.pitch ?? this.map.getPitch();
        options.bearing = options.bearing ?? this.map.getBearing();
        options.padding = this.absolutePadding;
        const offset: [number, number] = [
            (options.padding.right ?? 0) - (options.padding.left ?? 0),
            (options.padding.bottom ?? 0) - (options.padding.top ?? 0)
        ];
        const mapContainer: HTMLElement = this.map.getContainer();
        const effectiveMap: Rectangle = new Rectangle({
            top: (options.padding?.top ?? 0),
            right: mapContainer.offsetWidth - (options.padding?.right ?? 0),
            bottom: mapContainer.offsetHeight - (options.padding?.bottom ?? 0),
            left: (options.padding?.left ?? 0)
        });
        const mapAspectRatio: number = effectiveMap.width / effectiveMap.height;
        if (!options.duration) options.duration = 250;
        this.fitAlignedBounds(options);
        if (!!options.pitch || !!options.bearing) {
            this.map.once(
                'moveend', (() => {
                    const bbox: BoundingBox = this.getScreenBounds();
                    if (this.debug) {
                        this._drawBounds(
                            bbox.geo.vertices.bottomLeft.toArray(),
                            bbox.geo.vertices.topLeft.toArray(),
                            bbox.geo.vertices.topRight.toArray(),
                            bbox.geo.vertices.bottomRight.toArray(),
                            'screen-bounds',
                            'purple'
                        )
                    }
                    this.map.easeTo({
                        center: bbox.geo.center,
                        pitch: options.pitch,
                        bearing: options.bearing,
                        padding: options.padding,
                        offset: offset
                    }).once('moveend', () => {
                        let scale: number = 1;
                        const boundsWidth: number = bbox.screen.vertices.bottomRight.x - bbox.screen.vertices.bottomLeft.x;
                        const boundsHeight: number = bbox.screen.vertices.bottomLeft.y - bbox.screen.vertices.topLeft.y;
                        const boundsAspectRatio: number = boundsWidth / boundsHeight;
                        if (mapAspectRatio > boundsAspectRatio) {
                            scale = effectiveMap.height / boundsHeight;
                        } else {
                            scale = effectiveMap.width / boundsWidth;
                        }
                        const zoom: number = this.map.getZoom();
                        const zoomAdjustment: number = Math.log2(scale);
                        if (this.debug) {
                            console.group('FitBounds.fitScreenBounds');
                            console.debug(`Map Zoom: ${zoom}`);
                            console.debug(`Adjusted Zoom: ${zoom + zoomAdjustment}`);
                            console.groupEnd();
                        }
                        const optimalZoom: number = zoom + zoomAdjustment;
                        this.map.easeTo({
                            zoom: optimalZoom
                        }).once('moveend', () => {
                            if (!!options.pitch) {
                                this._optimisePitchedMap(bbox, effectiveMap);
                            } else {
                                this.dispatchEvent(this.fitScreenBoundsEvent);
                            }
                        });
                    });
                })
            );
        } else {
            this.map.once(
                'moveend', (() => { this.dispatchEvent(this.fitScreenBoundsEvent) })
            );
        }

        return this.map;
    }

    /**
     * Iteratively adjusts the map view to ensure a bounding box fits within the effective map area,
     * accounting for map pitch and terrain source loading. If the terrain source is not yet loaded,
     * waits for it before proceeding. Projects the bounding box vertices to screen coordinates and
     * checks if they fit within the specified effective map rectangle. If not, zooms out or pans
     * the map as needed, using smooth transitions. Dispatches a custom event when the fit is complete.
     *
     * @param bbox - The bounding box to fit, containing geographic vertices and center.
     * @param effectiveMap - The rectangle representing the effective area of the map to fit the bounding box into.
     */
    private _optimisePitchedMap = (bbox: BoundingBox, effectiveMap: Rectangle) => {
        const terrainSourceId = "mapbox-dem";
        const style = this.map.getStyle() as mapboxgl.StyleSpecification
        if (!(style.sources[terrainSourceId] && this.map.isSourceLoaded(terrainSourceId))) {
            const sourcedataListener = (e: mapboxgl.MapSourceDataEvent) => {
                // Make sure this is the event for the terrain source
                if (e.sourceId === terrainSourceId) {
                    // Check if the source is fully loaded
                    if (e.isSourceLoaded) {
                        this._optimisePitchedMap(bbox, effectiveMap);
                        // Remove the listener after the source is loaded
                        this.map.off('sourcedata', sourcedataListener);
                    }
                }
            };
            // Attach the listener
            if (this.debug) console.debug('FitBounds._optimisePitchedMap: Terrain is still loading...');
            this.map.on('sourcedata', sourcedataListener);
            return;
        }

        const bottomLeft = this.map.project(bbox.geo.vertices.bottomLeft);
        const bottomRight = this.map.project(bbox.geo.vertices.bottomRight);
        const topLeft = this.map.project(bbox.geo.vertices.topLeft);
        if (
            bottomRight.x - bottomLeft.x > effectiveMap.width ||
            bottomLeft.y - topLeft.y > effectiveMap.height
        ) {
            const adjustedZoom: number = this.map.getZoom() - 0.1;
            this.map.easeTo(
                {
                    zoom: adjustedZoom,
                    center: bbox.geo.center,
                    duration: 100
                }
            ).once(
                'moveend', (() => { this._optimisePitchedMap(bbox, effectiveMap) })
            );
            if (this.debug)
                console.debug('FitBounds._optimisePitchedMap->adjustedZoom:', adjustedZoom);
        } else {
            let adjustedOffset: [number, number] = [0, 0];
            if (bottomLeft.x < effectiveMap.left) {
                adjustedOffset[0] = effectiveMap.left - bottomLeft.x;
            } else if (bottomRight.x > effectiveMap.right) {
                adjustedOffset[0] = effectiveMap.right - bottomRight.x;
            }
            if (topLeft.y < effectiveMap.top) {
                adjustedOffset[1] = effectiveMap.top - topLeft.y;
            } else if (bottomLeft.y > effectiveMap.bottom) {
                adjustedOffset[1] = effectiveMap.bottom - bottomLeft.y;
            }
            if (adjustedOffset.toString() !== "0,0") {
                if (this.debug)
                    console.debug('FitBounds._optimisePitchedMap->adjustedOffset:', adjustedOffset);
                this.map.easeTo({
                    center: bbox.geo.center,
                    offset: adjustedOffset
                })
                this.map.once(
                    'moveend', (() => { this.dispatchEvent(this.fitScreenBoundsEvent) })
                )
            } else {
                this.dispatchEvent(this.fitScreenBoundsEvent);
            }
        }

    }

    /**
     * Normalizes the input padding into a consistent `mapboxgl.PaddingOptions` object.
     *
     * @param input - The padding input, which can be:
     *   - A single number, applied uniformly to all sides.
     *   - An array of numbers, where:
     *     - `[top, right]` applies the same `top` and `bottom`, and the same `right` and `left`.
     *     - `[top, right, bottom]` applies the specified `top`, `right`, and `bottom`, with `left` equal to `right`.
     *     - `[top, right, bottom, left]` applies the specified values to each side.
     *   - A partial `mapboxgl.PaddingOptions` object, where missing sides default to `0`.
     *
     * @returns A `mapboxgl.PaddingOptions` object with `top`, `right`, `bottom`, and `left` properties, ensuring all sides are defined.
     */
    private _normalizePadding = (input: number | number[] | Partial<mapboxgl.PaddingOptions>): mapboxgl.PaddingOptions => {
        if (typeof input === "number") {
            return { top: input, right: input, bottom: input, left: input };
        }

        if (Array.isArray(input)) {
            const [t = 0, r = 0, b = 0, l = 0] = input;
            return input.length === 2
                ? { top: t, right: r, bottom: t, left: r }
                : input.length === 3
                    ? { top: t, right: r, bottom: b, left: r }
                    : { top: t, right: r, bottom: b, left: l };
        }

        return {
            top: input.top ?? 0,
            right: input.right ?? 0,
            bottom: input.bottom ?? 0,
            left: input.left ?? 0,
        };
    }

    /**
     * Draws a bounding box on the map using the provided coordinates and color.
     * Called when fitting to bounds with debug = true
     *
     * @param topLeft - The top-left corner of the bounding box.
     * @param topRight - The top-right corner of the bounding box.
     * @param bottomRight - The bottom-right corner of the bounding box.
     * @param bottomLeft - The bottom-left corner of the bounding box.
     * @param source - The source ID for the map layer.
     * @param color - The color of the bounding box line.
     */
    private _drawBounds = (
        topLeft: Coordinates,
        topRight: Coordinates,
        bottomRight: Coordinates,
        bottomLeft: Coordinates,
        source: string,
        color: string
    ): void => {
        queueMicrotask(() => {
            const sourceData = {
                "type": "geojson",
                "data": {
                    "type": "FeatureCollection" as const,
                    "features": [
                        {
                            type: "Feature",
                            geometry: {
                                type: "LineString",
                                coordinates: [
                                    topLeft,
                                    topRight,
                                    bottomRight,
                                    bottomLeft,
                                    topLeft
                                ]
                            },
                            properties: null
                        }
                    ]
                }
            };

            if (this.map.getSource(source)) {
                (this.map.getSource(source) as mapboxgl.GeoJSONSource).setData(sourceData.data as GeoJSON.FeatureCollection<GeoJSON.Geometry>);
            } else {
                this.map.addSource(source, sourceData as mapboxgl.GeoJSONSourceSpecification);
            }

            if (this.map.getLayer(`${source}-layer`)) {
                this.map.removeLayer(`${source}-layer`);
            }

            this.map.addLayer({
                "id": `${source}-layer`,
                "type": "line",
                "source": source,
                "layout": {
                    "line-join": "round",
                    "line-cap": "round"
                },
                "paint": {
                    "line-color": color,
                    "line-width": 4
                }
            });
        });
    }

    /**
     * Removes the specified layer and source from the map if they exist.
     *
     * @param source - The identifier for the map source and associated layer to be cleared.
     */
    public clearBounds(source: string): void {
        if (this.map.getLayer(`${source}-layer`)) {
            this.map.removeLayer(`${source}-layer`);
        }
        if (this.map.getSource(source)) {
            this.map.removeSource(source);
        }
    }
}
