import { CHART } from '../constants.js';
import { Chart, Filler, Interaction, Legend, LinearScale, LineController, LineElement, PointElement, Tooltip } from 'chart.js';
import type { ChartDataPoint, ElevationProfileSettings } from '../types.js';
import type { ChartDataset, InteractionItem, InteractionModeFunction } from 'chart.js';
import { getRelativePosition } from 'chart.js/helpers';

Chart.register(Filler, LinearScale, LineController, PointElement, LineElement, Tooltip, Legend);


// This function customizes how tooltips behave on an elevation profile chart with featured waypoints. 
// It enables two main behaviours:
// 1. Snap to Featured Waypoints
//   When the user hovers near a "featured" point (such as a labeled waypoint), the tooltip will snap to 
//    that point if the cursor is within a certain pixel tolerance (xTolerance).
//   The function checks all featured points and, if the cursor is close enough to any, 
//    returns that point for the tooltip to display.
// 2. Interpolate Elevation Between Points
//   If the cursor is not near a featured point, the function interpolates the elevation value between the 
//    two closest elevation data points on the x-axis.
//   It finds the segment where the hovered x-value falls, then linearly interpolates the y-value (elevation) 
//    between those two points.
//   It creates a "dummy" point at the interpolated position and returns it for the tooltip, so the tooltip 
//    follows the mouse smoothly even between real data points.
// 3. Sets Interpolated mapboxgl.Point for Tooltip Callbacks
//   The interpolated point is stored on the chart instance (_interpolatedPoint). This allows tooltip callbacks 
//    to access and display the interpolated values.
//
// How it Works (Step-by-Step):
// Get Mouse Position:
//   Converts the mouse event to chart-relative coordinates and determines the corresponding x-value on the chart.
//
// Check for Nearby mapboxgl.Point:
//   Calculates a tolerance based on the chart’s scale and featured point hover radius.
//   If a featured point is within this tolerance, returns it for the tooltip.
//   If a step point is within this tolerance, returns it for the tooltip.
// Interpolate if No Nearby mapboxgl.Point:
//   Finds the two elevation points that the hovered x-value falls between.
//   Calculates the interpolated y-value (elevation) at the hovered x.
//   Creates a dummy chart element at this interpolated position.
// Return Tooltip Items:
//   Returns either the real featured point or the interpolated dummy point for the tooltip to display.
// Why Use This?
//   Enhanced User Experience:
//     Users get precise tooltip feedback both at waypoints and anywhere along the elevation profile.
//   Smooth Tooltips:
//     Tooltips don’t “jump” between sparse data points but follow the mouse smoothly.
//   Custom Data Display:
//     Allows for custom formatting and display of interpolated values in tooltip callbacks.
// In summary:
//   This function makes tooltips on an elevation profile chart both smart (snapping to nearby data points) and smooth 
//     (interpolating between points), providing a much better interactive experience for users exploring elevation data.
type NearestPointCandidate = {
    x: number;
    y: number;
    label?: string;
    datasetIndex: number;
    index: number;
    distance: number;
};


Interaction.modes.tooltipMode = function (chart, e, options, useFinalPosition) {
    (chart as any)._interpolatedPoint = undefined;
    const evt = (e as any).native ?? e;
    const position = getRelativePosition(evt, chart);
    // const position = getRelativePosition(e, chart);
    const scale = chart.scales.x;
    const hoveredX = scale.getValueForPixel(position.x);
    if (!hoveredX) return [];

    const xRange = scale.max - scale.min;

    const featuredDataset = chart.data.datasets[0] as ChartDataset<'line', ChartDataPoint[]>;
    const elevationDataset = chart.data.datasets[1] as ChartDataset<'line', ChartDataPoint[]>;

    const radius = typeof featuredDataset.pointHoverRadius === 'number'
        ? featuredDataset.pointHoverRadius
        : CHART.DEFAULT_FEATURE_HOVER_RADIUS;

    const xTolerance = ((radius ?? CHART.DEFAULT_FEATURE_HOVER_RADIUS) / scale.width) * xRange;
    const elevationPoints = elevationDataset.data;

    const items: InteractionItem[] = [];

    // Find all nearby elevation points within tolerance
    const nearbyPoints = elevationPoints.filter(p => Math.abs(p.x - hoveredX) <= xTolerance);

    if (nearbyPoints.length > 0) {
        // 1) If there’s exactly one point, pick it
        let preferred = nearbyPoints[0];

        // 2) If more than one, see if any has a label
        if (nearbyPoints.length > 1) {
            const labeled = nearbyPoints.find(p => !!p.label);
            if (labeled) {
                preferred = labeled;
            } else {
                // 3) Otherwise pick the one with the smallest |x - hoveredX|
                preferred = nearbyPoints.reduce((a, b) =>
                    Math.abs(b.x - hoveredX) < Math.abs(a.x - hoveredX) ? b : a
                );
            }
        }

        // Now map that back to the chart element
        const dsIdx = preferred.label ? 0 : 1;
        const dsData = (chart.data.datasets[dsIdx] as ChartDataset<'line', ChartDataPoint[]>).data;
        const ptIndex = dsData.findIndex(p => p.x === preferred.x && p.y === preferred.y);

        if (ptIndex !== -1) {
            const meta = chart.getDatasetMeta(dsIdx);
            return [{
                element: meta.data[ptIndex],
                datasetIndex: dsIdx,
                index: ptIndex
            }];
        }
    }


    // No nearby data point. Interpolate elevation data
    let i = elevationPoints.findIndex((p, idx) =>
        idx < elevationPoints.length - 1 &&
        p.x <= hoveredX &&
        elevationPoints[idx + 1].x >= hoveredX
    );

    if (i === -1 || i === elevationPoints.length - 1) return [];

    const p1 = elevationPoints[i];
    const p2 = elevationPoints[i + 1];

    const t = (hoveredX - p1.x) / (p2.x - p1.x);
    const y = p1.y + t * (p2.y - p1.y);

    // Fake a tooltip element at interpolated point
    const interpolatedPoint: ChartDataPoint = {
        x: hoveredX,
        y: y,
        label: ''
    };
    const meta = chart.getDatasetMeta(1);
    const pixelX = chart.scales.x.getPixelForValue(hoveredX);
    const pixelY = chart.scales.y.getPixelForValue(y);
    const dummyPoint = {
        // x: position.x,
        x: pixelX,
        y: pixelY,
        hasValue: () => true,
        getProps: () => ({ x: pixelX, y }),
        tooltipPosition: () => ({ x: pixelX, y: pixelY }),
        // These are needed for tooltip animation/placement
        inXRange: () => true,
        inYRange: () => true,
        inRange: () => true,
        getCenterPoint: () => ({
            x: position.x,
            y: chart.scales.y.getPixelForValue(y)
        }),
        skip: false,
        options: {}, // may be accessed internally
        draw: () => { },
        raw: interpolatedPoint,
        __interpolated: true
    };

    items.push({
        element: dummyPoint as any, // cast for Chart.js compatibility
        datasetIndex: 1,
        index: i,
    });

    (chart as any)._interpolatedPoint = {
        x: hoveredX,
        y: y
    };

    return items;
};

// Extend Chart.js to include the custom tooltip mode
declare module 'chart.js' {
    interface InteractionModeMap {
        tooltipMode: InteractionModeFunction;
    }
}

/**
 * Represents an interactive elevation profile chart using Chart.js.
 * 
 * The `ElevationChart` class is responsible for rendering an elevation profile and featured waypoints
 * within a specified container element. It supports dynamic updates, custom styling, and interactive
 * tooltips. The chart is highly configurable via the provided `ElevationProfileSettings`.
 * 
 * ### Features
 * - Renders an elevation profile line and featured waypoints.
 * - Customizable axes, labels, tooltips, and styles.
 * - Draws vertical droplines from waypoints to the x-axis.
 * - Responsive and maintains aspect ratio.
 * - Provides methods for drawing and destroying the chart.
 * 
 * ### Usage
 * ```typescript
 * const chart = new ElevationChart(settings, containerDiv, true);
 * chart.drawElevationProfile(elevationData);
 * // ...
 * chart.destroy();
 * ```
 * 
 * @remarks
 * - Requires Chart.js to be available in the environment.
 * - The chart container is cleared and styled upon instantiation.
 * - The chart is destroyed and DOM elements are cleaned up via {@link destroy}.
 * 
 * @public
 */
export default class ElevationChart {
    chart?: Chart;
    private _placeholder: HTMLDivElement;
    private _chartCanvas: HTMLCanvasElement;

    constructor(
        private readonly settings: ElevationProfileSettings,
        private readonly chartContainer: HTMLDivElement,
        private readonly debug: boolean = false
    ) {
        this.chartContainer.style.position = 'relative';
        this.chartContainer.innerHTML = "";
        this.chartContainer.classList.add(...this.settings.containerClassList);
        if (this.settings.chartMaxHeight)
            this.chartContainer.style.maxHeight = this.settings.chartMaxHeight;
        if (this.settings.chartMinAspectRatio)
            this.chartContainer.style.aspectRatio = this.settings.chartMinAspectRatio.toString();
        this._placeholder = document.createElement("div");
        this._placeholder.classList = this.settings.placeholder.classList;
        const span = document.createElement('span');
        span.textContent = this.settings.placeholder.label;
        this._placeholder.append(span);
        this.chartContainer.appendChild(this._placeholder);
        // Create a canvas for Chart.js
        this._chartCanvas = document.createElement("canvas");
        this._chartCanvas.style.top = '0';
        this._chartCanvas.style.position = 'absolute';
        this.chartContainer.appendChild(this._chartCanvas);
    }

    /**
     * Cleans up resources and removes chart elements
     * @public
     */
    public destroy(): void {
        if (this._chartCanvas) {
            // Get chart instance and destroy it
            const chartInstance = Chart.getChart(this._chartCanvas);
            if (chartInstance) chartInstance.destroy();
            this._chartCanvas.remove();
        }
        this._placeholder?.remove();
        this.chartContainer?.remove();
        if (this.debug) console.debug('ElevationChart: destroyed');
    }

    /**
     * Renders an elevation profile chart using the provided elevation data.
     *
     * This method processes the input data to separate and deduplicate waypoints and step points,
     * then initializes and configures a Chart.js line chart to visualize the elevation profile.
     * The chart displays distance on the x-axis and elevation on the y-axis, with custom styling,
     * tooltips, and tick formatting based on the current settings.
     *
     * @param elevationData - An array of `ChartDataPoint` objects representing the elevation profile.
     *                        Each point should contain at least `x` (distance) and `y` (elevation) values,
     *                        and may optionally include a `label` to indicate a featured waypoint.
     *
     * @remarks
     * - If the input data array is empty, the method logs an error and returns early.
     * - The chart is rendered on the canvas referenced by `this._chartCanvas`.
     * - Chart options, labels, and styles are derived from the `settings` property.
     * - Tooltips are customized to show waypoint labels and formatted distance/elevation values.
     * - The chart is responsive and resizes after rendering.
     * - Any errors during chart creation are caught and logged.
     */
    public drawElevationProfile(elevationData: ChartDataPoint[]): void {
        if (!elevationData.length) {
            console.error('ElevationChart: empty dataset supplied');
            return;
        }

        try {
            // create featured points from those with label values
            const featuredPoints = elevationData.filter(member => !!member.label);
            // dedupe elevation datapoints making sure to retain label in case of duplicate
            const stepPoints = Array.from(
                elevationData.reduce((map, pt) => {
                    const existing = map.get(pt.x);
                    // if there's no entry yet, or the existing one has no label but this one does, overwrite
                    if (!existing || (!existing.label && !!pt.label)) {
                        map.set(pt.x, pt);
                    }
                    return map;
                }, new Map<number, ChartDataPoint>())
                    .values()
            );

            this.chart = new Chart<'line', ChartDataPoint[], unknown>(this._chartCanvas, {
                type: 'line',
                data: {
                    datasets: this._datasets(featuredPoints, stepPoints),
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    scales: {
                        x: {
                            type: 'linear', // Linear scale for distance
                            title: {
                                display: true,
                                text: `${this.settings.labels.distance} (${this.settings.labels.distanceUnits})`,
                                font: {
                                    family: this.settings.styles.title.fontFamily,
                                    weight: this.settings.styles.title.weight,
                                    size: this.settings.styles.title.size,

                                },
                                padding: this.settings.styles.title.padding
                            },
                            bounds: 'data',
                            offset: false,         // Prevent Chart.js from adding padding on ends
                            grace: 0,
                            min: 0,
                            max: featuredPoints.at(-1)!.x, // set max at last waypoint
                            ticks: {
                                maxTicksLimit: this.settings.axes.x.ticks?.maxTicks ?? CHART.DEFAULT_MAX_X_TICKS,
                                autoSkip: false,
                                align: 'center',
                                includeBounds: false,
                                font: {
                                    family: this.settings.styles.bodyFontFamily,
                                    weight: this.settings.styles.title.weight,
                                },
                                padding: this.settings.axes.x.ticks?.padding ?? CHART.DEFAULT_TICK_PADDING,
                                major: {
                                    enabled: true, // Ensure only major ticks are shown
                                },
                                callback: function (val, index, ticks) {
                                    // Suppress the bound tick labels (leaves only true major ticks)
                                    const tick = ticks[index];
                                    // Check if value on or outside data range limits (bounds ticks)
                                    const isBoundsTick = tick.value <= this.min || tick.value >= this.max;
                                    if (isBoundsTick) return '';
                                    return val;
                                },
                            },
                        },
                        y: {
                            title: {
                                display: true,
                                text: `${this.settings.labels.elevation} (${this.settings.labels.elevationUnits})`,
                                font: {
                                    family: this.settings.styles.title.fontFamily,
                                    weight: this.settings.styles.title.weight,
                                    size: this.settings.styles.title.size,
                                },
                            },
                            ticks: {
                                maxTicksLimit: this.settings.axes.y.ticks?.maxTicks ?? CHART.DEFAULT_MAX_Y_TICKS,
                                font: {
                                    family: this.settings.styles.bodyFontFamily,
                                    weight: this.settings.styles.title.weight,
                                },
                                padding: this.settings.axes.x.ticks?.padding ?? CHART.DEFAULT_TICK_PADDING,
                            },
                        },
                    },
                    interaction: {
                        mode: 'nearest',
                        intersect: false,
                    },
                    hover: {
                        mode: 'nearest',
                        intersect: true, // <- Important: Only hover when near actual point
                    },
                    plugins: {
                        legend: {
                            display: false,
                        },
                        tooltip: {
                            ...this.settings.tooltip?.options,
                            mode: 'tooltipMode',
                            intersect: false,
                            displayColors: false,
                            backgroundColor: (context) => {
                                const chart = context.chart;
                                const isInterpolated = (chart as any)._interpolatedPoint;
                                return isInterpolated
                                    ? this.settings.tooltip.interpolated.backgroundColor
                                    : this.settings.tooltip.standard.backgroundColor;
                            },
                            borderColor: (context) => {
                                const chart = context.chart;
                                const isInterpolated = (chart as any)._interpolatedPoint;
                                return isInterpolated
                                    ? this.settings.tooltip.interpolated.borderColor
                                    : this.settings.tooltip.standard.borderColor;
                            },
                            borderWidth: (context) => {
                                const chart = context.chart;
                                const isInterpolated = (chart as any)._interpolatedPoint;
                                return isInterpolated
                                    ? this.settings.tooltip.interpolated.borderWidth
                                    : this.settings.tooltip.standard.borderWidth;
                            },
                            callbacks: {
                                // find a waypoint if closeby, otherwise display step data
                                label: (context) => {
                                    const tooltip = context.chart.tooltip;
                                    if (!tooltip) return '';
                                    const chart = context.chart;
                                    const interpolated = (chart as any)._interpolatedPoint;

                                    // Use interpolated values if available and not a real waypoint point
                                    if (
                                        interpolated &&
                                        !(context.dataset.label === 'Waypoints')
                                    ) {
                                        const xValue = interpolated.x.toFixed(1);
                                        const yValue = interpolated.y.toFixed(0);
                                        return [
                                            `${this.settings.labels.distance}: ${xValue}${this.settings.labels.distanceUnits}`,
                                            `${this.settings.labels.elevation}: ${yValue}${this.settings.labels.elevationUnits}`
                                        ];
                                    }
                                    const point = context.raw as ChartDataPoint;
                                    const xValue = Number(point.x).toFixed(1);
                                    const yValue = Number(point.y).toFixed(0);
                                    return [
                                        `${this.settings.labels.distance}: ${xValue}${this.settings.labels.distanceUnits}`,
                                        `${this.settings.labels.elevation}: ${yValue}${this.settings.labels.elevationUnits}`,
                                    ];
                                },
                                labelTextColor: (context) => {
                                    const chart = context.chart;
                                    const isInterpolated = (chart as any)._interpolatedPoint && context.dataset.label !== 'Waypoints';
                                    return isInterpolated
                                        ? this.settings.tooltip.interpolated.textColor
                                        : this.settings.tooltip.standard.textColor;
                                },
                                title: (context) => {
                                    const tooltip = context[0]?.chart.tooltip;
                                    if (!tooltip) return '';
                                    const chart = context[0].chart;
                                    const interpolated = (chart as any)._interpolatedPoint; if (
                                        interpolated &&
                                        !(context[0].dataset.label === 'Waypoints')
                                    ) return '';
                                    const point = context[0].raw as ChartDataPoint;
                                    return point.label || '';
                                },
                            }
                        },
                    },
                    elements: {
                        line: {
                            tension: this.settings.line.tension * featuredPoints.at(-1)!.x / 100,
                        },
                    },
                },
                plugins: [this._droplinesPlugin(featuredPoints)],
            });
        } catch (error) {
            console.error('ElevationChart.drawElevationProfile(): An error occurred', error);
            this._placeholder.innerHTML = this.settings.placeholder.errorMessage;
            this._placeholder.classList.add('error');
            this._chartCanvas.remove();
            return;
        }

        if (this.debug) console.debug('Elevation chart', this.chart);
        // Resize the chart to fit the container
        setTimeout(() => {
            this.chart!.resize();
            this._placeholder.remove();
        }, CHART.PLACEHOLDER_REMOVE_DELAY);
    }

    /**
     * Creates a Chart.js plugin that draws vertical droplines from specified featured points
     * down to the x-axis on the chart. The droplines are only drawn for the dataset labelled 'Waypoints'.
     *
     * @param featuredPoints - An array of ChartDataPoint objects representing the points from which droplines will be drawn.
     * @returns An object implementing the Chart.js plugin interface with an `id` and a `beforeDatasetDraw` hook.
     *
     * @remarks
     * - The dropline color and width are determined by `this.settings.styles.dropLineColour` and `this.settings.styles.dropLineWidth`.
     * - The plugin only draws droplines for the dataset with the label 'Waypoints'.
     */
    private _droplinesPlugin = (featuredPoints: ChartDataPoint[]): {
        id: string;
        beforeDatasetDraw: (chart: Chart, args: {
            index: number;
        }) => void;
    } => {
        return {
            id: 'droplines',
            beforeDatasetDraw: (chart: Chart, args: { index: number }) => {
                const { ctx, scales } = chart;
                const { index } = args;
                const xScale = scales.x;
                const yScale = scales.y;

                featuredPoints.forEach(featuredPoint => {
                    const xPixel = xScale.getPixelForValue(featuredPoint.x);
                    const yPixel = yScale.getPixelForValue(featuredPoint.y);

                    const waypointsDatasetIndex = chart.data.datasets.findIndex(
                        ds => ds.label === 'Waypoints'
                    );
                    if (index !== waypointsDatasetIndex) return;

                    // Draw dropline
                    ctx.save();
                    ctx.strokeStyle = this.settings.styles.dropLineColour;
                    ctx.lineWidth = this.settings.styles.dropLineWidth;
                    ctx.beginPath();
                    ctx.moveTo(xPixel, yPixel); // Start at the endpoint
                    ctx.lineTo(xPixel, yScale.getPixelForValue(yScale.min)); // Drop to the bottom
                    ctx.stroke();
                    ctx.restore();
                });
            },
        };
    }

    /**
     * Generates an array of Chart.js dataset configurations for rendering waypoints and elevation profile lines.
     *
     * @param featuredPoints - An array of `ChartDataPoint` objects representing the featured waypoints to display on the chart.
     * @param elevationData - An array of `ChartDataPoint` objects representing the elevation profile data to plot.
     * @returns An array of `ChartDataset<'line', ChartDataPoint[]>` objects, including one for waypoints and one for the elevation profile.
     */
    private _datasets = (featuredPoints: ChartDataPoint[], elevationData: ChartDataPoint[]): ChartDataset<'line', ChartDataPoint[]>[] => {
        return [
            {
                label: 'Waypoints',
                data: featuredPoints,
                borderColor: 'transparent',
                backgroundColor: this.settings.styles.featureColor,
                pointRadius: this.settings.styles.featureRadius,
                pointHoverRadius: this.settings.styles.featureHoverRadius,
                showLine: false,
                clip: false,
            },
            {
                label: 'Elevation Profile',
                data: elevationData,
                borderColor: this.settings.styles.profileBorderColor,
                backgroundColor: this.settings.styles.profileBackgroundColor,
                borderWidth: this.settings.line.width,
                fill: 'start',
                pointRadius: this.settings.styles.stepPointRadius,
                pointHoverRadius: this.settings.styles.stepPointHoverRadius
            },
        ]
    };

}


