import mapboxgl from 'mapbox-gl';
import ElevationChart from './Chart.js';
import Route from './Route.js';
import type { 
    ChartDataPoint, CoordinatesArray, DetailedSummaryData, LegDetailedData, RouteData, RouteSummarySettings, 
    RouteSummaryTableSettings, RouteTableDataColumns, RouteTableDataRow, RouteType, WayPoints 
} from '../types.js';
import { ElevationRGB } from './Elevation.js';
import { GpxStreamBuilder } from './GPX.js';
import { svgFromId } from '../utility/utility.js';
import { UI } from '../constants.js';

/**
 * Represents the possible states of a detailed route summary.
 *
 * @enum DetailedSummaryState
 * @property {string} Initial - The initial state before any action has been taken.
 * @property {string} NoRoute - Indicates that no route is currently loaded.
 * @property {string} Loading - Indicates that the route summary is currently being loaded.
 * @property {string} Loaded - Indicates that the route summary has been successfully loaded.
 */
enum DetailedSummaryState {
    Initial = 'initial',
    NoRoute = 'empty',
    Loading = 'loading',
    Loaded = 'loaded'
}

/**
 * Provides summary and detailed information for a route, including distance, duration, and elevation profile.
 * 
 * The `RouteSummary` class manages the rendering and state of route summary UI components, supporting both
 * simple and detailed views. It handles asynchronous updates, event-driven rendering, and integration with
 * elevation data sources. The class is responsible for:
 * 
 * - Displaying a simple summary with distance (and optionally duration).
 * - Displaying a detailed summary with per-leg statistics, elevation gain/loss, and an elevation profile chart.
 * - Managing the lifecycle of UI elements and elevation chart components.
 * - Fetching and processing elevation data when required.
 * - Formatting and localizing distance and duration displays.
 * 
 * @remarks
 * - The summary view is determined by route parameters (`showSummary` and `showElevationProfile`).
 * - Elevation data is fetched using the ElevationRGB utility if enabled.
 * - The class is designed to be used within a map-based routing application with event-driven updates.
 * 
 * @example
 * ```typescript
 * const summary = new RouteSummary(route, true);
 * summary.renderRouteInformation();
 * ```
 * 
 * @public
 */
export default class RouteSummary {
    detailedSummary: DetailedSummary;
    detailedSummaryData?: DetailedSummaryData;
    settings: RouteSummarySettings;
    private _simpleContainer?: HTMLElement;
    private _showElevationProfile?: boolean;
    private _elevationChart?: ElevationChart;
    private _elevationRGB?: ElevationRGB;

    constructor(readonly route: Route, private readonly debug: boolean = false) {
        this.settings = this.route.settings.summary;
        this.detailedSummary = new DetailedSummary(this, this.debug);
    }

    public destroy() {
        this.clear();
        this.detailedSummary.destroy();
        this._elevationRGB = undefined;
        if (this.debug) console.debug('RouteSummary: destroyed');
    }

    /**
     * Clears the current route summary state and associated UI elements.
     *
     * This method destroys the elevation chart if it exists, resets the detailed summary data and state,
     * removes the simple summary container from the DOM, and logs the action if debugging is enabled.
     */
    public clear() {
        this._elevationChart?.destroy();
        this.detailedSummaryData = undefined;
        this.detailedSummary.state = DetailedSummaryState.NoRoute;
        this._simpleContainer?.remove();
        this._simpleContainer = undefined;
        if (this.debug) console.debug('RouteSummary: cleared');
    }

    /**
     * Renders route information based on the current route parameters.
     * 
     * This method schedules the rendering logic using `queueMicrotask` to ensure
     * that UI updates occur asynchronously. It clears any existing content and then
     * determines which summary view to display based on the `showSummary` parameter:
     * 
     * - If `showSummary` is `"simple"`, it renders a simple placeholder.
     * - If `showSummary` is `"detailed"`, it optionally initializes an elevation chart
     *   (if `_showElevationProfile` is enabled), renders a detailed placeholder, and sets
     *   the detailed container's state to loading.
     * 
     * @remarks
     * This method is intended to be called whenever the route summary display needs to be updated.
     */
    public renderRouteInformation = (): void => {
        queueMicrotask(() => {
            this.clear();
            this._showElevationProfile = this.route.showElevationProfile;
            switch (this.route.parameters.showSummary) {
                case "simple":
                    this._renderSimplePlaceHolder();
                    break;
                case "detailed":
                    if (this._showElevationProfile) {
                        queueMicrotask(() => {
                            this._elevationChart = new ElevationChart(
                                this.settings.elevationProfile,
                                this.detailedSummary.chartContainer,
                                this.debug
                            );
                        });
                    }
                    this._renderDetailedPlaceHolder();
                    this.detailedSummary.state = DetailedSummaryState.Loading;
            }
        });
    }

    /**
     * Renders a simple placeholder UI element for displaying route distance information.
     * 
     * This method creates a container element with the appropriate classes and appends
     * a label, a placeholder for the distance, and the distance units to it. The container
     * is then appended to the map wrapper element. If route data is already available,
     * it immediately renders the data; otherwise, it sets up an event listener to render
     * the data once the "directionsReturned" event is fired.
     *
     * @private
     */
    private _renderSimplePlaceHolder = (): void => {
        this._simpleContainer = document.createElement('div');
        this._simpleContainer.classList.add(...this.settings.simple.classList);
        const distancePlaceholder: HTMLSpanElement = document.createElement('span');
        distancePlaceholder.setAttribute("for", "route-distance");
        distancePlaceholder.textContent = " - ";
        this._simpleContainer.append(this.settings.simple.label, ": ", distancePlaceholder, this.settings.simple.distanceUnits);
        this.route.mapWrapper.append(this._simpleContainer);
        if (!!this.route.routeData) {
            this._renderSimpleData(this.route.routeData);
        } else {
            const listener = (event: Event) => {
                this._renderSimpleData((event as CustomEvent).detail as RouteData);
                this.route.removeEventListener("directionsReturned", listener);
            };
            this.route.addEventListener("directionsReturned", listener);
        }
    }

    /**
     * Renders a simplified summary of the route data, including distance and optionally duration,
     * into the `_simpleContainer` element. The distance is formatted based on its value:
     * - Less than 1 km: 3 decimal places
     * - Between 1 km and 10 km: 1 decimal place
     * - 10 km or more: no decimal places
     * 
     * If `showDuration` is enabled in settings and the route data includes a duration,
     * the formatted duration is appended to the container.
     *
     * @param routeData - The route data object containing distance (in metres) and optionally duration (in seconds).
     */
    private _renderSimpleData = (routeData: RouteData): void => {
        const getDistanceDisplay = (distance: number): string => {
            distance = distance / 1000;
            let dp: number = 0;
            if (distance < 1) {
                dp = 3;
            } else if (distance < 10) {
                dp = 1;
            }
            return distance.toFixed(dp);
        }
        this._simpleContainer!.replaceChildren(this.settings.simple.label, ": ", getDistanceDisplay(routeData.distance), this.settings.simple.distanceUnits);
        if (this.settings.simple.showDuration && routeData.duration) {
            this._simpleContainer!.append(this._formatDuration(routeData.duration))
        }
    }

    /**
     * Renders the detailed placeholder in the route table using the current waypoints,
     * elevation profile visibility, and route type. If waypoints are already available,
     * it proceeds to render the detailed data immediately. Otherwise, it waits for the
     * "waypointsReady" event before rendering the detailed data.
     *
     * @private
     */
    private _renderDetailedPlaceHolder = (): void => {
        this.detailedSummary.routeTable.setPlaceHolder(
            this.route.parameters.waypoints!,
            !!this._showElevationProfile,
            this.route.parameters.routeType
        );
        if (this.route.waypoints.length) {
            this._renderDetailedData();
        } else {
            this.route.addEventListener("waypointsReady", () => this._renderDetailedData(), { once: true });
        }
    }

    /**
     * Fetches and renders detailed summary data for the route.
     *
     * This method asynchronously retrieves detailed summary data and updates the UI components accordingly.
     * If elevation profile display is enabled, it processes the route profile data and updates the elevation chart,
     * ensuring the chart is resized after rendering. It also updates the route table with the new data and sets
     * the detailed summary state to loaded.
     *
     * @private
     * @returns {void}
     */
    private _renderDetailedData = (): void => {
        this._getDetailedSummaryData().then((data) => {
            if (this.debug) console.debug('Route Summary: Detailed Summary Data', data);
            if (this._showElevationProfile) {
                queueMicrotask(() => {
                    const elevationProfile: ChartDataPoint[] = data.routeProfile.map(p => ({
                        x: p.distance,
                        y: p.elevation!,
                        label: p.name!
                    }));
                    this._elevationChart!.drawElevationProfile(elevationProfile);
                });
            }
            this.detailedSummary.routeTable.updateData(data);
            this.detailedSummaryData = data;
            this.detailedSummary.state = DetailedSummaryState.Loaded;
        })
    }

    /**
     * Generates a detailed summary of the route, including distance, elevation, and profile data.
     *
     * This asynchronous method processes each leg of the route, flattens coordinates and elevation data,
     * calculates cumulative distances and elevation gain/loss, and constructs a detailed summary object.
     * The summary includes per-leg and total statistics, as well as a route profile suitable for elevation charts.
     *
     * @returns {Promise<DetailedSummaryData>} A promise that resolves to a `DetailedSummaryData` object containing
     *   route profile points, leg summaries, total distance, elevation gain/loss, route type, and elevation profile visibility.
     *
     * @remarks
     * - Requires route data and waypoints to be present on the instance.
     * - If `_showElevationProfile` is enabled, elevation data is fetched and included.
     * - The method avoids duplicating coordinates between steps and labels waypoints in the profile.
     */
    private _getDetailedSummaryData = async (): Promise<DetailedSummaryData> => {
        const summary: DetailedSummaryData = {
            routeProfile: [],
            legs: [],
            total: { distance: 0, elevation: { gain: 0, loss: 0 } },
            routeType: this.route.parameters.routeType,
            showElevation: !!this._showElevationProfile
        };

        // 1) Build flat coordinate array, recording each leg’s [startIdx,endIdx)
        const allCoords: CoordinatesArray = [];
        const legRanges: { startIdx: number; endIdx: number }[] = [];

        for (const leg of this.route.routeData!.legs) {
            const startIdx = allCoords.length;

            // Flatten this leg’s steps, dropping overlapping points *only within* step boundaries
            for (let si = 0; si < leg.steps.length; si++) {
                const stepCoords = leg.steps[si].geometry.coordinates as CoordinatesArray;
                const coordsToAdd = si < leg.steps.length - 1
                    ? stepCoords.slice(0, -1)
                    : stepCoords;
                allCoords.push(...coordsToAdd);
            }

            const endIdx = allCoords.length;  // inclusive of the leg’s true endpoint
            legRanges.push({ startIdx, endIdx });
        }

        // 2) Fetch once (or skip) for allCoords
        let flatElevs: number[] = [];
        if (this._showElevationProfile) {
            if (!this._elevationRGB) {
                this._elevationRGB = new ElevationRGB({ settings: this.settings.elevationProfile.RGBSettings ?? {}, debug: this.debug });
            }
            flatElevs = await this._elevationRGB.getElevationsFromTerrainRGB(allCoords);
        }

        // 3) Walk through each leg’s index range to build profile + per‑leg stats
        let cumulativeDistanceMeters = 0;

        for (let legIndex = 0; legIndex < legRanges.length; legIndex++) {
            const { startIdx, endIdx } = legRanges[legIndex];
            const leg = this.route.routeData!.legs[legIndex];
            const waypointStart = this.route.waypoints[legIndex];
            const waypointEnd = this.route.waypoints[legIndex + 1];

            // Initialize this leg’s summary
            const legSummary: LegDetailedData = {
                label: `${waypointStart.name!} - ${waypointEnd.name!}`,
                distance: { start: cumulativeDistanceMeters, end: 0, length: 0 },
                elevation: {
                    gain: 0,
                    loss: 0,
                    start: flatElevs[startIdx] || 0,
                    end: 0
                }
            };

            // Iterate each segment in this leg
            for (let i = startIdx; i < endIdx - 1; i++) {
                const [lng1, lat1] = allCoords[i];
                const [lng2, lat2] = allCoords[i + 1];

                // Distance
                const from = new mapboxgl.LngLat(lng1, lat1);
                const to = new mapboxgl.LngLat(lng2, lat2);
                const segmentDist = from.distanceTo(to); // in meters

                // Elevation gain/loss
                const elev1 = this._showElevationProfile ? flatElevs[i] : 0;
                const elev2 = this._showElevationProfile ? flatElevs[i + 1] : 0;
                const delta = elev2 - elev1;
                if (delta > 0) legSummary.elevation.gain += delta;
                else legSummary.elevation.loss -= delta;

                // Push profile point
                summary.routeProfile.push({
                    lng: lng1,
                    lat: lat1,
                    name: i === startIdx ? waypointStart.name! : undefined,
                    distance: cumulativeDistanceMeters / 1000, // km
                    elevation: elev1
                });

                cumulativeDistanceMeters += segmentDist;
            }

            // Push the exact endpoint of this leg (duplicate of next leg’s start)
            const lastIdx = endIdx - 1;
            const [lngF, latF] = allCoords[lastIdx];
            const elevF = this._showElevationProfile ? flatElevs[lastIdx] : 0;

            summary.routeProfile.push({
                lng: lngF,
                lat: latF,
                name: undefined,
                distance: cumulativeDistanceMeters / 1000, // km
                elevation: elevF,
            });

            // Finalize this leg’s summary
            legSummary.distance.end = cumulativeDistanceMeters;
            legSummary.distance.length = cumulativeDistanceMeters - legSummary.distance.start;
            legSummary.elevation.end = elevF;

            summary.legs.push(legSummary);
            summary.total.distance += legSummary.distance.length;
            summary.total.elevation.gain += legSummary.elevation.gain;
            summary.total.elevation.loss += legSummary.elevation.loss;
        }

        // 4) Label only the very final point with the final waypoint’s name
        const finalWaypoint = this.route.waypoints.at(-1)!.name!;
        summary.routeProfile.at(-1)!.name = finalWaypoint;

        return summary;
    }


    /**
     * Formats a duration given in seconds into a human-readable string using localized units (hours and minutes),
     * and returns it as an HTMLSpanElement with the class "route-duration".
     *
     * @param seconds - The duration in seconds to format.
     * @param locale - Optional. The BCP 47 language tag to use for localization (defaults to the user's browser language or 'en-GB').
     * @returns An HTMLSpanElement containing the formatted duration string.
     */
    private _formatDuration = (seconds: number, locale: string = ""): HTMLSpanElement => {
        if (!locale) locale = navigator.language || 'en-GB'
        const hours = Math.floor(seconds / 3600);
        const minutes = Math.floor((seconds % 3600) / 60);

        const hourFormatter = new Intl.NumberFormat(locale, { style: "unit", unit: "hour", unitDisplay: "long" });
        const minuteFormatter = new Intl.NumberFormat(locale, { style: "unit", unit: "minute", unitDisplay: "long" });

        const parts: string[] = [];
        if (hours) parts.push(hourFormatter.format(hours));
        if (minutes) parts.push(minuteFormatter.format(minutes));

        const durationSpan: HTMLSpanElement = document.createElement("span");
        durationSpan.className = "route-duration";
        durationSpan.textContent = ` (${parts.join(", ")})`;
        return durationSpan;
    }

}

/**
 * Represents a dynamic summary table for route information, including distance, ascent, and descent data.
 * 
 * The `RouteTable` class is responsible for constructing, updating, and managing an HTML table that displays
 * route segment data between waypoints. It supports dynamic updates, placeholder rows, unroutable waypoint warnings,
 * and toggling of elevation columns.
 * 
 * @remarks
 * - The table is built and managed entirely in the DOM, with support for custom styling via settings.
 * - Handles both routable and unroutable segments, displaying warnings as needed.
 * - Supports toggling the visibility of elevation data columns.
 * 
 * @example
 * ```typescript
 * const table = new RouteTable(settings, containerElement);
 * table.setPlaceHolder(waypoints, true, 'cycling');
 * table.updateData(summaryData);
 * ```
 * 
 * @public
 */
class RouteTable {
    private _table: HTMLTableElement;
    private _body: HTMLTableSectionElement;
    private _dataColumns: RouteTableDataColumns;
    private _unroutableWarning: HTMLDivElement
    private _dataRows: RouteTableDataRow[] = [];

    constructor(private settings: RouteSummaryTableSettings, private container: HTMLElement) {
        ({
            table: this._table,
            body: this._body,
            dataColumns: this._dataColumns,
            unroutableWarning: this._unroutableWarning
        } = this._buildTable());
    }

    /**
     * Clears the contents of the summary table and resets its state.
     *
     * This method empties the table body, removes the unroutable warning,
     * resets the data rows and sets all data column footers to a default value.
     * If the `remove` parameter is set to `true`, the entire table element is removed from the DOM.
     *
     * @param remove - If `true`, removes the table element from the DOM. Defaults to `false`.
     */
    clear = (remove: boolean = false): void => {
        this._body.innerHTML = '';
        this._unroutableWarning.remove();
        this._dataRows = [];
        Object.keys(this._dataColumns).forEach((key) => {
            this._dataColumns[key as (keyof RouteTableDataColumns)].footer.textContent = '-';
        });
        if (remove) this._table.remove();
    }

    /**
     * Builds and returns a set of DOM elements representing a summary table for route data.
     *
     * The table includes a header, body, and footer, with columns for leg, distance, ascent, and descent.
     * It also creates a warning element for unroutable waypoints, which can be conditionally displayed.
     *
     * @returns An object containing:
     * - `table`: The constructed HTMLTableElement.
     * - `body`: The table's HTMLTableSectionElement for the body rows.
     * - `dataColumns`: An object mapping column keys ('distance', 'ascent', 'descent') to their header and footer elements.
     * - `unroutableWarning`: An HTMLDivElement for displaying unroutable waypoint warnings.
     */
    private _buildTable = (): {
        table: HTMLTableElement,
        body: HTMLTableSectionElement,
        dataColumns: RouteTableDataColumns,
        unroutableWarning: HTMLDivElement
    } => {
        const table = document.createElement('table');
        table.classList.add(...this.settings.classList);
        // head
        const thead = document.createElement('thead');
        thead.classList.add(...this.settings.tableHeaderClassList ?? [])
        const theadRow: HTMLTableRowElement = document.createElement('tr');
        let th: HTMLTableCellElement = document.createElement('th');
        // leg column
        if (this.settings.columns.leg.svgId)
            th.append(svgFromId(this.settings.columns.leg.svgId, [UI.STANDARD_ICON_CLASS]));
        th.append(this.settings.columns.leg.heading);
        th.classList.add(...this.settings.columns.leg.headingClassList ?? []);
        theadRow.appendChild(th);
        thead.append(theadRow);
        // Footer: Add the totals as the final row
        const tfoot: HTMLTableSectionElement = document.createElement('tfoot');
        tfoot.classList.add(...this.settings.footerClassList ?? []);
        const tfootRow: HTMLTableRowElement = document.createElement('tr');
        tfootRow.appendChild(document.createElement('th'));
        tfoot.append(tfootRow);
        // populate header and footer data columns
        const dataColumns = {} as RouteTableDataColumns;
        for (const key of ['distance', 'ascent', 'descent'] as (keyof RouteTableDataColumns)[]) {
            const th = document.createElement('th');
            if (this.settings.columns[key].svgId)
                th.append(svgFromId(this.settings.columns[key].svgId, [UI.STANDARD_ICON_CLASS]));
            th.classList.add(...this.settings.columns[key].headingClassList ?? []);
            th.title = this.settings.columns[key].heading;
            theadRow.appendChild(th);
            const td = document.createElement('td');
            td.classList.add(...this.settings.footerCellClassList ?? []);
            td.textContent = '-';
            tfootRow.appendChild(td);
            dataColumns[key] = { head: th, footer: td };
        }
        // table body
        const body: HTMLTableSectionElement = document.createElement('tbody');
        table.append(thead, body, tfoot);
        // unroutable waypoints warning conditionally displayed below table
        const unroutableWarning: HTMLDivElement = document.createElement('div');
        unroutableWarning.classList.add(...this.settings.unroutableWarning.captionClassList ?? []);
        unroutableWarning.append(
            svgFromId(this.settings.unroutableWarning.svgId, [UI.UNROUTABLE_ICON_ID]),
            this.settings.unroutableWarning.text
        );

        return { table, body, dataColumns, unroutableWarning }
    }

    /**
     * Toggles the visibility of elevation-related table cells (ascent and descent).
     *
     * @param value - If `true`, shows the ascent and descent cells; if `false`, hides them.
     */
    private _showElevation = (value: boolean): void => {
        const cells = [
            this._dataColumns.ascent.head, 
            this._dataColumns.ascent.footer, 
            this._dataColumns.descent.head, 
            this._dataColumns.descent.footer
        ];
        if (value) {
            cells.forEach(cell => cell.style.removeProperty('display'));
        } else {
            cells.forEach(cell => cell.style.display = 'none');
        }
    }

    /**
     * Clears the current table content and populates it with a specified number of empty placeholder rows.
     * Optionally includes elevation profile columns (ascent and descent) based on the provided flag.
     *
     * @param rowCount - The number of empty rows to create in the table.
     * @param _showElevationProfile - Whether to include ascent and descent columns in each row.
     *
     * @remarks
     * - Each row will have a header cell and data cells for distance, and optionally ascent and descent.
     * - The method also updates the elevation profile display according to the flag.
     * - All created rows are appended to the table body and stored in the `_dataRows` array.
     */
    private _emptyPlaceHolder = (rowCount: number, _showElevationProfile: boolean): void => {
        this.clear();
        this._showElevation(_showElevationProfile);
        const rows: HTMLTableRowElement[] = [];
        for (let i = 0; i < rowCount; i++) {
            const dataRow = {} as RouteTableDataRow;
            const row = document.createElement('tr')
            rows.push(row);
            dataRow.leg = document.createElement('th');
            dataRow.leg.classList.add(...this.settings.rowHeaderClassList ?? []);
            row.appendChild(dataRow.leg);
            // distance, ascent, descent columns
            const columns = ['distance'] as (keyof RouteTableDataColumns)[];
            if (_showElevationProfile) columns.push('ascent', 'descent');
            columns.forEach((key) => {
                const cell: HTMLTableCellElement = document.createElement('td');
                cell.classList.add(...this.settings.dataCellClassList ?? []);
                cell.textContent = '-';
                dataRow[key] = cell;
                row.append(cell);
            });
            this._dataRows.push(dataRow);
        };
        this._body.append(...rows);
    }

    /**
     * Updates the placeholder content for the route summary table based on the provided waypoints,
     * elevation profile visibility, and route type. This method sets up the table rows with waypoint
     * labels, determines routability, and manages the display of elevation and unroutable warnings.
     *
     * @param waypoints - An array of waypoints representing the route.
     * @param _showElevationProfile - Whether to display the elevation profile.
     * @param routeType - The type of route being displayed.
     */
    public setPlaceHolder = (waypoints: WayPoints, _showElevationProfile: boolean, routeType: RouteType): void => {
        this._emptyPlaceHolder(waypoints.length - 1, _showElevationProfile);
        this._showElevation(_showElevationProfile);
        const rows: HTMLTableRowElement[] = [];
        let hasUnroutableWaypoints: boolean = false;
        this._dataRows.forEach((row, index) => {
            // First column: waypoint labels
            const label1: string = waypoints[index].name || `${this.settings.defaultWaypointName} #${index + 1}`;
            const label2: string = waypoints[index + 1].name || `${this.settings.defaultWaypointName} #${index + 2}`;
            row.leg.textContent = `${label1} - ${label2}`;
            row.isRoutable = waypoints[index].isRoutable && waypoints[index + 1].isRoutable && !!routeType;
            if (!row.isRoutable) hasUnroutableWaypoints = true;
        });
        if (!this._table.isConnected) {
            this.container.append(this._table);
        }
        if (hasUnroutableWaypoints || !routeType) {
            this.container.append(this._unroutableWarning);
        }
    }

    /**
     * Updates the summary data displayed in the UI based on the provided `DetailedSummaryData`.
     *
     * This method updates each data row with the corresponding leg's label, distance, and optionally elevation gain/loss.
     * If the number of data rows does not match the number of legs, it calls `_emptyPlaceHolder` to adjust the rows.
     * For unroutable legs, an unroutable warning icon is appended if a route type is specified.
     * The footer values for distance, ascent, and descent are also updated based on the total values in the data.
     *
     * @param data - The detailed summary data containing legs, total values, and display options.
     */
    public updateData = (data: DetailedSummaryData): void => {
        if (this._dataRows.length !== data.legs.length)
            this._emptyPlaceHolder(this._dataRows.length, data.showElevation);
        this._dataRows.forEach((row, index) => {
            const leg = data.legs[index]!;
            row.leg.textContent = leg.label;
            if (!row.isRoutable && !!data.routeType)
                row.leg.append(svgFromId(this.settings.unroutableWarning.svgId, [UI.UNROUTABLE_ICON_ID]));
            row.distance.textContent = `${(leg.distance.length / 1000).toFixed(1)}km`;
            if (data.showElevation) {
                row.ascent!.textContent = `${leg.elevation.gain.toFixed(0)}m`;
                row.descent!.textContent = `${leg.elevation.loss.toFixed(0)}m`;
            }
        });
        this._dataColumns.distance.footer.textContent = `${(data.total.distance / 1000).toFixed(1)}km`;
        if (data.showElevation) {
            this._dataColumns.ascent.footer.textContent = `${data.total.elevation.gain.toFixed(0)}m`;
            this._dataColumns.descent.footer.textContent = `${data.total.elevation.loss.toFixed(0)}m`;
        }
    }
}

/**
 * A container class responsible for managing and displaying a detailed summary of a route,
 * including map, table, chart, and GPX download functionality. Handles UI state such as
 * fullscreen and expanded/collapsed views, and synchronizes with the underlying route data.
 *
 * @remarks
 * - Integrates with Mapbox Assist for map display.
 * - Manages DOM elements for summary, table, chart, and fullscreen presentation.
 * - Handles state transitions (initial, loading, loaded, no route) and updates UI accordingly.
 * - Provides GPX download functionality if enabled in settings.
 * - Listens for fullscreen changes and updates layout.
 *
 * @example
 * ```typescript
 * const detailedSummary = new DetailedSummary(routeSummary);
 * ```
 *
 * @public
 */
class DetailedSummary {
    private _state: DetailedSummaryState = DetailedSummaryState.Initial;
    private _fullscreen: boolean | undefined;
    private _expanded: boolean | undefined;

    private _mapWrapper: HTMLElement;
    private _mapContainer: HTMLElement;
    private _tableContainer?: HTMLElement;
    private _chartContainer?: HTMLDivElement;
    private _gpxDownloadLink?: HTMLElement;
    private _gpxStreamBuilder?: GpxStreamBuilder;

    container: HTMLElement = document.createElement("div");
    headerElement: HTMLElement = document.createElement("div");
    summaryBody: HTMLElement = document.createElement("div");
    routeTable: RouteTable;
    fullscreenWrapper: HTMLElement = document.createElement("div");

    /**
     * Constructs a new instance of the class.
     *
     * @param routeSummmary - The summary object containing route information and settings.
     * @param debug - Indicates whether debug mode is enabled.
     *
     * Initializes the map and summary containers, sets up event listeners for fullscreen changes and header button clicks,
     * creates a new RouteTable instance, and sets the initial state to `NoRoute`.
     */
    constructor(private routeSummmary: RouteSummary, private readonly debug: boolean) {
        this._mapWrapper = this.routeSummmary.route.mapWrapper;
        this._mapContainer = this.routeSummmary.route.mapContainer;
        this._buildSummaryContainer();
        this._mapContainer.addEventListener('fullscreenchange', this._handleFullScreenEvent);
        this.routeTable = new RouteTable(this.routeSummmary.settings.detailed.table, this.tableContainer)
        this.state = DetailedSummaryState.NoRoute;
    }

    /**
     * Cleans up and removes all DOM elements and event listeners associated with this instance.
     *
     * This method performs the following actions:
     * - Removes the 'fullscreenchange' event listener from the map container.
     * - Clears the inner HTML of the container element.
     * - Removes the container element from the DOM.
     * - Removes the fullscreen wrapper element from the DOM.
     */
    destroy(): void {
        this._mapContainer.removeEventListener('fullscreenchange', this._handleFullScreenEvent);
        this.container.innerHTML = '';
        this.container.remove();
        this.fullscreenWrapper.remove();
    }

    /**
     * Gets the container element for the summary table.
     * 
     * If the container does not exist, it is created as a `<div>`, assigned the CSS classes
     * specified in `routeSummmary.settings.detailed.table.containerClassList`, and appended
     * to the `summaryBody` element. The created or existing container is then returned.
     *
     * @returns {HTMLElement} The summary table container element.
     */
    public get tableContainer(): HTMLElement {
        if (!this._tableContainer) {
            this._tableContainer = document.createElement("div");
            this._tableContainer.classList.add(...this.routeSummmary.settings.detailed.table.containerClassList);
            this.summaryBody.append(this._tableContainer);
        }
        return this._tableContainer;
    }

    /**
     * Gets the HTMLDivElement used as the chart container for the elevation profile.
     * If the container does not exist, it is created, assigned the appropriate CSS classes
     * from the route summary settings, and prepended to the summary body element.
     *
     * @returns The chart container HTMLDivElement.
     */
    public get chartContainer(): HTMLDivElement {
        if (!this._chartContainer) {
            this._chartContainer = document.createElement("div");
            this._chartContainer.classList.add(...this.routeSummmary.settings.elevationProfile.containerClassList);
            this.summaryBody.prepend(this._chartContainer);
        }
        return this._chartContainer;
    }

    /**
     * Gets the current detailed summary state.
     *
     * @returns The current value of the detailed summary state.
     */
    public get state(): DetailedSummaryState {
        return this._state;
    }

    /**
     * Sets the current state of the route summary component.
     *
     * Updates the internal state, container attributes, and UI elements based on the provided `DetailedSummaryState`.
     * - If the state is unchanged, no action is taken.
     * - Logs state changes if debugging is enabled.
     * - Updates the container's `data-state` and `aria-hidden` attributes.
     * - Handles UI changes for each state:
     *   - `NoRoute`: Clears the route table, collapses the summary, disables the GPX download link, and resets the chart container.
     *   - `Initial`: Collapses the summary, disables the GPX download link, and resets the chart container.
     *   - `Loaded`: Enables the GPX download link and expands the summary.
     *   - `Loading`: Expands the summary.
     *
     * @param value - The new state to set for the route summary.
     */
    public set state(value: DetailedSummaryState) {
        if (value === this._state) return; // no change
        if (this.debug) console.debug('RouteSummary: state changed to ', value);
        this._state = value;
        this.container.dataset.state = value;
        this.container.setAttribute("aria-hidden", String(value === DetailedSummaryState.NoRoute));
        switch (value) {
            case DetailedSummaryState.NoRoute:
                this.routeTable.clear(true);
            case DetailedSummaryState.Initial:
                this.expanded = false;
                this._chartContainer = undefined;
                this._gpxDownloadLink?.setAttribute("disabled", "true");
                break;
            case DetailedSummaryState.Loaded:
                this._gpxDownloadLink?.removeAttribute("disabled");
            case DetailedSummaryState.Loading:
                this.expanded = true;
        }
    }

    /**
     * Gets the fullscreen state.
     *
     * @returns {boolean | undefined} `true` if fullscreen is enabled, `false` if disabled, or `undefined` if the state is not set.
     */
    public get fullscreen(): boolean | undefined {
        return this._fullscreen;
    }

    /**
     * Sets the fullscreen mode for the route summary component.
     * 
     * When set to `true`, moves the container into the fullscreen wrapper,
     * hides the wrapper from assistive technologies, and collapses the summary.
     * When set to `false`, restores the container to its original wrapper and expands the summary.
     * Also updates relevant ARIA attributes and data attributes for accessibility and styling.
     * 
     * @param value - Whether to enable (`true`) or disable (`false`) fullscreen mode.
     */
    public set fullscreen(value: boolean) {
        if (value === this._fullscreen) return; // no change
        if (this.debug) console.debug('RouteSummary: fullscreen changed to ', value);
        this._fullscreen = value;
        this.fullscreenWrapper.setAttribute("aria-hidden", String(!value));
        this.container.dataset.fullscreen = String(value);
        if (value) {
            this.fullscreenWrapper.append(this.container);
            this.headerElement.addEventListener('click', this._headerClickHandler);
            this.expanded = false;
        } else {
            this._mapWrapper.append(this.container);
            this.headerElement.removeEventListener('click', this._headerClickHandler);
            this.expanded = true;
        };
    }

    private _headerClickHandler = (): void => {
        this.expanded = !this.expanded;
    }

    /**
     * Indicates whether the map container element is currently displayed in fullscreen mode.
     *
     * @returns {boolean} `true` if the map container is the fullscreen element; otherwise, `false`.
     */
    get isFullscreen(): boolean {
        return document.fullscreenElement === this._mapContainer;
    }

    /**
     * Handles the fullscreen change event by updating the `fullscreen` property
     * to reflect the current fullscreen state. Logs a debug message if debugging is enabled.
     *
     * @private
     */
    private _handleFullScreenEvent = (): void => {
        if (this.debug) console.debug("Route Summary: Fullscreen change detected");
        this.fullscreen = this.isFullscreen;
    }

    /**
     * Handles the GPX download event for the route summary.
     *
     * This method is triggered by a mouse event (typically a click) and initiates the download
     * of the GPX file if the detailed summary data is loaded. It constructs a title for the GPX file
     * using the names of the first and last waypoints, then calls the GPX stream builder to download
     * the data. If an error occurs during the process, it logs the error and disables the download link.
     *
     * @param event - The mouse event that triggered the download action.
     */
    private _handleGpxDownload = (event: MouseEvent): void => {
        if (this.state === DetailedSummaryState.Loaded && this.routeSummmary.detailedSummaryData) {
            event.stopImmediatePropagation();
            if (this.debug) console.debug("Route Summary: Downloading GPX");
            try {
                const title: string = this.routeSummmary.route.waypoints[0].name! + ' - ' + this.routeSummmary.route.waypoints.at(-1)!.name!
                this._gpxStreamBuilder?.download(this.routeSummmary.detailedSummaryData, title);
            } catch (error) {
                console.error("Route Summary: Error downloading GPX", error);
                this._gpxDownloadLink?.setAttribute("disabled", "true");
            }
        }
    }

    /**
     * Gets a value indicating whether the route summary is expanded.
     * 
     * @returns `true` if the summary is expanded, `false` if collapsed, or `undefined` if the state is not set.
     */
    public get expanded(): boolean | undefined {
        return this._expanded;
    }

    /**
     * Sets the expanded state of the route summary component.
     * This state is only referenced when the map is in full-screen mode.
     * 
     * When set, updates the internal `_expanded` property and synchronizes the
     * expanded state across relevant DOM elements and ARIA attributes for accessibility.
     * If the value does not change, no action is taken.
     * 
     * @param value - A boolean indicating whether the component should be expanded (`true`) or collapsed (`false`).
     */
    public set expanded(value: boolean) {
        if (value === this._expanded) return; // no change
        if (this.debug) console.debug('RouteSummary: expanded changed to ', value);
        this._expanded = value;
        this.container.dataset.expanded = String(value);
        this.fullscreenWrapper.setAttribute("aria-expanded", String(value));
        this.container.setAttribute("aria-expanded", String(value));
        this.headerElement.setAttribute("aria-expanded", String(value));
    }

    /**
     * Builds and configures the summary container UI for the route summary.
     * 
     * This method initializes and assembles the DOM elements required for displaying
     * the route summary, including the header, GPX download link (if enabled), and
     * fullscreen handling. It applies the appropriate CSS classes from the settings,
     * sets up event listeners, and appends the constructed elements to their respective
     * parent containers based on the fullscreen state.
     * 
     * Side effects:
     * - Modifies DOM elements such as `container`, `headerElement`, `summaryBody`, and `fullscreenWrapper`.
     * - Creates and configures the GPX download link and its event handler if GPX download is enabled.
     * - Updates the `expanded` and `fullscreen` state properties.
     * - Appends the summary container to either the fullscreen wrapper or the map wrapper.
     * 
     * @private
     */
    private _buildSummaryContainer(): void {
        const settings = this.routeSummmary.settings.detailed;
        this.container.classList.add(...settings.containerClassList);
        this.headerElement.classList.add(...settings.headerElement.classList);
        const contents = document.createElement('div');
        const headerText = document.createElement("span");
        headerText.textContent = settings.headerElement.text;
        contents.append(headerText);
        if (settings.gpx?.show) {
            this._gpxDownloadLink = document.createElement('a');
            this._gpxDownloadLink.classList.add(...settings.gpx.downloadLink.classList)
            if (settings.gpx.downloadLink.svgId) this._gpxDownloadLink.append(svgFromId(settings.gpx.downloadLink.svgId, [UI.COMPACT_ICON_CLASS]));
            this._gpxDownloadLink.append(settings.gpx.downloadLink.label);
            contents.append(this._gpxDownloadLink);
            this._gpxStreamBuilder = new GpxStreamBuilder(settings.gpx, this._mapContainer, this.debug);
            this._gpxDownloadLink.addEventListener('click', this._handleGpxDownload);
        }
        this.headerElement.append(contents, svgFromId(settings.headerElement.iconSvgId, [UI.STANDARD_ICON_CLASS, "expanded-state"]));
        this.summaryBody.classList.add(...settings.bodyClassList);
        this.container.append(this.headerElement, this.summaryBody);

        this.fullscreenWrapper.classList.add(...settings.fullScreen.containerClassList);
        this._mapContainer.append(this.fullscreenWrapper);

        this.expanded = false;
        this.fullscreen = this.isFullscreen;

        if (this.fullscreen) {
            this.fullscreenWrapper.append(this.container);
        } else {
            this._mapWrapper.append(this.container);
        }
    }
}
