import type { DetailedSummaryData, GPXSettings, RoutePoint } from '../types.js';
import { svgFromId } from '../utility/utility.js';
import { UI } from '../constants.js';

/**
 * A utility class for generating and downloading GPX files from route data in the browser.
 *
 * The `GpxStreamBuilder` class provides methods to:
 * - Prompt the user for GPX file metadata (name and optional author) via a modal dialog.
 * - Generate a standards-compliant GPX 1.1 file, including metadata, waypoints, and track segments.
 * - Stream the GPX file content efficiently and trigger a download in the browser.
 * - Ensure safe and descriptive filenames, and properly escape XML content.
 *
 * The modal dialog and GPX output are customizable via the provided `GPXSettings`.
 *
 * @remarks
 * - The class is intended for use in browser environments.
 * - All DOM elements for the modal dialog are created and removed dynamically.
 * - The GPX file includes custom extensions for additional route metadata if configured.
 *
 * @example
 * ```typescript
 * const builder = new GpxStreamBuilder(settings, document.body);
 * await builder.download(routeData);
 * ```
 *
 * @public
 */
export class GpxStreamBuilder {
    constructor(private readonly settings: GPXSettings, private parentElement: HTMLElement = document.body, private readonly debug: boolean = false) { }

    /**
     * Formats a `RoutePoint` object into a string with latitude and longitude attributes,
     * each rounded to five decimal places, suitable for use in XML or GPX files.
     *
     * @param p - The `RoutePoint` object containing latitude (`lat`) and longitude (`lng`) properties.
     * @returns A string in the format: `lat="..." lon="..."` with coordinates rounded to five decimals.
     */
    private fmtCoord(p: RoutePoint): string {
        return `lat="${p.lat.toFixed(5)}" lon="${p.lng.toFixed(5)}"`;
    }

    /**
     * Creates and displays a modal dialog for user input, allowing the user to enter a name (required)
     * and an optional author. The modal includes cancel and submit buttons, and resolves with the entered
     * data or `null` if the dialog is closed or cancelled.
     *
     * @returns A Promise that resolves to an object containing the `name` (string, required) and
     * optionally `author` (string), or `null` if the modal is closed without submission.
     *
     * @remarks
     * - The modal is dynamically constructed using settings for labels, placeholders, icons, and CSS classes.
     * - The dialog is appended to the component's parent element and removed from the DOM after closing.
     * - The function ensures accessibility by setting appropriate ARIA attributes.
     */
    private _createModal(suggestedTitle?: string): Promise<{ name: string; author?: string } | null> {
        return new Promise((resolve) => {
            const settings = this.settings.modal;

            const dialog = document.createElement('dialog');
            dialog.classList.add(...settings.classLists.dialog);
            dialog.setAttribute('closedby', 'any');

            const titleBar = document.createElement('div');
            titleBar.id = 'mapbox-assist--gpx-dialog-title';
            if (settings.icons?.titleBar) titleBar.append(svgFromId(settings.icons.titleBar, [UI.STANDARD_ICON_CLASS]));
            titleBar.append(settings.title);

            const cancelButton = document.createElement('button');
            cancelButton.classList.add(...settings.classLists.button ?? []);
            cancelButton.type = 'button';
            cancelButton.setAttribute('aria-label', settings.labels.cancelButton);
            cancelButton.append(svgFromId(settings.icons.cancel, [UI.STANDARD_ICON_CLASS]));
            titleBar.append(cancelButton);

            dialog.setAttribute('aria-labelledby', titleBar.id);
            dialog.setAttribute('aria-modal', 'true');
            dialog.setAttribute('role', 'dialog');

            const form = document.createElement('form');
            form.method = 'dialog';

            const controlGroup = (key: "name" | "author"): HTMLDivElement => {
                const element = document.createElement('div');
                element.classList.add(...settings.classLists.controlGroup);

                const label = document.createElement('label');
                label.classList.add(...settings.classLists.label ?? []);
                label.textContent = settings.labels[key] ?? key;

                const input = document.createElement('input');
                input.classList.add(...settings.classLists.input ?? []);
                input.placeholder = settings.placholders?.[key] || '';
                input.type = 'text';
                if (key === 'name') {
                    input.required = (key === 'name');
                    input.autofocus = true;
                    input.autocomplete = "off";
                    input.value = suggestedTitle ?? '';
                } else if (key === 'author') {
                    input.autocomplete = "name";
                }

                input.name = key;

                element.append(label, input);
                return element;
            }

            const buttonRow = document.createElement('div');
            buttonRow.classList.add(...settings.classLists.buttonRow);

            const submitButton = document.createElement('button');
            submitButton.classList.add(...settings.classLists.button ?? []);
            submitButton.type = 'submit';
            submitButton.textContent = settings.labels.downloadButton;
            if (settings.icons?.download)
                submitButton.prepend(svgFromId(settings.icons.download, [UI.COMPACT_ICON_CLASS]));

            buttonRow.append(submitButton);

            form.append(controlGroup('name'), controlGroup('author'), buttonRow);
            dialog.append(titleBar, form);
            this.parentElement.append(dialog);

            cancelButton.addEventListener('click', () => {
                // If the active element is an HTMLElement, blur it to remove focus
                // This is useful for accessibility and to prevent focus trap on mobile browsers
                if (document.activeElement instanceof HTMLElement) {
                    document.activeElement.blur();
                }
                dialog.close();
            });

            form.addEventListener('submit', (e) => {
                e.preventDefault();
                const formData = new FormData(form);
                const name = (formData.get('name') as string).trim();
                if (!name) return;
                const author = (formData.get('author') as string).trim();
                dialog.close();
                dialog.remove();
                resolve({
                    name: name,
                    author: author || undefined,
                });
            });

            dialog.addEventListener('close', () => {
                dialog.remove();
                resolve(null);
            }, { once: true });

            dialog.showModal();
        });
    }

    /**
     * Returns the current local date and time as a formatted string.
     *
     * The format is based on the 'en-CA' locale and includes year, month, day,
     * hour, minute, and second, all in two-digit format with 24-hour time.
     * All spaces, colons, and dashes are replaced with underscores, and the
     * comma separator is removed, resulting in a compact, filename-safe string.
     *
     * @returns {string} The formatted local date and time string.
     */
    private _localDateTime = (): string => {
        // Use 'en-CA' as it outputs dates in yyyy-mm-dd
        return new Intl.DateTimeFormat('en-CA', {
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
            hour: '2-digit',
            minute: '2-digit',
            second: '2-digit',
            hour12: false
        }).format(new Date()).replace(',', '').replace(/[\s:-]/g, '_');
    }

    /**
     * Generates a safe filename for a GPX file based on the provided name.
     * The filename is converted to lowercase, non-alphanumeric characters are replaced with underscores,
     * leading and trailing underscores are removed, and the result is truncated to 25 characters.
     * If the resulting name is empty, a default name using the current local date and time is used.
     * The returned filename always has a `.gpx` extension.
     *
     * @param name - The desired base name for the file.
     * @returns A sanitized filename string with a `.gpx` extension.
     */
    private _safeFilename = (name: string): string => {
        const safeFilename = (name: string): string => {
            return name.toLowerCase()
                .replace(/[^a-z0-9-]+/g, '_')
                .replace(/^_+|_+$/g, '')
                .slice(0, 25)
        }
        name = safeFilename(name);
        if (!name) name = safeFilename(`Track_${this._localDateTime()}`)
        return `${name}.gpx`;
    }

    /**
     * Escapes special XML characters in a string to their corresponding XML entities.
     *
     * The following characters are replaced:
     * - `<` with `&lt;`
     * - `>` with `&gt;`
     * - `&` with `&amp;`
     * - `'` with `&apos;`
     * - `"` with `&quot;`
     *
     * @param unsafe - The input string that may contain characters to escape.
     * @returns The escaped string safe for XML usage.
     */
    private _escapeXml = (unsafe: string): string => {
        return unsafe.replace(/[<>&'"]/g, (c) => {
            switch (c) {
                case '<': return '&lt;';
                case '>': return '&gt;';
                case '&': return '&amp;';
                case '\'': return '&apos;';
                case '"': return '&quot;';
                default: return c;
            }
        });
    }

    /**
     * Downloads the provided route data as a GPX file.
     *
     * This method prompts the user for a file name and optional author information,
     * then generates a GPX file containing route metadata, waypoints, and track segments.
     * The GPX file is streamed and downloaded directly in the browser.
     *
     * @param data - The detailed summary data containing route profile, legs, and totals.
     * @returns A promise that resolves when the GPX file has been generated and the download initiated.
     * @throws {Error} If GPX file generation fails.
     */
    async download(data: DetailedSummaryData, suggestedTitle?: string): Promise<void> {
        try {
            const userInput = await this._createModal(suggestedTitle);
            if (!userInput) return;

            const { name, author } = userInput!;
            const encoder = new TextEncoder();
            const creator = `${location.origin}${location.pathname}`;
            const rParam = new URLSearchParams(location.search).get('r');
            const url = `${creator}${rParam ? `?r=${rParam}` : ''}`;
            const points: RoutePoint[] = data.routeProfile;
            const waypoints = points.filter(p => !!p.name);

            const stream = new ReadableStream<Uint8Array>({
                start: (controller) => {
                    const push = (s: string) => controller.enqueue(encoder.encode(s));
                    push(`<?xml version="1.0" encoding="UTF-8"?><gpx version="1.1" creator="${creator}" `);
                    push(`xmlns="http://www.topografix.com/GPX/1/1" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" `);
                    if (this.settings.extensions) push(`xmlns:gpx="${this.settings.extensions.namespace}" `);
                    push(`xsi:schemaLocation="http://www.topografix.com/GPX/1/1 http://www.topografix.com/GPX/1/1/gpx.xsd`);
                    if (this.settings.extensions) push(` ${this.settings.extensions.namespace} ${this.settings.extensions.schemaURL}`);
                    push(`">`);
                    push(`<metadata><name>${this._escapeXml(name)}</name>`);
                    push(`<extensions>`);
                    push(`<gpx:length>${(data.total.distance / 1000).toFixed(3)}</gpx:length>`);
                    push(`<gpx:ele_gain>${data.total.elevation.gain.toFixed(0)}</gpx:ele_gain>`);
                    push(`<gpx:ele_loss>${data.total.elevation.loss.toFixed(0)}</gpx:ele_loss>`);
                    push(`</extensions>`);
                    if (this.settings.description) push(`<desc>${this._escapeXml(this.settings.description)}</desc>`);
                    if (author) push(`<author><name>${this._escapeXml(author)}</name></author>`);
                    push(`<url>${url}</url>`);
                    push(`<time>${new Date().toISOString()}</time></metadata>`);

                    waypoints.forEach((pt, index) => {
                        push(`<wpt ${this.fmtCoord(pt)}>`);
                        push(`<name>${this._escapeXml(pt.name || `Waypoint #${index}`)}</name>`);
                        if (pt.elevation !== undefined) push(`<ele>${pt.elevation.toFixed(1)}</ele>`);
                        push(`<extensions>`);
                        push(`<gpx:dist_from_start>${pt.distance.toFixed(3)}</gpx:dist_from_start>`);
                        if (index !== waypoints.length - 1) push(`<gpx:segment_start>true</gpx:segment_start>`)
                        push(`</extensions>`);
                        push(`</wpt>`);
                    });

                    push(`<trk><name>${this._escapeXml(name)}</name>`);
                    let legIndex: number = 0;
                    points.forEach(pt => {
                        if (!!pt.name && legIndex < waypoints.length - 1) {
                            if (legIndex !== 0) push(`</trkseg>`);
                            push(`<trkseg><extensions>`);
                            const legName = data.legs[legIndex]?.label || `Track Leg #${legIndex + 1}`
                            push(`<gpx:name>${this._escapeXml(legName)}</gpx:name>`)
                            push(`<gpx:length>${(data.legs[legIndex]?.distance.length / 1000).toFixed(3)}</gpx:length>`);
                            push(`<gpx:ele_gain>${data.legs[legIndex]?.elevation.gain.toFixed(0)}</gpx:ele_gain>`);
                            push(`<gpx:ele_loss>${data.legs[legIndex]?.elevation.loss.toFixed(0)}</gpx:ele_loss>`);
                            push(`</extensions>`);
                            legIndex++;
                        }
                        push(`<trkpt ${this.fmtCoord(pt)}>`);
                        if (pt.elevation !== undefined) push(`<ele>${pt.elevation.toFixed(1)}</ele>`);
                        push(`</trkpt>`);
                    });

                    push(`</trkseg></trk></gpx>`);
                    controller.close();
                }
            });

            const blob = new Response(stream).blob();
            const blobUrl = URL.createObjectURL(await blob);
            const a = document.createElement('a');
            a.href = blobUrl;
            a.download = this._safeFilename(name);
            a.style.display = 'none';
            document.body.append(a);
            a.click();
            a.remove();
            URL.revokeObjectURL(blobUrl);

        } catch (error) {
            console.error('Failed to generate GPX file:', error);
            throw new Error('GPX file generation failed');
        }
    }
}
