import mapboxgl from 'mapbox-gl';
import type { Coordinates } from '../utility/index.js';

export type PointVertices = {
    topLeft: mapboxgl.Point;
    topRight: mapboxgl.Point;
    bottomLeft: mapboxgl.Point;
    bottomRight: mapboxgl.Point;
};

export type ScreenBox = {
    vertices: PointVertices;
    center: mapboxgl.Point;
};

export type GeoBox = {
    vertices: {
        topLeft: mapboxgl.LngLat;
        topRight: mapboxgl.LngLat;
        bottomLeft: mapboxgl.LngLat;
        bottomRight: mapboxgl.LngLat;
    };
    bounds: mapboxgl.LngLatBounds;
    center: mapboxgl.LngLat;
};

export type BoundingBox = {
    screen: ScreenBox;
    geo: GeoBox;
}

export type GeoCircle = {
    center: Coordinates | mapboxgl.LngLat;
    radiusKm: number;
}