import mapboxgl from 'mapbox-gl';
import { CoordinateParser, getMapboxAccessToken } from '../utility/utility.js';
import type { Feature, FeatureCollection, Point as GeojsonPoint } from 'geojson';
import { MAPBOX, UI } from '../constants.js';
import { MapboxHTMLEvent, MapboxSearchBox } from '../types.js';
import type { SearchSettings } from '../types.js';

/**
 * Represents the possible states of a search box UI component.
 *
 * @remarks
 * This enum is used to track the current state of the search box,
 * such as whether it is focused, loading results, displaying results,
 * or has encountered an error.
 *
 * @enum {string}
 * @property {string} Initial - The search box is in its initial, unfocused state.
 * @property {string} Focused - The search box is currently focused by the user.
 * @property {string} Loading - The search box is fetching or processing search results.
 * @property {string} Results - The search box has results to display.
 * @property {string} Error - An error occurred during the search process.
 */
export enum SearchBoxState {
    Initial = 'initial',
    Focused = 'focused',
    Loading = 'loading',
    Results = 'results',
    Error = 'error'
}

type RetrieveEventDetail = FeatureCollection & {
    features: (Feature<GeojsonPoint> & {
        properties: {
            name?: string;
            [key: string]: any;
        };
    })[];
};

/**
 * A custom Mapbox GL control that provides a search box UI for geocoding and coordinate input.
 * 
 * This control wraps the MapboxSearchBox and manages its lifecycle, state, and accessibility.
 * It supports proximity biasing based on the map's center, debounced coordinate parsing, and
 * ARIA attribute management for accessibility.
 * 
 * ### Features
 * - Integrates MapboxSearchBox as a map control.
 * - Handles focus, blur, and input events to manage UI state.
 * - Fixes Mapbox bug where on-screen keyboard obscures the results, but clicking done dismisses results.
 * - Supports searching by coordinates (GPS input) and places a marker on the map.
 * - Automatically updates proximity bias for search results based on map movement.
 * - Manages ARIA attributes for accessibility compliance.
 * - Emits custom events on state changes.
 * 
 * ### Usage
 * ```typescript
 * const searchControl = new SearchBoxControl(settings, debug);
 * map.addControl(searchControl, 'top-left');
 * ```
 * 
 * ### Settings
 * ```typescript
 * {
     accessToken?: string; // optional search token - falls back to mapboxgl access token in use
     placeholder?: string; // optional text to appear in empty search input control
     useProximityBias?: boolean; // use proximity biasing to show results closer to the map center
     options?: Partial<SearchBoxOptions> // any relevant Mapbox SearchBoxOptions - see https://docs.mapbox.com/api/search/search-box/
   }
 * ```
 * 
 * ### States
 * SearchBoxStates 
 * States have accompanying css classes on the control container. Use these to control the apperance of the search box.
 * ```typescript
 *      [SearchBoxState.Initial]: ['searchbox--initial'],
        [SearchBoxState.Focused]: ['searchbox--focused'],
        [SearchBoxState.Loading]: ['searchbox--loading'],
        [SearchBoxState.Results]: ['searchbox--focused', 'searchbox--results'],
        [SearchBoxState.Error]: ['searchbox--error']
 * ```
 *        
 * @remarks
 * - Requires a valid Mapbox access token either passed in settings or loaded in mapboxgl instance.
 * - Designed for use with Mapbox GL JS v3+.
 * - The control cleans up all event listeners and DOM nodes on removal.
 * - An error is logged to console when searching coordinates - this comes from the Mapbox Search API. It can be ignored.
 * 
 * @example
 * ```typescript
 * const searchControl = new SearchBoxControl({ accessToken: 'YOUR_TOKEN', useProximityBias: true });
 * map.addControl(searchControl);
 * ```
 * 
 * @fires expandEvent - Dispatched when the search box state changes.
 * @fires searchResultPositionedEvent - Dispatched when map finishes moving to clicked search result.
 * 
 * @public
 */
export default class SearchBoxControl extends EventTarget implements mapboxgl.IControl {
    private _map?: mapboxgl.Map;
    private _mapContainer!: HTMLElement;
    private _container!: HTMLDivElement;
    private _searchBox!: MapboxSearchBox;
    private _searchBoxInputContainer!: HTMLElement;
    private _searchBoxInput!: HTMLInputElement;
    private _clearButton!: HTMLButtonElement;
    private _results!: HTMLElement;
    private _state: SearchBoxState = SearchBoxState.Initial;
    private readonly stateClasses = {
        [SearchBoxState.Initial]: ['searchbox--initial'],
        [SearchBoxState.Focused]: ['searchbox--focused'],
        [SearchBoxState.Loading]: ['searchbox--loading'],
        [SearchBoxState.Results]: ['searchbox--focused', 'searchbox--results'],
        [SearchBoxState.Error]: ['searchbox--error']
    };
    private _blurTimeout: NodeJS.Timeout | null = null;
    private _debounceTimeout: NodeJS.Timeout | null = null;

    constructor(private readonly settings: SearchSettings, private readonly debug: boolean = false) {
        super();
    }

    /**
     * Adds the search control to the given Mapbox map instance.
     *
     * This method creates the search box UI, sets up event listeners for user interactions,
     * and observes the DOM for the dynamic addition of internal elements. It also handles
     * cleanup of observers and timeouts, and initializes proximity bias if enabled in settings.
     *
     * @param map - The Mapbox map instance to which the search control will be added.
     * @returns The HTML container element for the search control.
     */
    onAdd(map: mapboxgl.Map): HTMLElement {
        let observer: MutationObserver;
        let timeout: NodeJS.Timeout;

        this._map = map;
        this._mapContainer = map.getContainer();
        this._searchBox = this._createSearchBoxObject();
        this._container = document.createElement('div');
        this._container.classList = 'mapboxgl-ctrl searchbox-container';
        this.state = SearchBoxState.Loading;
        this._container.append(this._searchBox as Node);

        const cleanup = () => {
            observer?.disconnect();
            clearTimeout(timeout);
        };

        // Set up a MutationObserver to detect when internals are added
        observer = new MutationObserver(() => {
            const inputContainer = this._container.querySelector('div[class$="--SearchBox"]');
            const input = this._container.querySelector('input');
            const results = this._container.querySelector('div[class$="--Results"]');
            const clearButton = this._container.querySelector('button[class$="--ClearBtn"]');

            if (inputContainer && input && results && clearButton) {
                cleanup();
                this._searchBoxInputContainer = inputContainer as HTMLButtonElement;
                this._searchBoxInput = input as HTMLInputElement;
                this._results = results as HTMLDivElement;
                this._clearButton = clearButton as HTMLButtonElement;

                this._searchBoxInputContainer.addEventListener('click', this._containerClickHandler, true);
                this._clearButton.addEventListener('blur', this._blurHandler, true);
                this._clearButton.addEventListener('click', this._clearClickHandler, true);
                this._searchBoxInput.addEventListener('blur', this._blurHandler, true);
                this._searchBoxInput.addEventListener('keydown', this._keydownHandler, true);
                this._searchBoxInput.addEventListener('input', this._inputHandler, true);
                this._searchBoxInput.addEventListener('input', this._debounce(this._handleGPSInput), true);
                this._searchBox.addEventListener('retrieve', this._retrieveHandler, true);
                this.state = SearchBoxState.Initial;
            }
        });

        timeout = setTimeout(() => {
            cleanup();
            console.warn("SearchBox internal elements did not load in time.");
        }, 5000);

        observer.observe(this._container, {
            childList: true,
            subtree: true,
        });

        if (this.settings.useProximityBias) {
            this._setProximity();
            map.on('moveend', this._setProximity);
        }
        return this._container;
    }

    /**
     * Cleans up event listeners, timeouts, and DOM elements associated with the search control.
     * 
     * This method should be called when the control is being removed from the map to prevent memory leaks
     * and unintended behavior. It detaches all event listeners, clears any active _debounce timeouts,
     * removes the control's container from the DOM, and resets the map reference.
     */
    onRemove(): void {
        if (this.settings.useProximityBias) {
            this._map?.off('moveend', this._setProximity);
        }
        this._searchBoxInputContainer.removeEventListener('click', this._containerClickHandler, true);
        this._clearButton.removeEventListener('blur', this._blurHandler, true);
        this._clearButton.removeEventListener('click', this._clearClickHandler, true);
        this._searchBoxInput.removeEventListener('blur', this._blurHandler, true);
        this._searchBoxInput.removeEventListener('keydown', this._keydownHandler, true);
        this._searchBoxInput.removeEventListener('input', this._inputHandler, true);
        this._searchBoxInput.removeEventListener('input', this._debounce(this._handleGPSInput), true);
        this._searchBox.removeEventListener('retrieve', this._retrieveHandler, true);
        if (this._debounceTimeout) {
            clearTimeout(this._debounceTimeout);
            this._debounceTimeout = null;
        }
        if (this._container.parentNode) {
            this._container.parentNode.removeChild(this._container);
        }
        this._map = undefined;
    }

    getDefaultPosition(): mapboxgl.ControlPosition {
        return 'top';
    }

    /**
     * Creates and configures a new instance of `MapboxSearchBox` with the current settings.
     *
     * - Sets the access token from settings or a fallback getter.
     * - Throws an error if the access token is missing.
     * - Optionally sets the placeholder text if provided in settings.
     * - Applies additional options from settings.
     * - Injects the `MapboxGL` object as a workaround for missing types.
     * - Disables the default marker.
     * - Binds the search box to the current map instance.
     *
     * @returns {MapboxSearchBox} The configured search box instance.
     * @throws {Error} If no Mapbox access token is available.
     */
    private _createSearchBoxObject = (): MapboxSearchBox => {
        const searchBox = new MapboxSearchBox();
        searchBox.accessToken = this.settings.accessToken ?? getMapboxAccessToken();
        if (!searchBox.accessToken) {
            throw new Error('Mapbox access token is required for SearchBox.');
        }
        if (this.settings.placeholder) searchBox.placeholder = this.settings.placeholder;
        searchBox.options = this.settings.options ?? {};
        (searchBox as any)['mapboxgl'] = mapboxgl; // workaround: required types missing from mapboxgl
        searchBox.marker = false;
        searchBox.bindMap(this._map!);
        return searchBox;
    }

    /**
     * Dispatches a custom "expandEvent" event with the provided search box state as its detail.
     *
     * @param value - The current state of the search box to include in the event detail.
     */
    private _dispatchExpandEvent(value: SearchBoxState): void {
        this.dispatchEvent(new CustomEvent("expandEvent", { detail: value }));
    }

    /**
     * Clears the blur timeout if it is set, preventing any pending blur actions from executing.
     * Resets the `_blurTimeout` property to `null` after clearing.
     * 
     * @private
     */
    private _clearTimer = (): void => {
        if (this._blurTimeout) {
            clearTimeout(this._blurTimeout);
            this._blurTimeout = null;
        }
    }

    /**
     * Handles the click event for clearing the search box.
     * 
     * - Sets the search box state to `Focused`.
     * - Clears any existing timer.
     * - Starts a timeout to reset the state to `Initial` after 3 seconds.
     * - Stores the timeout ID in `_blurTimeout` for potential future clearing.
     *
     * @private
     */
    private _clearClickHandler = (): void => {
        this.state = SearchBoxState.Focused;
        this._clearTimer();
        this._blurTimeout = setTimeout(() => {
            this.state = SearchBoxState.Initial;
            this._searchBoxInput.blur();
            this._blurTimeout = null;
        }, MAPBOX.SEARCH_BOX_CLEAR_TIMEOUT);
    }

    /**
     * Handles click events on the search box container.
     * 
     * - Clears any active timer.
     * - If the search box is in the initial state:
     *   - If there is input, transitions to the results state.
     *   - Otherwise, transitions to the focused state.
     *   - Selects the input text.
     * - Focuses the search box input.
     *
     * @private
     */
    private _containerClickHandler = (): void => {
        this._clearTimer();
        if (this.state === SearchBoxState.Initial) {
            if (this._searchBoxInput.value.length) {
                this.state = SearchBoxState.Results;
            } else {
                this.state = SearchBoxState.Focused;
            }
            this._searchBoxInput.select();
        }
        this._searchBoxInput.focus();
    }

    /**
     * Handles the blur event for the search box.
     * 
     * When triggered, this method sets a timeout to reset the search box state
     * to `SearchBoxState.Initial` after 1 second. It also clears the timeout
     * reference after execution. This allows for a delayed reset of the search
     * box state when it loses focus.
     *
     * @private
     */
    private _blurHandler = (): void => {
        this._blurTimeout = setTimeout(() => {
            this.state = SearchBoxState.Initial;
            this._blurTimeout = null;
        }, MAPBOX.SEARCH_BOX_BLUR_TIMEOUT);
    }

    /**
     * Handles keyboard events for the search box input.
     *
     * - On 'Enter' or 'Done' key press: Prevents the default action, focuses the clear button,
     *   clears any active timers, and updates ARIA attributes to indicate that results are shown.
     * - On 'Escape' key press: Sets the search box state to focused.
     *
     * @param event - The keyboard event triggered by user interaction.
     */
    private _keydownHandler = (event: KeyboardEvent) => {
        if (event.key === 'Enter' || event.key === 'Done') {
            event.preventDefault();
            this._clearButton.focus();
            setTimeout(() => {
                this._clearTimer();
                this._updateAriaAttributes(SearchBoxState.Results);
            }, 0);
        } else if (event.key === 'Escape') {
            this.state = SearchBoxState.Focused;
        }
    }

    /**
     * Handles the input event for the search box.
     * 
     * Updates the component's state based on whether the input field contains any text.
     * - If the input has a value, sets the state to `SearchBoxState.Results`.
     * - If the input is empty, sets the state to `SearchBoxState.Focused`.
     *
     * @param event - The input event triggered by the user typing in the search box.
     */
    private _inputHandler = (event: Event) => {
        if ((event.target as HTMLInputElement).value.length) {
            this.state = SearchBoxState.Results;
        } else {
            this.state = SearchBoxState.Focused;
        }
    }

    /**
     * Handles the retrieval of search results from a Mapbox event.
     * 
     * This method clears any existing search markers and popups, extracts the first feature
     * from the event details, and, if present, creates a new `mapboxgl.LngLat` instance from the feature's
     * geometry coordinates. It then waits for the map to move before emitting the search result's
     * positioned event with the feature's name and coordinates.
     * 
     * @param e - The Mapbox HTML event containing the search result details.
     */
    private _retrieveHandler = (e: MapboxHTMLEvent<RetrieveEventDetail>) => {
        // clear existing search markers and popups
        this._clearMarkersPopups();
        const feature = e.detail.features[0];
        if (!feature) return;
        if (this.debug) console.debug('Search found the following feature:', feature);
        const { geometry, properties } = feature;
        const lngLat = new mapboxgl.LngLat(...geometry.coordinates as [number, number]);
        // wait for map move to initiate adding marker
        this._map!.once('move', () => this._emitSearchResultPositioned(properties.name, lngLat));
    }

    /**
     * Sets the search box's proximity option to the current center of the map.
     * 
     * This method updates the `proximity` property of the search box options
     * to match the map's current center coordinates, which can be used to
     * bias search results towards the map's center location.
     *
     * @private
     */
    private _setProximity = (): void => {
        this._searchBox.options.proximity = this._map!.getCenter() as mapboxgl.LngLat;
    }

    /**
     * Creates a debounced version of the provided function, ensuring that it is only invoked
     * after a specified delay has elapsed since the last time it was called.
     *
     * @template T - The type of the function to debounce.
     * @param fn - The function to debounce.
     * @param delay - The number of milliseconds to delay; defaults to 300ms.
     * @returns A debounced function that delays invoking `fn` until after `delay` milliseconds have elapsed
     *          since the last time the debounced function was called.
     *
     * @remarks
     * If the debounced function is called again before the delay has elapsed, the previous timeout is cleared
     * and the delay restarts. The debounced function preserves the `this` context of the class instance.
     */
    private _debounce<T extends (...args: any[]) => void>(
        fn: T,
        delay: number = UI.DOUBLE_CLICK_DELAY
    ): (...args: Parameters<T>) => void {
        return (...args: Parameters<T>) => {
            if (this._debounceTimeout) {
                clearTimeout(this._debounceTimeout);
            }
            this._debounceTimeout = setTimeout(() => {
                fn.apply(this, args);
                this._debounceTimeout = null;
            }, delay);
        };
    }

    /**
     * Handles input from the search box when GPS coordinates are entered.
     * 
     * Attempts to parse the input value as coordinates using `CoordinateParser`.
     * If parsing is successful, creates a `mapboxgl.LngLat` object, clears existing markers and popups,
     * moves the map to the specified coordinates with a zoom level of 14, and emits a search result event.
     * Logs an error to the console if coordinate parsing fails.
     * 
     * @Remarks
     * This method is triggered when the user inputs GPS coordinates directly into the search box.
     * An error will show in the console regardless of correct input. This is thrown by the Mapbox API
     * and cannot be avoided without making a custom search handler. For the purposes of this application'
     * it is left as is.
     *
     * @private
     */
    private _handleGPSInput = (): void => {
        try {
            const coords = CoordinateParser.parse(this._searchBoxInput.value);
            if (!coords) return;
            const lngLat = new mapboxgl.LngLat(...coords);
            // Clear markers
            this._clearMarkersPopups();
            this._map!.flyTo({ center: lngLat, zoom: MAPBOX.SEARCH_RESULT_FLY_TO_ZOOM });
            this._emitSearchResultPositioned(undefined, lngLat);
        } catch (error) {
            console.error('SearchBoxControl._handleGPSInput: Failed to parse coordinates:', error);
        }
    }

    /**
     * Removes all search-related markers and popups from the map container.
     *
     * This method queries the map container for all elements with the classes
     * 'mapboxgl-popup' and 'mapboxgl-marker search-marker', and removes them
     * from the DOM. It is typically used to clear previous search results or
     * reset the map's state.
     *
     * @private
     */
    private _clearMarkersPopups = (): void => {
        this._mapContainer.querySelectorAll('div.mapboxgl-popup, div.mapboxgl-marker.search-marker').forEach((item) => {
            item.remove();
        });
    }

    /**
     * Emits a custom "searchResultPositioned" event with the provided label and geographical coordinates.
     * If the map is currently moving, the event emission is deferred until the movement ends.
     *
     * @param label - The label associated with the search result, or undefined if not available.
     * @param lngLat - The longitude and latitude of the search result as a `mapboxgl.LngLat` object.
     */
    private _emitSearchResultPositioned = (label: string | undefined, lngLat: mapboxgl.LngLat) => {
        if (this._map!.isMoving()) {
            this._map!.once('moveend', () => this._emitSearchResultPositioned(label, lngLat));
            return;
        }
        // dispatch event with clicked result details for handling on the wrapping class
        const searchResultPositionedEvent = new CustomEvent(
            "searchResultPositioned", {
                detail: {
                    lngLat: lngLat, 
                    label: label
                }
            }
        )
        this.dispatchEvent(searchResultPositionedEvent);
    }

    // --- state management ---

    /**
     * Gets or sets the current state of the search box control.
     * 
     * This property manages the state of the search box, updating the container's class list
     * and ARIA attributes based on the current state. It also dispatches an event when the state changes.
     *
     * @private
     */
    private get state(): SearchBoxState {
        return this._state;
    }

    /**
     * Sets the state of the search box control.
     * 
     * This method updates the state of the search box, modifies the container's class list
     * to reflect the new state, and updates ARIA attributes for accessibility. It also dispatches
     * an event to notify other components of the state change.
     *
     * @param newState - The new state to set for the search box control.
     */
    private set state(newState: SearchBoxState) {
        const oldState = this._state;
        if (oldState === newState) return;

        // Remove old state class
        this._container?.classList.remove(...this.stateClasses[oldState]);

        // Add new state class
        this._container?.classList.add(...this.stateClasses[newState]);

        // Update ARIA attributes based on state
        this._updateAriaAttributes(newState);

        this._state = newState;

        // Dispatch state change event
        this._dispatchExpandEvent(newState)

        if (this.debug) {
            console.debug(`SearchBoxControl: State changed from ${oldState} to ${newState}`);
        }
    }

    /**
     * Updates the ARIA attributes of the search box and results container based on the current state.
     *
     * @private
     */
    private _updateAriaAttributes(state: SearchBoxState): void {
        if (!this._searchBoxInput || !this._results) return;

        switch (state) {
            case SearchBoxState.Loading:
                this._searchBoxInput?.setAttribute('aria-busy', 'true');
                break;
            case SearchBoxState.Focused:
                this._searchBoxInput.setAttribute('aria-expanded', 'true');
                break;
            case SearchBoxState.Results:
                this._results.setAttribute('aria-hidden', 'false');
                break;
            case SearchBoxState.Error:
                this._searchBoxInput?.setAttribute('aria-invalid', 'true');
                break;
            default:
                this._searchBoxInput.removeAttribute('aria-busy');
                this._searchBoxInput.removeAttribute('aria-invalid');
                this._searchBoxInput.setAttribute('aria-expanded', 'false');
                this._results.setAttribute('aria-hidden', 'true');
        }
    }


}