/**
 * A utility class for displaying temporary toast messages within a specified host element.
 *
 * Toast messages are shown as transient notifications that fade in and out, and are automatically
 * removed from the DOM after a specified duration. Each host element can have its own toast container.
 *
 * @example
 * ```typescript
 * Toast.show(document.body, "Hello, world!", 2000);
 * ```
 *
 * @remarks
 * - Toast messages are styled using the `toast-message` and `toast-wrapper` CSS classes.
 * - The toast container is automatically created and removed as needed.
 *
 * @public
 */
export default class Toast {
    private static containerMap = new WeakMap<HTMLElement, HTMLElement>();

    /**
     * Displays a toast message within the specified host element for a given duration.
     *
     * @param host - The HTMLElement where the toast message will be displayed.
     * @param message - The message to show in the toast.
     * @param duration - Optional. The duration in milliseconds for which the toast will be visible. Defaults to 1500ms.
     *
     * The toast will fade in, remain visible for the specified duration, and then fade out.
     * If no other toasts remain, the wrapper element will be removed from the DOM.
     */
    static show(host: HTMLElement, message: string, duration = 1500): void {
        const toastWrapper = this._getOrCreateWrapper(host);

        const toast = document.createElement("div");
        toast.className = "toast-message";
        toast.textContent = message;

        toastWrapper.appendChild(toast);

        // Trigger fade-in animation
        requestAnimationFrame(() => {
            toast.classList.add("visible");
        });

        // Remove after timeout
        setTimeout(() => {
            toast.classList.remove("visible");
            toast.addEventListener("transitionend", () => {
                toast.remove();
                if (toastWrapper.children.length === 0) {
                    toastWrapper.remove();
                    this.containerMap.delete(host);
                }
            });
        }, duration);
    }

    /**
     * Retrieves an existing toast wrapper element associated with the given host element,
     * or creates a new one if it does not exist. The wrapper is a `<div>` with the class
     * "toast-wrapper" appended to the host element. The association between the host and
     * its wrapper is managed internally using a container map.
     *
     * @param host - The host HTMLElement to which the toast wrapper should be attached.
     * @returns The existing or newly created toast wrapper HTMLElement.
     */
    private static _getOrCreateWrapper(host: HTMLElement): HTMLElement {
        if (this.containerMap.has(host)) {
            return this.containerMap.get(host)!;
        }

        const wrapper = document.createElement("div");
        wrapper.className = "toast-wrapper";
        host.appendChild(wrapper);
        this.containerMap.set(host, wrapper);
        return wrapper;
    }
}
