import mapboxgl from 'mapbox-gl';
import RouteForm, { RouteFormState } from './Form.js';
import type { FoundFeatureResult, FoundRouteResult, Waypoint, WaypointFormSettings } from '../types.js';
import { getRandomString, svgFromId } from '../utility/utility.js';
import { Routable } from './Routable.js';
import { UI } from '../constants.js';

/**
 * Enum representing the available button actions for a waypoint form item.
 *
 * @enum {string}
 * @property {string} moveUp - Button to move the waypoint up in the list.
 * @property {string} moveDown - Button to move the waypoint down in the list.
 * @property {string} delete - Button to delete the waypoint.
 * @property {string} grip - Button to grip and drag the waypoint.
 */
enum FormWaypointButton {
    moveUp = 'moveUp',
    moveDown = 'moveDown',
    delete = 'bin',
    grip = 'grip'
}

/**
 * Represents the collection of DOM elements associated with a waypoint form item.
 *
 * @property listItem - The `<li>` element representing the waypoint in a list.
 * @property name - The `<textarea>` element for editing the waypoint's name.
 * @property buttons - A mapping of button types to their corresponding HTML elements.
 * @property coordinates - An object containing elements related to the waypoint's coordinates:
 *   - container: The `<div>` wrapping the coordinate controls.
 *   - input: The `<input>` element for entering coordinates.
 *   - display: The `<span>` element for displaying formatted coordinates.
 * @property routableWarning - The `<div>` element displaying a warning if the waypoint is not routable.
 */
type FormWaypointElements = {
    listItem: HTMLLIElement;
    name: HTMLTextAreaElement;
    buttons: Record<FormWaypointButton, HTMLElement>;
    coordinates: {
        container: HTMLDivElement;
        input: HTMLInputElement;
        display: HTMLSpanElement;
    };
    routableWarning: HTMLDivElement;
}

/**
 * Represents a UI form item for a single waypoint in a route planning interface.
 * 
 * The `FormWaypoint` class manages the creation, updating, and destruction of a waypoint form element,
 * including its DOM structure, event listeners, and interaction with the parent `RouteForm`.
 * It provides methods for updating the waypoint's name, swapping its position in the list,
 * deleting the waypoint, and handling routability checks.
 * 
 * @remarks
 * - Handles DOM creation and manipulation for a waypoint form item.
 * - Integrates with the parent `RouteForm` to update the route state and waypoint layers.
 * - Manages event listeners for user interactions such as moving, deleting, and editing waypoints.
 * - Checks if the waypoint is routable and displays a warning if not.
 * 
 * @example
 * ```typescript
 * const waypoint = new Waypoint(...);
 * const formWaypoint = new FormWaypoint(routeForm, waypoint, true);
 * ```
 * 
 * @public
 */
export class FormWaypoint extends EventTarget {
    elements: FormWaypointElements;
    settings: WaypointFormSettings;

    /**
     * Initializes a new instance of the FormWaypoint class.
     *
     * @param routeForm - The parent RouteForm instance associated with this waypoint.
     * @param waypoint - The Waypoint object containing location and metadata.
     * @param debug - Optional flag to enable debug mode. Defaults to false.
     */
    constructor(public readonly routeForm: RouteForm, public waypoint: Waypoint, private readonly debug: boolean = false) {
        super();
        this.settings = routeForm.settings.waypointFormSettings;
        this.elements = this._buildListItem();
        this._addEventListeners();
        this._getWaypointInfo();
    }

    /**
     * Cleans up the FormWaypoint instance by removing event listeners,
     * detaching the associated list item element from the DOM,
     * and resetting the elements reference.
     *
     * This method should be called when the FormWaypoint is no longer needed
     * to prevent memory leaks and ensure proper resource management.
     */
    destroy(): void {
        this._removeEventListeners();
        this.elements.listItem.remove();
        this.elements = undefined as unknown as FormWaypointElements;
    }

    /**
     * Updates the value of the name input element and triggers the name change handler.
     *
     * @param value - The new name to set for the waypoint.
     * 
     * @remarks
     * This method is typically called by the parent form when the waypoint name is missing during submission.
     */
    updateName = (value: string): void => {
        // called from parent form if missing name when submitting
        this.elements.name.value = value;
        this._nameChangeHandler();
    };

    /**
     * Indicates whether the waypoint is routable.
     *
     * @returns {boolean | undefined} `true` if the waypoint can be used for routing,
     * `false` if it cannot, or `undefined` if the routability is unknown.
     */
    get isRoutable(): boolean | undefined {
        return this.waypoint.isRoutable;
    }

    /**
     * Sets the routable status of the waypoint and updates the UI accordingly.
     * 
     * If the value changes:
     * - When set to `true`, clears any routable warning message from the UI.
     * - When set to `false`, displays a routable warning message in the UI.
     * 
     * @param value - Indicates whether the waypoint is routable.
     */
    set isRoutable(value: boolean) {
        if (value.toString() !== this.elements.routableWarning.dataset.isRoutable) {
            if (value) {
                this.elements.routableWarning.innerHTML = "";
            } else {
                this.elements.routableWarning.append(this._routableWarning)
            }
            this.elements.routableWarning.dataset.isRoutable = value.toString();
        }
        this.waypoint.isRoutable = value;
    }

    /**
     * Retrieves and applies metadata for the current waypoint, then updates routing and UI state.
     *
     * Workflow:
     * - Attempts to resolve a display name and coordinates for the waypoint.
     * - Checks whether the waypoint is routable; if so (and a route type is set), snaps and updates coordinates.
     * - Fills in the waypoint name if it remains unset after routability checks.
     * - Updates the parent route's waypoint layer, scrolls the corresponding list item into view,
     *   and schedules a microtask to dispatch a 'waypointInfoLoaded' CustomEvent with the waypoint as detail.
     *
     * Error handling:
     * - Any errors during lookup or routability checks are caught and (optionally) logged when debug mode is enabled.
     *
     * Side effects:
     * - Mutates this.isRoutable and may update the waypoint's name and coordinates.
     * - Calls routeForm.route.updateWaypointLayerSource to refresh map layers.
     * - Performs DOM interactions (scrollIntoView and dispatchEvent).
     *
     * Events:
     * - Emits 'waypointInfoLoaded' (CustomEvent) in a microtask with the waypoint as the event detail.
     *
     * @fires waypointInfoLoaded
     * @returns void
     * @internal
     */
    private _getWaypointInfo = (): void => {
        this._findWaypointName(this.waypoint)
            .then((foundFeatureResult) => {
                if (!this.waypoint.name && foundFeatureResult.name) {
                    this._updateCoordinates(foundFeatureResult.lngLat, false);
                    this.updateName(foundFeatureResult.name);
                }

                return this._checkIsRoutable();
            })
            .then((foundRoutableResult) => {
                this.isRoutable = foundRoutableResult.found;
                if (this.isRoutable && foundRoutableResult.lngLat && !!this.routeForm.routeType) {
                    this._updateCoordinates(foundRoutableResult.lngLat, false);
                }
                if (!this.waypoint.name) {
                    if (foundRoutableResult.name) this.updateName(foundRoutableResult.name);
                }
                if (this.debug) console.debug('foundRoutableResult:', foundRoutableResult);
                // update parent RouteForm and waypoint map layer
                this.routeForm.route.updateWaypointLayerSource(this.routeForm.waypoints);
                // scroll to the item if it was just added
                this.elements.listItem.scrollIntoView({ behavior: 'smooth', block: 'end' });
                queueMicrotask(() => {
                    // emit a custom event that notifies the information has now loaded
                    if (this.debug) console.debug("Waypoint info loaded, dispatching event", this);
                    this.dispatchEvent(new CustomEvent('waypointInfoLoaded', { detail: this.waypoint }));
                });
            })
            .catch((error) => {
                if (this.debug) console.error('Error getting waypoint info:', error);
            });
    }

    /**
     * Updates the waypoint's latitude and longitude with the provided `mapboxgl.LngLat` values,
     * updates the corresponding input and display elements with the new coordinates,
     * and optionally updates the waypoint layer source on the map.
     *
     * @param lngLat - An object containing the new longitude and latitude values.
     * @param updateMap - Whether to update the parent RouteForm and waypoint map layer (default: true).
     */
    private _updateCoordinates = (lngLat: mapboxgl.LngLat, updateMap: boolean = true): void => {
        this.waypoint.longitude = lngLat.lng;
        this.waypoint.latitude = lngLat.lat;
        const coordinatesValue: string = `${this.waypoint.latitude}, ${this.waypoint.longitude}`;
        const coordinatesDisplay: string = `${this.waypoint.latitude.toFixed(5)}, ${this.waypoint.longitude.toFixed(5)}`;
        this.elements.coordinates.input.value = coordinatesValue;
        this.elements.coordinates.display.textContent = coordinatesDisplay;
        if (updateMap) {
            // update parent RouteForm and waypoint map layer
            this.routeForm.route.updateWaypointLayerSource(this.routeForm.waypoints);
        }
    }

    /**
     * Moves the current list item to the position after its next sibling in the DOM.
     * If there is a next sibling, this method swaps the current item with it,
     * effectively moving the item one position down in the list.
     *
     * @private
     * @returns {void}
     */
    private _swapWithNext = (): void => {
        const nextItem = this.elements.listItem.nextElementSibling;
        if (nextItem) {
            this.elements.listItem.parentNode!.insertBefore(this.elements.listItem, nextItem.nextElementSibling);
        }
    };

    /**
     * Moves the current list item element one position up in its parent list,
     * swapping it with its previous sibling if one exists.
     *
     * @private
     * @returns {void}
     */
    private _swapWithPrevious = (): void => {
        const previousItem = this.elements.listItem.previousElementSibling;
        if (previousItem) {
            this.elements.listItem.parentNode!.insertBefore(this.elements.listItem, previousItem);
        }
    };

    /**
     * Deletes this waypoint item from the parent `RouteForm`.
     *
     * This method performs the following actions:
     * 1. Removes this waypoint item from the parent `RouteForm`'s list.
     * 2. Updates the `waypointItems` array to exclude this item.
     * 3. Sets the `RouteForm` state to `Loaded` if waypoints remain, or `NoRoute` if none remain.
     * 4. Queues an update to the waypoint map layer source.
     * 5. Destroys this waypoint item instance.
     *
     * @private
     */
    private _delete = (): void => {
        // update parent RouteForm and waypoint map layer before destroying self
        this.routeForm.deleteWaypointItem(this);
        this.routeForm.waypointItems = this.routeForm.waypointItems.filter((item) => item !== this);
        this.routeForm.state = this.routeForm.waypointItems.length ? RouteFormState.Loaded : RouteFormState.NoRoute;
        queueMicrotask(() => this.routeForm.route.updateWaypointLayerSource(this.routeForm.waypoints));
        this.destroy();
    }

    /**
     * Automatically adjusts the height of the name textarea element to fit its content.
     * Resets the height to 'auto' before setting it to the scroll height, ensuring the textarea grows or shrinks as needed.
     *
     * @private
     */
    private _autoGrowTextarea = (): void => {
        this.elements.name.style.height = 'auto'; // Reset height
        this.elements.name.style.height = `${this.elements.name.scrollHeight}px`; // Set to scroll height
    };

    /**
     * Builds and returns a set of DOM elements representing a waypoint form item.
     *
     * This method creates a structured list item (`<li>`) with controls for displaying and editing
     * waypoint information such as coordinates, name, and routability. It also generates buttons for
     * moving, deleting, and gripping the waypoint, and sets up appropriate ARIA attributes for accessibility.
     *
     * @returns {FormWaypointElements} An object containing references to the created DOM elements,
     * including buttons, coordinate controls, name input, routable warning, and the list item container.
     *
     * @private
     */
    private _buildListItem = (): FormWaypointElements => {
        const elements = {} as FormWaypointElements;
        elements.buttons = {} as Record<FormWaypointButton, HTMLElement>;
        elements.coordinates = {
            container: undefined as unknown as HTMLDivElement,
            input: undefined as unknown as HTMLInputElement,
            display: undefined as unknown as HTMLSpanElement
        };
        const uniqueId: string = getRandomString();

        const coordinatesValue: string = `${this.waypoint.latitude}, ${this.waypoint.longitude}`;
        const coordinatesDisplay: string = `${this.waypoint.latitude.toFixed(5)}, ${this.waypoint.longitude.toFixed(5)}`;
        const isRoutableValue: string = `${(this.waypoint.isRoutable !== false)}`;

        const gridButton = (key: FormWaypointButton): HTMLElement => {
            const iconSettings: { svgId: string; label: string; containerClassList: string[]; } = this.settings.icons[key];
            const button = document.createElement('div');
            button.classList.add(...iconSettings.containerClassList);
            if (key === FormWaypointButton.grip)
                button.classList.add(UI.MOVE_HANDLE_CLASS);
            button.title = iconSettings.label;
            button.setAttribute('aria-label', iconSettings.label);
            button.role = "button";
            button.dataset.action = key;
            button.append(svgFromId(iconSettings.svgId, [UI.STANDARD_ICON_CLASS]));
            return button;
        };

        elements.listItem = document.createElement("li");
        elements.listItem.id = uniqueId;
        elements.listItem.role = "group";
        elements.listItem.dataset.type = "waypoint-form-item";
        elements.listItem.classList.add(...this.settings.containerClassList);
        elements.listItem.setAttribute('aria-labelledby', `${uniqueId}-name`);
        elements.listItem.setAttribute("aria-grabbed", "false");

        const gridContainer = document.createElement('div');
        gridContainer.classList.add(...this.settings.gridClassList);

        const leftColumn = document.createElement('div');
        leftColumn.classList.add(...this.settings.columnClassList.left);
        elements.buttons.moveUp = gridButton(FormWaypointButton.moveUp);
        elements.buttons.moveDown = gridButton(FormWaypointButton.moveDown);
        leftColumn.append(elements.buttons.moveUp, elements.buttons.moveDown);

        const centerColumn = document.createElement('div');
        centerColumn.classList.add(...this.settings.columnClassList.center);

        const coordsGroup = document.createElement('div');
        coordsGroup.classList.add(...this.settings.controlGroup.classList);
        const coordinatesLabel = document.createElement('span');
        coordinatesLabel.classList.add(...this.settings.controlGroup.gps.labelClassList);
        coordinatesLabel.textContent = this.settings.controlGroup.gps.labelText;
        elements.coordinates.container = document.createElement('div');
        elements.coordinates.container.classList.add(...this.settings.controlGroup.gps.controlClassList);
        elements.coordinates.display = document.createElement('span');
        elements.coordinates.display.textContent = coordinatesDisplay;
        elements.coordinates.container.append(elements.coordinates.display, svgFromId(this.settings.controlGroup.gps.svgId));
        elements.coordinates.container.title = this.settings.controlGroup.gps.title;
        elements.coordinates.container.setAttribute('aria-label', this.settings.controlGroup.gps.ariaLabel);
        elements.coordinates.container.dataset.type = "gps";
        elements.coordinates.input = document.createElement('input');
        elements.coordinates.input.id = `${uniqueId}--coords`;
        elements.coordinates.input.dataset.field = "coordinates";
        elements.coordinates.input.hidden = true;
        elements.coordinates.input.value = coordinatesValue;
        coordsGroup.append(coordinatesLabel, elements.coordinates.container, elements.coordinates.input);

        const nameGroup = document.createElement('div');
        nameGroup.classList.add(...this.settings.controlGroup.classList);
        const name = document.createElement('span');
        name.classList.add(...this.settings.controlGroup.waypointName.labelClassList);
        name.textContent = this.settings.controlGroup.waypointName.labelText;
        name.id = `${uniqueId}-name-label`;
        elements.name = document.createElement('textarea');
        elements.name.classList.add(...this.settings.controlGroup.waypointName.controlClassList);
        elements.name.id = `${uniqueId}-name`;
        elements.name.value = this.waypoint.name || '';
        elements.name.setAttribute('aria-label', this.settings.controlGroup.waypointName.ariaLabel);
        elements.name.setAttribute('aria-describedby', `${uniqueId}-name-label`);
        elements.name.dataset.field = "name-label";
        elements.name.rows = 1;
        nameGroup.append(name, elements.name);

        const routableInput = document.createElement('input');
        routableInput.id = `${uniqueId}--routable`;
        routableInput.dataset.field = "isRoutable";
        routableInput.hidden = true;
        routableInput.value = isRoutableValue;

        centerColumn.append(coordsGroup, nameGroup, routableInput);

        const rightColumn = document.createElement('div');
        rightColumn.classList.add(...this.settings.columnClassList.right);
        elements.buttons.grip = gridButton(FormWaypointButton.grip);
        elements.buttons.bin = gridButton(FormWaypointButton.delete);
        rightColumn.append(elements.buttons.grip, elements.buttons.bin);

        elements.routableWarning = document.createElement('div');

        gridContainer.append(leftColumn, centerColumn, rightColumn);
        elements.listItem.append(gridContainer, elements.routableWarning);
        return elements;
    }


    /**
     * Attempts to find and return the name of a given waypoint by querying the feature layers at the waypoint's coordinates.
     * If the waypoint already has a name, it returns that immediately.
     *
     * @param waypoint - The waypoint object containing latitude and longitude to search for a feature name.
     * @returns A promise that resolves to a `FoundFeatureResult` containing the found name and coordinates, or an object with `name` as `undefined` if not found.
     *
     * @remarks
     * If an error occurs during the lookup, the error is logged (if debugging is enabled), and a default result with `name` as `undefined` is returned.
     */
    private _findWaypointName = async (waypoint: Waypoint): Promise<FoundFeatureResult> => {
        if (waypoint.name)
            return { name: waypoint.name, lngLat: new mapboxgl.LngLat(waypoint.longitude, waypoint.latitude) };
        try {
            const map = this.routeForm.route.map;
            let namedWaypoint: Waypoint = { ...waypoint };
            const result = await this.routeForm.route.featureLayerManager.findFeatureNameAtCoord([namedWaypoint.longitude, namedWaypoint.latitude]);
            return result;
        } catch (error) {
            if (this.debug) console.error('Error finding waypoint name:', error);
            return { name: undefined, lngLat: new mapboxgl.LngLat(waypoint.longitude, waypoint.latitude) };
        }
    }

    /**
     * Checks if the current waypoint is routable.
     *
     * This method should be called after the waypoint's name is updated, as the coordinates
     * may have been snapped to a feature. If the routability status of the waypoint is unknown
     * (i.e., `isRoutable` is `undefined`), it performs an asynchronous check using the
     * `Routable.isRoutable` method with the current waypoint's coordinates, map, access token,
     * route type, and maximum gap settings. If the routability status is already known,
     * it returns the result based on the existing `isRoutable` property.
     *
     * @returns A promise that resolves to a `FoundRouteResult` indicating whether the waypoint is routable.
     */
    private _checkIsRoutable = async (): Promise<FoundRouteResult> => {
        // call after waypoint name is updated in case coords are snapped to feature
        if (this.waypoint.isRoutable === undefined) {
            // status unknown when added from map, check is routable
            const result = await Routable.isRoutable({
                lngLat: new mapboxgl.LngLat(this.waypoint.longitude, this.waypoint.latitude),
                map: this.routeForm.route.map,
                accessToken: this.routeForm.route.mapOptions.accessToken,
                routeType: this.routeForm.routeType,
                maxGap: this.routeForm.route.settings.maxGap,
                debug: this.debug
            });
            return result;
        } else {
            return { found: !!this.waypoint.isRoutable };
        }
    }

    /**
     * Handles button click actions for a waypoint form item.
     *
     * Executes the corresponding action based on the provided `FormWaypointButton`:
     * - `moveUp`: Swaps the current waypoint with the previous one.
     * - `moveDown`: Swaps the current waypoint with the next one.
     * - `delete`: Deletes the current waypoint.
     * - `grip` or any other value: No action is taken (handled externally).
     *
     * @param action - The button action to handle.
     */
    private _buttonClickHandler = (action: FormWaypointButton) => {
        switch (action) {
            case FormWaypointButton.moveUp:
                this._swapWithPrevious();
                break;
            case FormWaypointButton.moveDown:
                this._swapWithNext();
                break;
            case FormWaypointButton.delete:
                this._delete();
                break;
            default: // do nothing for 'grip', handled on outer form
                break;
        }
    }

    /**
     * Handles the click event for waypoint coordinates.
     * 
     * When invoked, this method pans the map to the current waypoint's longitude and latitude
     * using the map's `flyTo` method.
     *
     * @private
     */
    private _coordsClickHandler = (): void => {
        this.routeForm.route.map.flyTo({ center: [this.waypoint.longitude, this.waypoint.latitude] });
    }

    /**
     * Handles changes to the waypoint name input field.
     * 
     * Updates the `waypoint.name` property with the current value from the input element,
     * refreshes the waypoint layer source on the map, and automatically resizes the textarea
     * to fit its content.
     *
     * @private
     */
    private _nameChangeHandler = (): void => {
        this.waypoint.name = this.elements.name.value;
        this.routeForm.route.updateWaypointLayerSource(this.routeForm.waypoints);
        this._autoGrowTextarea();
    }

    /**
     * Handles the keydown event for the name input field.
     * 
     * If the Enter key is pressed, prevents the default behavior (such as adding a newline)
     * and blurs the input field to dismiss the keyboard, especially useful on mobile devices.
     *
     * @param e - The keyboard event triggered by user interaction.
     */
    private _nameKeyDownHandler = (e: KeyboardEvent): void => {
        if (e.key === 'Enter') {
            e.preventDefault(); // Prevent Enter from adding a newline
            this.elements.name.blur(); // Trigger the Done button to dismiss the keyboard on mobile
        }
    };

    /**
     * Handles the focus event for the name input element by selecting its text.
     * This allows users to easily replace or edit the current value when the input gains focus.
     *
     * @private
     */
    private _nameFocusHandler = (): void => {
        this.elements.name.select();
    };

    /**
     * Handles the form expansion event. If the event's detail property is `true`,
     * triggers the auto-grow functionality for the textarea.
     *
     * @param event - The event object, expected to be a `CustomEvent` with a boolean `detail` indicating expansion state.
     */
    private _formExpandedHandler = (event: Event): void => {
        if ((event as CustomEvent).detail as boolean)
            this._autoGrowTextarea();
    }

    /**
     * Attaches all necessary event listeners to the form elements and buttons
     * within the waypoint form. This includes handling form expansion, textarea
     * auto-growing, name input changes, keyboard interactions, focus events,
     * coordinate container clicks, and button clicks.
     *
     * @private
     */
    private _addEventListeners = (): void => {
        this.routeForm.addEventListener('expandEvent', this._formExpandedHandler);
        this.elements.name.addEventListener('input', this._autoGrowTextarea);
        this.elements.name.addEventListener('change', this._nameChangeHandler);
        this.elements.name.addEventListener('keydown', this._nameKeyDownHandler);
        this.elements.name.addEventListener('focus', this._nameFocusHandler);
        this.elements.coordinates.container.addEventListener('click', this._coordsClickHandler);
        for (const key of Object.keys(this.elements.buttons) as FormWaypointButton[]) {
            this.elements.buttons[key].addEventListener('click', () => this._buttonClickHandler(key));
        }
    }

    /**
     * Removes all event listeners previously attached to the form and its elements.
     *
     * This includes:
     * - The 'expandEvent' listener on the route form.
     * - 'input', 'change', 'keydown', and 'focus' listeners on the name input element.
     * - 'click' listener on the coordinates container.
     * - 'click' listeners on all button elements within the form.
     *
     * This method is typically called during cleanup to prevent memory leaks and unintended behavior.
     */
    private _removeEventListeners = (): void => {
        this.routeForm.removeEventListener('expandEvent', this._formExpandedHandler);
        this.elements.name.removeEventListener('input', this._autoGrowTextarea);
        this.elements.name.removeEventListener('change', this._nameChangeHandler);
        this.elements.name.removeEventListener('keydown', this._nameKeyDownHandler);
        this.elements.name.removeEventListener('focus', this._nameFocusHandler);
        this.elements.coordinates.container.removeEventListener('click', this._coordsClickHandler);
        for (const key of Object.keys(this.elements.buttons) as FormWaypointButton[]) {
            this.elements.buttons[key].removeEventListener('click', () => this._buttonClickHandler(key));
        }
    }

    /**
     * Creates and returns an HTML element representing a routable warning message.
     * 
     * The returned `<div>` element includes:
     * - Classes from the routable warning icon's container class list.
     * - An SVG icon (retrieved by ID) and a label.
     * - Accessibility attributes: `role="alert"` and `aria-live="assertive"` for screen readers.
     * 
     * @returns {HTMLElement} The constructed warning message element.
     * @private
     */
    private get _routableWarning(): HTMLElement {
        const div = document.createElement('div');
        const icon = this.settings.icons.routableWarning;
        div.classList.add(...icon.containerClassList);
        div.append(svgFromId(icon.svgId), icon.label);
        div.setAttribute('role', 'alert');
        div.setAttribute('aria-live', 'assertive');
        return div;
    };
}
