import mapboxgl from 'mapbox-gl';
import { compressToEncodedURIComponent, decompressFromEncodedURIComponent } from 'lz-string';
import type { RouteParameters, RouteType, WayPoints } from '../types.js';

interface EncodedWaypoint extends Array<number | string | boolean | undefined> {
    0: number;  // longitude x 1e6
    1: number;  // latitude x 1e6
    2: string;  // name
    3?: boolean; // showPin
    4?: boolean; // isRoutable (false only)
}

type EncodedPayload = {
    w: EncodedWaypoint[];
    t?: RouteType;
    s?: "simple" | "detailed";
    e?: boolean;
};

/**
 * A utility class for managing route parameters in the URL.
 * 
 * This class provides methods to encode, decode, set, retrieve, and clear route parameters
 * in the browser's URL. It ensures that route parameters are compressed and stored efficiently
 * in the URL, while also allowing for easy retrieval and decoding of these parameters.
 * 
 * Key Features:
 * - Encodes route parameters into a compressed string for compact storage in the URL.
 * - Decodes compressed route parameters from the URL back into a usable format.
 * - Updates the browser's history state when setting or clearing route parameters.
 * - Provides default values for route parameters to ensure consistency.
 * 
 * Use this class to manage route-related state in a web application, enabling features such as
 * sharing URLs with route information or persisting route state across page reloads.
 */
export class RouteUrl {
    /**
     * Default configuration options for route display and behavior.
     *
     * @property routeType - The type of route to use (e.g., "walking").
     * @property showSummary - Level of summary detail to display ("simple" or "detailed").
     * @property showElevationProfile - Whether to display the elevation profile.
     * @property showPin - Whether to display a pin on the map.
     * @property isRoutable - Indicates if the route is routable.
     */
    private static readonly DEFAULTS = {
        routeType: undefined as RouteType,
        showSummary: "detailed" as "simple" | "detailed",
        showElevationProfile: true,
        showPin: true,
        isRoutable: true,
    } as const;

    /**
     * Updates the current browser URL with encoded route parameters.
     *
     * This method encodes the provided route parameters and updates the URL's
     * query string with the encoded data under the "r" parameter. It uses
     * the `replaceState` method to modify the browser's history without reloading
     * the page. If an error occurs during the process, it logs the error to the console.
     *
     * @param parameters - The route parameters to encode and set in the URL.
     * @param debug - Optional flag to enable debug mode for encoding. Defaults to `false`.
     * 
     * @throws Will log an error to the console if encoding or URL manipulation fails.
     */
    public static setURL = (parameters: RouteParameters, debug: boolean = false): void => {
        try {
            const encoded = this._encodeRouteParameters(parameters, debug);
            const url = new URL(window.location.href);
            url.searchParams.set("r", encoded);
            window.history.replaceState({}, "", url.toString());
        } catch (error) {
            console.error("Failed to set URL parameters:", error);
        }
    }

    /**
     * Retrieves and decodes route parameters from the current URL.
     *
     * @param debug - Optional flag to enable debug mode. Defaults to `false`.
     * @returns The decoded route parameters as a `RouteParameters` object, or `null` if the "r" parameter is not present
     *          in the URL or if decoding fails.
     * @throws Logs an error to the console if decoding the route parameters fails.
     */
    public static getURL = (debug: boolean = false): RouteParameters | null => {
        const url = new URL(window.location.href);
        const encoded = url.searchParams.get("r");
        if (!encoded) return null;
        try {
            return this._decodeRouteParameters(encoded, debug);
        } catch (error) {
            console.error("Failed to decode route parameters:", error);
            return null;
        }
    }

    /**
     * Clears the "r" query parameter from the current URL without reloading the page.
     * This method modifies the browser's history state to reflect the updated URL.
     *
     * @remarks
     * This function uses the `URL` and `window.history.replaceState` APIs to manipulate
     * the URL in a non-destructive way, ensuring the page does not reload.
     */
    public static clearURL = (): void => {
        const url = new URL(window.location.href);
        url.searchParams.delete("r");
        window.history.replaceState({}, "", url.toString());
    };

    /**
     * Encodes route parameters into a compressed and encoded URI component string.
     *
     * @param params - The route parameters to encode, including waypoints, route type, and display options.
     * @param debug - Optional flag to enable debug logging. Defaults to `false`.
     * @returns A compressed and encoded URI component string representing the route parameters.
     * 
     * @remarks
     * 
     * - This function takes a `RouteParameters` object, which includes an array of waypoints.
     * - If no wapoints are provided, function returns an empty string.
     *
     * The function processes the waypoints by converting their longitude and latitude
     * to integers (scaled by 1e6) and optionally includes additional properties like
     * pin labels and visibility. It also encodes other route settings such as route type,
     * summary visibility, and elevation profile visibility if they differ from the defaults.
     *
     * If `debug` is set to `true`, the function logs the encoded payload and input parameters
     * to the console for debugging purposes.
     */
    private static _encodeRouteParameters = (params: RouteParameters, debug: boolean = false): string => {
        if (!params.waypoints) return "";
        const packedWaypoints: EncodedWaypoint[] = params.waypoints.map(wp => {
            const packed: EncodedWaypoint = [
                Math.round(wp.longitude * 1e6),
                Math.round(wp.latitude * 1e6),
                wp.name ?? "",
            ];
            if (wp.showPin !== this.DEFAULTS.showPin) {
                packed.push(wp.showPin);
            }
            if (wp.isRoutable === false) {
                // Fill slot 3 with showPin if not already added, otherwise insert isRoutable
                if (packed.length === 3) packed.push(this.DEFAULTS.showPin); // ensure slot 3
                packed[4] = false;
            }
            return packed;
        });

        const payload: EncodedPayload = { w: packedWaypoints };

        if (params.routeType !== this.DEFAULTS.routeType) {
            payload.t = params.routeType;
        }
        if (params.showSummary && params.showSummary !== this.DEFAULTS.showSummary) {
            payload.s = params.showSummary;
        }
        if (params.showElevationProfile !== undefined && params.showElevationProfile !== this.DEFAULTS.showElevationProfile) {
            payload.e = params.showElevationProfile;
        }
        if (debug) console.debug("RouteUrl: Encoded payload:", payload, params);
        return compressToEncodedURIComponent(JSON.stringify(payload));
    }

    /**
     * Decodes a compressed and encoded route parameters string into a `RouteParameters` object.
     *
     * @param encoded - The compressed and encoded string representing route parameters.
     * @param debug - Optional flag to enable debug logging. Defaults to `false`.
     * @returns The decoded `RouteParameters` object containing waypoints and route settings.
     * @throws {Error} If decompression fails or the payload structure is invalid.
     */
    private static _decodeRouteParameters = (encoded: string, debug: boolean = false): RouteParameters => {
        const json = decompressFromEncodedURIComponent(encoded);
        if (!json) throw new Error("Failed to decompress route parameters");

        const payload = JSON.parse(json) as EncodedPayload;
        if (!payload || !Array.isArray(payload.w)) {
            throw new Error("Invalid payload structure");
        }

        const waypoints: WayPoints = payload.w.map(wpArr => {
            const [lngPacked, latPacked, nameRaw, showPinRaw, isRoutableRaw] = wpArr;
            return {
                longitude: lngPacked / 1e6,
                latitude: latPacked / 1e6,
                name: nameRaw ? this._sanitizeLabel(nameRaw) : undefined,
                showPin: showPinRaw !== undefined ? showPinRaw : this.DEFAULTS.showPin,
                isRoutable: isRoutableRaw === false ? false : true,
            };
        });

        const value = {
            waypoints,
            routeType: payload.t ?? this.DEFAULTS.routeType,
            showSummary: payload.s ?? this.DEFAULTS.showSummary,
            showElevationProfile: payload.e !== undefined ? payload.e : this.DEFAULTS.showElevationProfile,
        };
        if (debug) console.debug("RouteUrl: Decoded parameters:", value);
        return value;
    }

    /**
     * Sanitizes a given label string by removing any potentially unsafe HTML content.
     * This is achieved by parsing the string as HTML and extracting only the text content.
     *
     * @param label - The input string that may contain HTML content.
     * @returns A sanitized string with all HTML tags removed, leaving only plain text.
     */
    private static _sanitizeLabel = (label: string): string => (
        new DOMParser().parseFromString(label, "text/html").body.textContent || ""
    );
}

/**
 * Utility class for encoding and decoding Mapbox camera parameters into the URL.
 *
 * The `CameraUrl` class provides static methods to serialize and deserialize map camera state
 * (bearing, pitch, zoom, and center) into a compact, URL-safe base64 string. This allows
 * sharing or persisting the map's current view via the browser URL.
 *
 * @remarks
 * - Uses base64url encoding for compactness and URL safety.
 * - Only non-default camera parameters are encoded to minimize URL length.
 * - The encoded camera state is stored in the `c` query parameter.
 *
 * @example
 * ```typescript
 * // To update the URL with the current camera state:
 * CameraUrl.setURL(mapInstance);
 *
 * // To retrieve camera options from the URL:
 * const options = CameraUrl.getURL();
 * if (options) {
 *   mapInstance.setOptions(options);
 * }
 * ```
 */
export class CameraUrl {
    /**
     * Default map view parameters.
     *
     * @remarks
     * These constants define the initial state for the map's bearing, pitch, and zoom level.
     *
     * @property {number} bearing - The default compass bearing (rotation) of the map in degrees.
     * @property {number} pitch - The default pitch (tilt) of the map in degrees.
     * @property {number} zoom - The default zoom level of the map.
     *
     * @readonly
     */
    private static readonly DEFAULTS = {
        bearing: 0,
        pitch: 5,
        zoom: 12
    } as const;

    /**
     * Converts a given string to a Base64URL-encoded string.
     *
     * This method encodes the input string using Base64 encoding,
     * then modifies the result to be URL-safe by replacing '+' with '-',
     * '/' with '_', and removing any trailing '=' padding characters.
     *
     * @param raw - The input string to encode.
     * @returns The Base64URL-encoded representation of the input string.
     */
    private static _toBase64Url(raw: string): string {
        return btoa(raw)
            .replace(/\+/g, "-")
            .replace(/\//g, "_")
            .replace(/=+$/, "");
    }

    /**
     * Decodes a base64url-encoded string into its original string representation.
     *
     * This method replaces URL-safe base64 characters (`-` and `_`) with standard base64 characters (`+` and `/`),
     * adds necessary padding, and decodes the result using `atob`.
     *
     * @param encoded - The base64url-encoded string to decode.
     * @returns The decoded string.
     */
    private static _fromBase64Url(encoded: string): string {
        const base64 = encoded.replace(/-/g, "+").replace(/_/g, "/");
        const padded = base64 + "=".repeat((4 - base64.length % 4) % 4);
        return atob(padded);
    }

    /**
     * Updates the current browser URL to reflect the camera state of the given Mapbox map instance.
     * 
     * Encodes the map's bearing, pitch, zoom, and center coordinates into a compact base64url string,
     * and sets it as the "c" query parameter in the URL. If the map's camera matches the default values,
     * the "c" parameter is removed. Optionally logs the encoded payload if debug mode is enabled.
     * 
     * @param map - The mapboxgl.Map instance whose camera state will be encoded into the URL.
     * @param debug - Optional. If true, logs the encoded camera payload to the console. Defaults to false.
     * 
     * @remarks
     * - The method uses `window.history.replaceState` to update the URL without reloading the page.
     * - If the "r" query parameter is present, zoom and center are not included in the payload.
     * - The payload is encoded using a private `_toBase64Url` method.
     * - Errors during URL manipulation are caught and logged to the console.
     */
    public static setURL(map: mapboxgl.Map, debug: boolean = false): void {
        try {
            const url = new URL(window.location.href);
            const bearing = Math.round(map.getBearing());
            const pitch = Math.round(map.getPitch());

            let payload = "";

            if (bearing !== this.DEFAULTS.bearing) payload += `b${bearing}`;
            if (pitch !== this.DEFAULTS.pitch) payload += `p${pitch}`;

            if (!url.searchParams.get("r")) {
                const zoom = +(map.getZoom().toFixed(1));
                if (zoom !== this.DEFAULTS.zoom) payload += `z${zoom}`;
                const [lng, lat] = map.getCenter().toArray().map(c => +c.toFixed(4));
                payload += `c${lng}:${lat}`;
            }

            if (payload) {
                const encoded = this._toBase64Url(payload);
                url.searchParams.set("c", encoded);
            } else {
                url.searchParams.delete("c");
            }

            if (debug) console.debug("CameraUrl: Encoded:", payload);
            window.history.replaceState({}, "", url.toString());
        } catch (error) {
            console.error("Failed to set URL parameters:", error);
        }
    }

    /**
     * Parses camera parameters from the current URL's query string and returns them as a partial `mapboxgl.MapOptions` object.
     *
     * The method expects a base64url-encoded string under the "c" query parameter, which encodes camera options such as bearing, pitch, zoom, and center.
     * Decoded parameters are extracted using regular expressions and mapped to the corresponding `mapboxgl.MapOptions` properties:
     * - `b<number>`: Bearing (integer)
     * - `p<number>`: Pitch (integer)
     * - `z<number>`: Zoom (float)
     * - `c<lng>:<lat>`: Center coordinates (longitude, latitude as floats)
     *
     * @param debug - If `true`, logs the decoded string and resulting map options to the console for debugging purposes.
     * @returns A partial `mapboxgl.MapOptions` object with the parsed camera parameters, or `null` if parsing fails or the "c" parameter is missing.
     */
    public static getURL(debug: boolean = false): Partial<mapboxgl.MapOptions> | null {
        try {
            const url = new URL(window.location.href);
            const encoded = url.searchParams.get("c");
            if (!encoded) return null;

            const decoded = this._fromBase64Url(encoded);
            const mapOptions: Partial<mapboxgl.MapOptions> = {};

            const b = decoded.match(/b(-?\d+)/);
            const p = decoded.match(/p(-?\d+)/);
            const z = decoded.match(/z([0-9.]+)/);
            const c = decoded.match(/c(-?\d+(?:\.\d+)?):(-?\d+(?:\.\d+)?)/);

            if (b) mapOptions.bearing = parseInt(b[1]);
            if (p) mapOptions.pitch = parseInt(p[1]);
            if (z) mapOptions.zoom = parseFloat(z[1]);
            if (c) mapOptions.center = [parseFloat(c[1]), parseFloat(c[2])];

            if (debug) {
                console.debug("CameraUrl: Decoded:", decoded, mapOptions);
            }

            return mapOptions;
        } catch (error) {
            console.error("Failed to decode camera parameters:", error);
            return null;
        }
    }
}

/**
 * Utility class for managing the "s" search parameter in the browser's URL,
 * typically used to represent a style index for map or UI themes.
 *
 * @remarks
 * - The "s" parameter in the URL query string is used to store the current style index.
 * - If the style index is `0`, the "s" parameter is removed from the URL.
 * - If the style index is greater than `0`, the "s" parameter is set to the corresponding value.
 * - The class provides methods to set and retrieve the style index from the URL.
 *
 * @example
 * ```typescript
 * // Set the style index to 2 in the URL
 * StyleUrl.setURL(2);
 *
 * // Retrieve the current style index from the URL
 * const styleIndex = StyleUrl.getURL();
 * ```
 */
export class StyleUrl {
    /**
     * Updates the current browser URL's search parameter "s" to reflect the given style index.
     * 
     * - If `styleIndex` is 0, the "s" parameter is removed from the URL.
     * - If `styleIndex` is not 0, the "s" parameter is set to the string value of `styleIndex`.
     * - Optionally logs debug information if `debug` is true.
     * - Uses `window.history.replaceState` to update the URL without reloading the page.
     * 
     * @param styleIndex - The index of the style to set in the URL. If 0, the "s" parameter is removed.
     * @param debug - Optional. If true, logs debug information to the console. Defaults to false.
     */
    public static setURL(styleIndex: number, debug: boolean = false): void {
        try {
            const url = new URL(window.location.href);
            if (styleIndex === 0) {
                url.searchParams.delete("s");
                if (debug) console.debug('StyleUrl: index 0, removing searchParam "s"');
            } else {
                url.searchParams.set("s", styleIndex.toString());
                if (debug) console.debug(`StyleUrl: setting searchParam "s=${styleIndex}"`);
            }
            window.history.replaceState({}, "", url.toString());
        } catch (e) {
            console.error("StyleUrl.setURL:", e);
        }
    }

    public static getURL(debug: boolean = false): number | null {
        try {
            const url = new URL(window.location.href);
            const styleIndex = url.searchParams.get("s");
            if (styleIndex) {
                if (debug) console.debug(`StyleUrl: retrieved style index "${styleIndex}" from URL`);
                // Ensure the style index is a valid integer, return null if not
                return parseInt(styleIndex) ?? null;
            }
            return null;
        } catch (error) {
            console.error("StyleUrl.getURL:", error);
            return null;
        }
    }
}

