import mapboxgl from 'mapbox-gl';
import Route from './Route.js';
import Sortable from 'sortablejs';
import Toast from '../widgets/Toast.js';
import { FormWaypoint } from './FormWaypoint.js';
import { MAPBOX, UI } from '../constants.js';
import type { RouteFormSettings, RouteType, Waypoint, WayPoints } from '../types.js';
import { svgFromId } from '../utility/utility.js';


/**
 * Represents the possible states of the route form.
 *
 * @enum {string}
 * @property {RouteFormState.Initial} Initial - The initial state before any route is loaded.
 * @property {RouteFormState.NoRoute} NoRoute - Indicates that no route is available or found.
 * @property {RouteFormState.Loading} Loading - Indicates that a waypoint has been added but not yet fully loaded.
 * @property {RouteFormState.Loaded} Loaded - Indicates that a route has been successfully loaded.
 */
export enum RouteFormState {
    Initial = 'initial',
    NoRoute = 'empty',
    Loading = 'loading',
    Loaded = 'loaded'
}

/**
 * Represents the collection of DOM elements used in the route form UI.
 *
 * @property container - The main container element for the route form.
 * @property form - The HTML form element for route input.
 * @property headerButton - The button element used in the form header.
 * @property waypointList - The unordered list element displaying waypoints.
 * @property routeTypeSelect - The select element for choosing the route type.
 * @property submitButton - The button element to submit the form.
 * @property clearButton - The button element to clear the form inputs.
 * @property formInstructions - The element displaying instructions for the form.
 */
type RouteFormElements = {
    container: HTMLElement;
    form: HTMLFormElement;
    headerButton: HTMLButtonElement;
    waypointList: HTMLUListElement;
    routeTypeSelect: HTMLSelectElement;
    submitButton: HTMLButtonElement;
    clearButton: HTMLButtonElement;
    formInstructions: HTMLElement;
}

/**
 * Represents the interactive route form UI for managing waypoints and route options in a Mapbox-based application.
 * 
 * The `RouteForm` class is responsible for rendering, updating, and managing the state of a route planning form,
 * including adding, removing, and reordering waypoints, handling user interactions (such as context menus and touch events),
 * and synchronizing form state with the underlying route data model.
 * 
 * Key features:
 * - Dynamically builds and manages the form UI for route planning.
 * - Supports adding waypoints via map context menu (right-click or long-press on touch devices).
 * - Allows reordering of waypoints via drag-and-drop.
 * - Handles form expansion/collapse and state transitions.
 * - Integrates with Mapbox map events and updates the map accordingly.
 * - Emits custom events for UI state changes (e.g., expand/collapse).
 * - Provides accessibility features such as ARIA attributes and keyboard navigation support.
 * 
 * @remarks
 * - The form is automatically initialized and attached to a specified Mapbox control container.
 * - The class manages its own event listeners and DOM elements, and provides a `destroy()` method for cleanup.
 * - Waypoint management is limited to a maximum of 25 waypoints due to Mapbox Directions API constraints.
 * 
 * @example
 * ```typescript
 * const routeForm = new RouteForm(routeInstance, true);
 * routeForm.addEventListener("expandEvent", (e) => {
 *   console.debug("Form expanded:", e.detail);
 * });
 * // To clean up:
 * routeForm.destroy();
 * ```
 * 
 * @public
 */
export default class RouteForm extends EventTarget {
    settings: RouteFormSettings
    waypointItems: FormWaypoint[] = [];
    private _formElements: RouteFormElements;
    private _sortableList?: Sortable;
    private _state: RouteFormState = RouteFormState.Initial;
    private _expanded?: boolean = undefined;
    // touch support for context menu
    private _touchTimeout: number | null = null;
    private _touchStartPoint: mapboxgl.Point | null = null;

    /**
     * Initializes a new instance of the class, setting up the form UI and event listeners for a given route.
     * 
     * @param route - The `Route` instance associated with this form.
     * @param debug - Optional flag to enable debug mode. Defaults to `false`.
     * 
     * @remarks
     * - Loads form state based on existing route parameters.
     * - Appends the form to the specified Mapbox control container.
     * - Logs an error if the control container selector is invalid.
     */
    constructor(public route: Route, private readonly debug: boolean = false) {
        super();
        this.settings = route.settings.form;
        this._formElements = this._buildForm();
        this.expanded = !!this.settings.initialStateExpanded;

        // preload route form if route parameters already configured
        if ((this.route.parameters.waypoints ?? []).length > 0) {
            queueMicrotask(() => this._loadForm());
        } else {
            this.state = RouteFormState.NoRoute;
        }
        // add to mapbox control container
        const controlContainer = this.route.mapContainer.querySelector(this.settings.mapboxControlContainer);
        if (!controlContainer) {
            console.error(`RouteForm: ${this.settings.mapboxControlContainer} is not a valid MapBox control selector, no such element found.`);
            return
        } else {
            controlContainer.appendChild(this._formElements.container);
            this._addEventListeners();
        }
    }

    /**
     * Cleans up the form by clearing the list, removing event listeners,
     * removing the form container from the DOM, and resetting form elements.
     * 
     * This method should be called when the form is no longer needed to
     * prevent memory leaks and ensure proper teardown of resources.
     */
    destroy(): void {
        this._clearList();
        this._removeEventListeners();
        this._formElements.container.remove();
        this._formElements = {} as RouteFormElements;
    }

    /**
     * Loads the form with the current route parameters.
     *
     * Iterates over the waypoints in the route parameters, creates a `FormWaypoint` instance
     * for each, adds it to the `waypointItems` array, and appends its list item element to the
     * waypoint list in the form. Sets the route type select element's value based on the route
     * parameters, and updates the form state to `Loaded`.
     *
     * @private
     */
    private _loadForm = (): void => {
        this.route.parameters.waypoints?.forEach((waypoint) => {
            const fwp = new FormWaypoint(this, waypoint);
            this.waypointItems.push(fwp);
            this._formElements.waypointList.appendChild(fwp.elements.listItem);
        })
        this._formElements.routeTypeSelect.value = this.route.parameters.routeType ?? "";
        this.state = RouteFormState.Loaded;
    }

    /**
     * Gets the current state of the route form.
     * 
     * @returns The current {@link RouteFormState} instance representing the form's state.
     */
    get state(): RouteFormState {
        return this._state;
    }

    /**
     * Sets the current route form state and synchronizes related UI and accessibility attributes.
     *
     * On an actual state change:
     * - Updates the internal state and the form element's `data-state`.
     * - Toggles visibility via `aria-hidden` on the form and instructions elements
     *   (the form is hidden for non-interactive states, e.g., Initial/NoRoute).
     * - Dispatches a `"stateChange"` `CustomEvent` with the new state in `detail`.
     *
     * Regardless of whether the state changes, this recalculates the enabled/disabled status
     * of action buttons based on waypoint count:
     * - Clear is disabled when there are no waypoints.
     * - Submit is disabled until at least two waypoints exist.
     *
     * @param value - The new route form state to apply.
     * @fires stateChange
     */
    set state(value: RouteFormState) {
        if (this.state !== value) {
            this._state = value;
            this._formElements.form.dataset.state = value;
            const hideForm = [(RouteFormState.Initial, RouteFormState.NoRoute)].includes(value);
            this._formElements.form.setAttribute('aria-hidden', String(hideForm));
            this._formElements.formInstructions.setAttribute('aria-hidden', String(!hideForm));
            this.dispatchEvent(new CustomEvent('stateChange', { detail: value }));
        }
        this._formElements.clearButton.disabled = (this.waypointItems.length < 1);
        this._formElements.submitButton.disabled = (this.waypointItems.length < 2);
    }

    /**
     * Dispatches a custom "expandEvent" event with the specified boolean value as its detail.
     *
     * @param value - The boolean value to include in the event's detail payload.
     */
    private _dispatchExpandEvent(value: boolean): void {
        this.dispatchEvent(new CustomEvent("expandEvent", { detail: value }));
    }

    /**
     * Indicates whether the form is currently expanded.
     *
     * @returns `true` if the form is expanded; otherwise, `false`.
     */
    get expanded(): boolean {
        return !!this._expanded;
    }

    /**
     * Sets the expanded state of the route form UI.
     *
     * - No-ops if the requested state matches the current internal state.
     * - Logs a debug message when debug mode is enabled.
     * - Updates the "aria-expanded" attribute on both the container and the header button for accessibility.
     * - Dispatches an expand-state change event to notify listeners.
     *
     * Implementation note: compares against the backing field to correctly handle the initial undefined state.
     *
     * @param value - True to expand the form; false to collapse it.
     */
    set expanded(value: boolean) {
        // use class variable, not getter - need to test if undefined on first load
        if (this._expanded === value) return;
        if (this.debug) console.debug(`RouteForm: expanded state set from ${this._expanded} to ${value}`);
        this._expanded = value;
        this._formElements.container.setAttribute('aria-expanded', value.toString());
        this._formElements.headerButton.setAttribute('aria-expanded', value.toString());
        this._dispatchExpandEvent(value);
    }

    get routeType(): RouteType {
        return this._formElements.routeTypeSelect.value as RouteType;
    }

    /**
     * Gets the list of waypoints from the current waypoint items.
     *
     * @returns {WayPoints} An array of waypoints extracted from each waypoint item.
     */
    get waypoints(): WayPoints {
        return this.waypointItems.map((item) => item.waypoint);
    }

    /**
     * Retrieves the corresponding `FormWaypoint` instance for a given list item element.
     *
     * @param listElement - The HTML element representing the list item to search for.
     * @returns The `FormWaypoint` associated with the provided list element, or `undefined` if not found.
     */
    private _getListItem(listElement: HTMLElement): FormWaypoint | undefined {
        return this.waypointItems.find((item) => item.elements.listItem === listElement);
    }

    /**
     * Adds a new waypoint to the route form and map, normalizing input and enforcing
     * Mapbox Directions API waypoint limits when applicable.
     *
     * Behavior:
     * - Expands the form UI.
     * - If adding the waypoint would exceed MAPBOX.MAX_DIRECTIONS_WAYPOINTS for API-backed
     *   route types, shows a toast warning, briefly applies a highlight CSS class,
     *   logs a console warning, and returns without adding the waypoint.
     * - Normalizes the input:
     *   - mapboxgl.LngLat is converted to a Waypoint.
     *   - Waypoint is shallow-copied.
     *   In both cases, showPin is forced to true.
     * - Sets the form state to RouteFormState.Loading, creates a FormWaypoint, and subscribes
     *   once to its "waypointInfoLoaded" event.
     * - Appends the new item to the internal collection and DOM list, schedules a waypoint
     *   layer source update on the next microtask, and scrolls the item into view (optionally
     *   after a small delay if the form is expanding).
     *
     * Side effects:
     * - Mutates internal state (expanded, state, waypointItems).
     * - Updates the DOM and map layers.
     * - May display a toast message and temporary CSS highlighting for limit warnings.
     *
     * @param waypoint A Waypoint or mapboxgl.LngLat to add. LngLat is converted to a Waypoint; showPin is always set to true.
     * @returns void
     * @fires FormWaypoint#waypointInfoLoaded
     * @remarks The waypoint-count limit is enforced only for route types that invoke the
     * Mapbox Directions API; it is skipped for non-API route types (e.g., point-to-point).
     * @see MAPBOX.MAX_DIRECTIONS_WAYPOINTS
     * @see RouteFormState.Loading
     * @see UI.EXPAND_SCROLL_DELAY
     */
    private _addWaypoint(waypoint: Waypoint | mapboxgl.LngLat): void {
        this.expanded = true;
        if (this.waypointItems.length >= MAPBOX.MAX_DIRECTIONS_WAYPOINTS && !!this._formElements.routeTypeSelect.value) {
            // 25 limit does not apply to point-to-point route type (no api call)
            if (this.settings.waypointCountWarning.duration) {
                Toast.show(this.route.mapContainer, this.settings.waypointCountWarning.message, this.settings.waypointCountWarning.duration);
                this._formElements.container.classList.add(this.settings.waypointCountWarning.className);
                setTimeout(() => {
                    this._formElements.container.classList.remove(this.settings.waypointCountWarning.className);
                }, this.settings.waypointCountWarning.duration);
            }
            console.warn(`Route: More than ${MAPBOX.MAX_DIRECTIONS_WAYPOINTS} waypoints is not supported by Mapbox Directions API.`);
            return;
        }
        let newWaypoint: Waypoint;
        if (waypoint instanceof mapboxgl.LngLat) {
            newWaypoint = {
                latitude: waypoint.lat,
                longitude: waypoint.lng,
                name: undefined,
                showPin: true,
            };
        } else {
            newWaypoint = { ...waypoint, showPin: true };
        }

        this.state = RouteFormState.Loading; // form has at least 1 item, not yet fully loaded
        const fwp = new FormWaypoint(this, newWaypoint, this.debug);
        fwp.addEventListener('waypointInfoLoaded', this._waypointInfoLoadedHandler, { once: true });
        if (this.debug) console.debug('RouteForm:_addWaypoint: waypointInfoLoaded listener added', fwp);
        this.waypointItems.push(fwp);
        this._formElements.waypointList.appendChild(fwp.elements.listItem);
        queueMicrotask(() => this.route.updateWaypointLayerSource(this.waypoints));

        const timeDelay: number = this.expanded ? 0 : UI.EXPAND_SCROLL_DELAY;
        setTimeout(() => {
            fwp.elements.listItem.scrollIntoView({ behavior: 'smooth', block: 'end' });
        }, timeDelay);
    }

    /**
     * Handles the "waypoint info loaded" event.
     *
     * Transitions the route form state to `Loaded`, extracts the payload from
     * `CustomEvent.detail`, and logs diagnostic information for debugging.
     *
     * @param event - The dispatched event; expected to be a `CustomEvent` whose `detail`
     * carries waypoint-related data.
     * @private
     */
    private _waypointInfoLoadedHandler: EventListener = (event: Event): void => {
        this.state = RouteFormState.Loaded;
        const detail = (event as CustomEvent).detail;
        if (this.debug) console.debug('RouteForm:_waypointInfoLoadedHandler', detail);
    };

    /**
     * Removes the specified waypoint item from the list of waypoints.
     * Updates the internal state based on whether any waypoints remain.
     * Schedules an update to the waypoint layer source after the removal.
     *
     * @param listItem - The waypoint item to be removed from the list.
     */
    public deleteWaypointItem = (listItem: FormWaypoint) => {
        this.waypointItems = this.waypointItems.filter((item) => item !== listItem);
        this.state = this.waypointItems.length ? RouteFormState.Loaded : RouteFormState.NoRoute;
        queueMicrotask(() => this.route.updateWaypointLayerSource(this.waypoints));
    }

    /**
     * Handles the "show route" action from the form submission workflow.
     *
     * - Prevents the default event behavior and defers execution until the form reaches the Loaded state.
     * - Synchronizes the internal waypointItems order with the current DOM list order.
     * - Builds the waypoints collection from the form, removing auto-generated default pin labels.
     * - Updates route parameters (waypoints, routeType, optional summary) and renders the route on the map.
     * - Collapses the form UI after adding the route to the map.
     * - Registers a one-time listener to reflect any waypoint name updates (emitted via "waypointsUpdated") back into the form UI.
     *
     * Side effects:
     * - Mutates waypoint ordering and waypoint names.
     * - Mutates route parameters and triggers map rendering.
     * - Updates UI state (button blur, panel collapse, list item labels).
     *
     * @param event - The originating UI event (e.g., submit or click) to be handled.
     * @returns void
     * @remarks
     * - If the form is not yet ready (state !== Loaded), a one-time "stateChange" listener is attached and the operation is deferred.
     * - When this.debug is true, detailed diagnostics are logged to the console.
     * @private
     */
    private _showRoute = (event: Event): void => {
        event.preventDefault();
        if (this.state !== RouteFormState.Loaded) {
            this.addEventListener("stateChange", (event: Event) => {
                if ((event as CustomEvent).detail === RouteFormState.Loaded) {
                    this._showRoute(event);
                }
            }, { once: true });
            if (this.debug) console.debug('RouteForm:_showRoute: form not yet ready, waiting for stateChange event.');
            return;
        };
        this._formElements.submitButton.blur();
        const formBlockList = this._formElements.waypointList.querySelectorAll<HTMLLIElement>(`li[data-type="${UI.WAYPOINT_ITEM_DATA_TYPE}"]`);
        // sort waypointItems based on the order in the list
        this.waypointItems.sort((a, b) => {
            const indexA = Array.from(formBlockList).indexOf(a.elements.listItem);
            const indexB = Array.from(formBlockList).indexOf(b.elements.listItem);
            return indexA - indexB;
        });
        if (this.debug) console.debug('RouteForm:_showRoute', this.waypointItems);

        const formWaypoints: WayPoints = Array.from(formBlockList).map((listElement) => {
            const waypointItem = this._getListItem(listElement);
            return waypointItem?.waypoint;
        }).filter((waypoint): waypoint is Waypoint => waypoint !== undefined);
        formWaypoints.forEach(wp => {
            if (wp.name?.startsWith(`${this.route.settings.pins.defaultLabel} #`)) wp.name = "";
        });
        this.route.parameters.waypoints = formWaypoints;
        this.route.parameters.routeType = this._formElements.routeTypeSelect.value as RouteType;
        if (this.settings.summary.show) {
            this.route.parameters.showSummary = this.settings.summary.type;
        }
        if (this.debug) console.debug('RouteForm:_showRoute parameters', this.route.parameters);
        this.route.addToMap();
        this.expanded = false;

        // if any missing labels were updated, we need to update the form and waypoint markers
        const listener = () => {
            if (this.debug) console.debug('RouteForm._showRoute: waypointsUpdated event detected.', this.route.waypoints)
            this.route.waypoints.forEach((waypoint, index) => {
                const listItem = this.waypointItems[index];
                if (listItem && waypoint.name) {
                    listItem.updateName(waypoint.name);
                }
            });
        };
        this.route.addEventListener("waypointsUpdated", listener, { once: true });
    }

    /**
     * Clears the current list of waypoints and resets the route form state.
     *
     * This method performs the following actions:
     * - Clears any active popups.
     * - Removes focus from the clear button.
     * - Collapses the form if expanded.
     * - Destroys all waypoint items.
     * - Clears the route asynchronously using a microtask.
     * - Empties the waypoint items array.
     * - Sets the form state to `NoRoute`.
     *
     * @private
     */
    private _clearList = (): void => {
        this._clearPopups();
        this._formElements.clearButton.blur();
        this.expanded = false;
        this.waypointItems.forEach((item) => {
            item.destroy();
        });
        queueMicrotask(() => this.route.clear());
        this.waypointItems = [];
        this.state = RouteFormState.NoRoute;
    }

    /**
     * Handles the click event on the header element.
     * Toggles the `expanded` state between true and false.
     *
     * @private
     */
    private _headerClickHandler = (): void => {
        this.expanded = (!this.expanded);
    }

    /**
     * Removes all Mapbox GL popups and markers from the map container.
     *
     * This method queries the map container for any elements with the classes
     * 'mapboxgl-popup' or 'mapboxgl-marker' and removes them from the DOM.
     * It is typically used to clear any existing popups or markers before
     * rendering new ones.
     *
     * @private
     */
    private _clearPopups = (): void => {
        // Remove any popups if present
        this.route.mapContainer.querySelectorAll(`${MAPBOX.MARKER_SELECTOR}, ${MAPBOX.POPUP_SELECTOR}`).forEach((popup) => {
            popup.remove();
        });
    }

    /**
     * Handles context menu (right-click or long-press) events on the Mapbox map.
     * 
     * This method displays a custom context menu popup at the clicked location, allowing the user
     * to add a waypoint. It ensures the popup is anchored in a stable position by first letting
     * Mapbox choose the best anchor, then recreating the popup with that anchor locked in.
     * 
     * The popup contains a button (with an icon and label) that, when clicked, adds a waypoint
     * at the clicked coordinates and closes the popup. The method also prevents the context menu
     * from appearing if the map is currently being moved, rotated, or zoomed.
     * 
     * @param e - The Mapbox map mouse or touch event containing the clicked location.
     * @returns `Promise<void>` - A promise that resolves when the popup has been handled and anchored.
     */
    private _contextClickHandler = async(e: mapboxgl.MapMouseEvent | mapboxgl.MapTouchEvent): Promise<void> => {
        if (this.route.map.isMoving() || this.route.map.isRotating() || this.route.map.isZooming()) {
            return; // Prevent if the map is actively being interacted with
        }

        const clickedLngLat = e.lngLat;

        this._clearPopups();
        const popupBody = document.createElement('div');
        popupBody.className = UI.CONTEXT_MENU_BODY_CLASS;
        popupBody.setAttribute('role', 'menu');
        const waypointLink = document.createElement('a');
        waypointLink.role = "button";
        waypointLink.append(svgFromId(this.settings.contextMenu.iconSvgId), this.settings.contextMenu.label);
        popupBody.append(waypointLink);

        // Create a new popup
        // Note: Mapbox GL JS does not support stable popup anchoring, so we use a two-step process

        const popupOpts = { ...this.settings.contextMenu.popUpOptions };

        // Declare variables for stable popup
        let rightClickPopup: mapboxgl.Popup | null = null;
        let closed = false;

        // Add click handler to the button inside the popup
        const handleAction = (event: Event) => {
            event.preventDefault(); // Prevent default action
            event.stopImmediatePropagation(); // Prevent other handlers from executing
            event.stopPropagation(); // Prevent event bubbling
            this._addWaypoint(clickedLngLat);
            closed = true; // Mark as closed to prevent further actions
            rightClickPopup?.remove(); // Close popup after action
            rightClickPopup = null; // Clear reference
        };

        // Attach event listener to the button after the popup is added
        popupBody.addEventListener("click", handleAction);

        // Create initial popup so mapbox picks the best anchor for visibility
        const initialPopup = new mapboxgl.Popup(popupOpts)
            .setLngLat(clickedLngLat)
            .setDOMContent(popupBody)
            .addTo(this.route.map);

        rightClickPopup = initialPopup;

        // Wait a frame so the popup DOM is inserted and Mapbox has applied the anchor class
        await new Promise(requestAnimationFrame);

        // Defensive: ensure element exists
        const initialEl = initialPopup.getElement();
        if (!initialEl || closed || popupOpts.anchor) {
            // already closed or fixed anchor provided
            return;
        }

        // Find Mapbox's anchor class, e.g. "mapboxgl-popup-anchor-top"
        const anchorClass = Array.from(initialEl.classList).find(c => c.startsWith('mapboxgl-popup-anchor-'));
        const chosenAnchor = anchorClass 
            ? (anchorClass.replace('mapboxgl-popup-anchor-', '') as mapboxgl.PopupOptions['anchor']) 
            : undefined;

        if (!chosenAnchor || closed) return; // already closed or fixed anchor provided

        // Remove the initial popup (this detaches the popup's DOM but popupBody remains referenced)
        initialPopup.remove();

        // Create a new popup with the chosen anchor to lock placement
        rightClickPopup = new mapboxgl.Popup({ ...popupOpts, anchor: chosenAnchor })
            .setLngLat(clickedLngLat)
            .setDOMContent(popupBody) // move the same node, listeners preserved
            .addTo(this.route.map);

    }

    /**
     * Clears the long press detection by cancelling any pending touch timeout
     * and resetting the touch start point.
     *
     * This method should be called to ensure that any ongoing long press gesture
     * detection is aborted, such as when the user lifts their finger or the gesture
     * is otherwise interrupted.
     *
     * @private
     */
    private _clearLongPress = (): void => {
        if (this._touchTimeout !== null) {
            clearTimeout(this._touchTimeout);
            this._touchTimeout = null;
        }
        this._touchStartPoint = null;
    }

    /**
     * Handles the touch start event on the map.
     * 
     * If a single touch is detected, stores the touch start point and sets a timeout to trigger
     * a context menu handler after a specified long press duration. If multiple touches are detected,
     * clears any pending long press actions.
     * 
     * @param e - The mapboxgl.MapTouchEvent containing information about the touch event.
     */
    private _handleTouchStart = (e: mapboxgl.MapTouchEvent): void => {
        if (e.originalEvent.touches.length === 1) {
            this._touchStartPoint = e.point;
            this._touchTimeout = window.setTimeout(() => {
                this._contextClickHandler(e);
            }, this.settings.contextMenu.longPressDuration);
        } else {
            this._clearLongPress();
        }
    }

    /**
     * Handles the touch move event on the map.
     * 
     * If the user's touch movement exceeds the configured move tolerance (in pixels),
     * this method clears the long press timeout to prevent triggering a long press action.
     *
     * @param e - The mapboxgl.MapTouchEvent containing the current touch point coordinates.
     */
    private _handleTouchMove = (e: mapboxgl.MapTouchEvent): void => {
        if (!this._touchStartPoint) return;
        const dx = e.point.x - this._touchStartPoint.x;
        const dy = e.point.y - this._touchStartPoint.y;
        if (Math.sqrt(dx * dx + dy * dy) > this.settings.contextMenu.moveTolerancePx) {
            this._clearLongPress(); // Clear timeout if moved too much
        }
    }

    /**
     * Attaches event listeners to the map instance for handling right-click (context menu)
     * and touch-based long-press interactions. This enables custom context menu functionality
     * on both desktop and mobile devices. The method sets up handlers for:
     * - "contextmenu": Handles right-click events.
     * - "touchstart", "touchmove", "touchend", "touchcancel": Handles touch interactions for long-press detection.
     * - "dragstart", "rotatestart", "pitchstart": Clears long-press state when map gestures begin.
     *
     * @private
     */
    private _addRightClickMenuListeners = (): void => {
        this.route.map.on("contextmenu", this._contextClickHandler);
        this.route.map.on("touchstart", this._handleTouchStart);
        this.route.map.on("touchmove", this._handleTouchMove);
        this.route.map.on("touchend", this._clearLongPress);
        this.route.map.on("touchcancel", this._clearLongPress);
        this.route.map.on("dragstart", this._clearLongPress);
        this.route.map.on("rotatestart", this._clearLongPress);
        this.route.map.on("pitchstart", this._clearLongPress);
    }

    /**
     * Destroys the custom right-click context menu on the map and removes all related event listeners.
     *
     * This method performs the following actions:
     * - Removes all popup elements containing the context menu from the map container.
     * - Detaches event listeners for context menu, touch, drag, rotate, and pitch events that are used to trigger or clear the context menu.
     *
     * @private
     */
    private _destroyRightClickMenu = (): void => {
        this.route.mapContainer
            .querySelectorAll(`${MAPBOX.POPUP_SELECTOR}:has(div.${UI.CONTEXT_MENU_BODY_CLASS})`)
            .forEach((el) => el.remove());
        this.route.map.off("contextmenu", this._contextClickHandler);
        this.route.map.off("touchstart", this._handleTouchStart);
        this.route.map.off("touchmove", this._handleTouchMove);
        this.route.map.off("touchend", this._clearLongPress);
        this.route.map.off("touchcancel", this._clearLongPress);
        this.route.map.off("dragstart", this._clearLongPress);
        this.route.map.off("rotatestart", this._clearLongPress);
        this.route.map.off("pitchstart", this._clearLongPress);
    }

    /**
     * Initializes and attaches all necessary event listeners for the form UI components.
     *
     * - Adds right-click context menu listeners.
     * - Attaches click event handlers to the header, submit, and clear buttons.
     * - Initializes a sortable list for waypoints with drag-and-drop functionality,
     *   including accessibility attributes and cursor feedback during drag operations.
     *
     * @private
     */
    private _addEventListeners = (): void => {
        this._addRightClickMenuListeners();
        this._formElements.headerButton.addEventListener("click", this._headerClickHandler);
        this._formElements.submitButton.addEventListener("click", this._showRoute);
        this._formElements.clearButton.addEventListener("click", this._clearList);
        this._sortableList = Sortable.create(this._formElements.waypointList, {
            handle: `.${UI.MOVE_HANDLE_CLASS}`,
            swapThreshold: 0.50,
            onChoose: (e) => {
                this._formElements.waypointList.style.cursor = "grabbing";
                e.item.setAttribute("aria-grabbed", "true");
            },
            onUnchoose: (e) => {
                this._formElements.waypointList.style.removeProperty('cursor');
                e.item.setAttribute("aria-grabbed", "false");
            },
        });
    }

    /**
     * Removes all event listeners attached to the form elements and destroys related UI components.
     *
     * This method performs the following actions:
     * - Destroys the right-click context menu.
     * - Removes the click event listener from the header button.
     * - Removes the click event listener from the submit button.
     * - Removes the click event listener from the clear button.
     * - Destroys the sortable list instance if it exists.
     *
     * @private
     */
    private _removeEventListeners = (): void => {
        this._destroyRightClickMenu();
        this._formElements.headerButton.removeEventListener("click", this._headerClickHandler);
        this._formElements.submitButton.removeEventListener("click", this._showRoute);
        this._formElements.clearButton.removeEventListener("click", this._clearList);
        this._sortableList?.destroy();
    }

    /**
     * Builds and returns the DOM elements required for the route form UI.
     *
     * This method creates a container with a header button, a form containing instructions,
     * a list for waypoints, and a row of buttons including clear, route type select, and submit.
     * It applies classes and attributes based on the current settings and route parameters.
     *
     * @returns {RouteFormElements} An object containing references to the created DOM elements:
     * - `container`: The main container div for the form.
     * - `form`: The form element for route input.
     * - `headerButton`: The button toggling the form's visibility.
     * - `waypointList`: The list element for displaying waypoints.
     * - `routeTypeSelect`: The select element for choosing the route type.
     * - `submitButton`: The button to submit the form.
     * - `clearButton`: The button to reset the form.
     * - `formInstructions`: The container for form instructions.
     */
    private _buildForm = (): RouteFormElements => {
        const container = document.createElement("div");
        container.classList.add("mapboxgl-ctrl", ...this.settings.formContainerClassList);
        // header button
        const headerButton = document.createElement("button");
        headerButton.id = "waypointFormHeader";
        headerButton.type = "button";
        headerButton.classList.add(...this.settings.headerButtonClasslist);
        headerButton.setAttribute("aria-controls", "waypointForm");
        headerButton.append(this.settings.headerButtonText, svgFromId(UI.EXPAND_ICON_ID, [UI.STANDARD_ICON_CLASS]))
        // form
        const form = document.createElement("form");
        form.id = "waypointForm";
        form.classList.add(...this.settings.formClasslist);
        form.setAttribute("aria-hidden", (!this.settings.initialStateExpanded).toString());
        form.setAttribute("aria-labelledby", "waypointFormHeader");
        const waypointList = document.createElement("ul");
        waypointList.role = "list";
        waypointList.classList.add(...this.settings.waypointListClassList);
        // button row
        const buttonRow = document.createElement("div");
        buttonRow.classList.add(...this.settings.buttonRowClassList);
        const clearButton = document.createElement("button");
        clearButton.type = "reset";
        clearButton.textContent = this.settings.clearButtonText;
        clearButton.disabled = true;
        const routeTypeSelect = document.createElement("select");
        routeTypeSelect.setAttribute("aria-label", this.settings.routeTypeAriaLabel);
        routeTypeSelect.id = 'route-type-select';
        const fragment = document.createDocumentFragment();
        const options = this.settings.routeTypeOptions;
        options.forEach(({ value, text }) => {
            const option = document.createElement("option");
            option.value = value ?? '';
            option.textContent = text;
            fragment.appendChild(option);
        });
        routeTypeSelect.appendChild(fragment);
        if (options.length < 2) routeTypeSelect.hidden = true;
        if (this.route.parameters.routeType || this.route.parameters.waypoints?.length) {
            if (this.debug) console.debug("Route form select", this.route.parameters.routeType)
            routeTypeSelect.value = this.route.parameters.routeType ?? "";
        }
        const submitButton = document.createElement("button");
        submitButton.type = "submit";
        submitButton.disabled = true;
        submitButton.textContent = this.settings.submitButtonText;
        // Instructions displayed when there are no waypoints
        const formInstructions = document.createElement("div");
        formInstructions.classList.add(...this.settings.routeInstructionsClassList);
        this.settings.routeInstructions.forEach((instruction) => {
            const instructionElement = document.createElement("p");
            instructionElement.textContent = instruction;
            formInstructions.appendChild(instructionElement);
        })
        // append elements
        buttonRow.append(clearButton, routeTypeSelect, submitButton);
        form.append(formInstructions, waypointList, buttonRow);
        container.append(headerButton, form);

        return {
            container,
            form,
            headerButton,
            waypointList,
            routeTypeSelect,
            submitButton,
            clearButton,
            formInstructions
        }
    }

}

