import mapboxgl from 'mapbox-gl';
import type { OffCanvasSettings } from "./offcanvas.js";

export type FeatureLayerHandler = (
    feature: mapboxgl.GeoJSONFeature, map: mapboxgl.Map
) => Promise<string | HTMLElement | DocumentFragment | undefined | null>;

export type FeatureLayer = {
    id: string;
    tileId?: string; // Optional tile id to use when querying features by geo coordinates
    handler: FeatureLayerHandler;
};

export type FeatureLayerSettings = {
    layers?: FeatureLayer[]; // Feature layers to query on click
    offCanvas: OffCanvasSettings;
    apiProximity: number; // when matching feature name to coordinate, variation radius in metres to allow
}