import mapboxgl from 'mapbox-gl';

import { 
    VectorTile 
} from '@mapbox/vector-tile';

import type { SearchBoxOptions } from '@mapbox/search-js-core';

import { 
    MapboxHTMLEvent, 
    MapboxSearchBox,
} from '@mapbox/search-js-web';

type RouteType = "walking" | "cycling" | "driving" | "driving-traffic" | undefined;
type DefinedRouteType = Exclude<RouteType, undefined>;

type MapboxglExt = typeof mapboxgl & { config: { ACCESS_TOKEN: string; }; }

export {
    MapboxHTMLEvent, 
    MapboxSearchBox,
    VectorTile
}

export type{
    MapboxglExt,
    SearchBoxOptions,
    RouteType,
    DefinedRouteType,
}

