import Offcanvas from '../feature/OffCanvas.js';
import type { HelpControlSettings } from '../types/controls/settings/help.js';
import type { OffCanvasSettings } from '../types.js';
import { svgFromId } from '../utility/utility.js';

export default class HelpControl implements mapboxgl.IControl {
    private _offcanvas?: Offcanvas;
    private _container!: HTMLDivElement;
    private _button!: HTMLButtonElement;
    private _helpTemplate: HTMLTemplateElement | null = null;

    constructor(
        private readonly _mapContainer: HTMLElement,
        private readonly _settings: HelpControlSettings, 
        private readonly _offCanvasSettings: OffCanvasSettings, 
        private readonly debug: boolean = false
    ) {}

    onAdd(map: mapboxgl.Map): HTMLElement {
        this._container = document.createElement('div');
        this._container.className = "mapboxgl-ctrl mapboxgl-ctrl-group";
        this._button = document.createElement('button');
        this._button.type = "button";
        this._button.setAttribute("aria-label", this._settings.label);
        this._button.addEventListener('click', this._clickHandler);
        this._button.className = "mapboxgl-ctrl-share";
        const span = document.createElement('span');
        span.className = "mapboxgl-ctrl-icon";
        span.title = this._settings.label;
        span.setAttribute("aria-hidden", "true");
        span.append(svgFromId(this._settings.iconSvgId));
        this._button.appendChild(span);
        this._container.appendChild(this._button);
        this._helpTemplate = document.querySelector<HTMLTemplateElement>('#help-content');
        if (this._helpTemplate) {
            this._offcanvas = new Offcanvas(this._mapContainer, this._offCanvasSettings);
        }
        if (this.debug) {
            console.debug("HelpControl: Added help button with help content:", this._helpTemplate);
        }
        return this._container;
    }

    onRemove(map: mapboxgl.Map): void {
        this._button.removeEventListener('click', this._clickHandler);
        if (this._container.parentNode) {
            this._container.parentNode.removeChild(this._container);
        }
        this._offcanvas?.destroy();
    }

    private _clickHandler = (): void => {
        if (!this._helpTemplate) {
            console.error("HelpControl: Help content not found");
            return;
        }
        if (this.debug) {
            console.debug("HelpControl: Help content found:", this._helpTemplate);
        }
        if (this._helpTemplate) {
            this._offcanvas?.show(this._helpTemplate.content.cloneNode(true) as DocumentFragment);
        }
    }
}