import FitBounds from './bounds/Bounds.js';
import HelpControl from './controls/Help.js';
import mapboxgl from 'mapbox-gl';
import merge from 'deepmerge';
import Route from './route/Route.js';
import SearchBoxControl, { SearchBoxState } from './controls/Search.js';
import ShareControl from './controls/Share.js';
import StyleControl, { StyleControlState } from './controls/Style.js';
import { CameraUrl } from './url/Url.js';
import type { Coordinates, CoordsPopupSettings, MapParameters, Settings, UserCountry } from './types.js';
import { CoordsPopup } from './widgets/CoordsPopup.js';
import { defaultSettings } from './Settings.js';
import { FeatureLayerManager } from './feature/Feature.js';
import { getCountryBBox, getMapboxAccessToken, getUserCountry, isStyleLoaded, loadSvgSpriteSheet, svgFromId } from './utility/utility.js';
import { MAPBOX, TERRAIN, UI } from './constants.js';
import { StyleUrl } from './url/Url.js';

const dontMerge = (_: Array<any>, source: Array<any>) => source;

/**
 * Provides a high-level interface for initializing, managing, and interacting with a Mapbox GL JS map,
 * including controls, feature layers, routing, terrain, and user location services.
 *
 * `MapboxAssist` extends `EventTarget` to emit custom events for fullscreen changes, unmatched features,
 * and other map interactions. It encapsulates the setup and teardown of the map instance, controls,
 * and related UI components, and manages state for features such as search, geolocation, and style switching.
 *
 * ### Features
 * - Initializes a Mapbox map instance or attaches to an existing one.
 * - Merges user-provided settings with defaults, supporting deep merging and array merge customization.
 * - Adds and manages built-in and custom controls (search, navigation, scale, fullscreen, share, style, geolocate).
 * - Handles map events, including style changes, resizing, fullscreen toggling, and camera movement.
 * - Manages feature layers and custom layers, including event handling for unmatched features.
 * - Supports route management, including route form and summary UI, and style locking.
 * - Provides user location services, including permission handling, disclaimer dialogs, and geolocation controls.
 * - Supports terrain loading and configuration if enabled in settings.
 * - Handles map container resizing, including on-screen keyboard detection for mobile devices.
 * - Provides methods for cleanup and resource release (`destroy()`).
 *
 * ### Usage
 * ```typescript
 * const assist = new MapboxAssist(mapParameters, settings);
 * // ... interact with the map and controls ...
 * assist.destroy(); // Clean up when done
 * ```
 *
 * @template mapboxgl.Map - The Mapbox GL JS map instance type.
 * @template mapboxgl.MapOptions - The options type for initializing the map.
 * @template Settings - The configuration settings type for MapboxAssist.
 * @template FeatureLayerManager - The manager for feature layers.
 * @template Route - The route management class.
 * @template FitBounds - The bounds fitting utility.
 * @template mapboxgl.Layer - The Mapbox GL JS layer type.
 * @template SearchBoxControl - The search box control type.
 * @template StyleControl - The style switcher control type.
 * @template mapboxgl.GeolocateControl - The geolocation control type.
 * @template mapboxgl.Marker - The Mapbox GL JS marker type.
 * @template mapboxgl.LngLat - The longitude/latitude tuple or object type.
 * @template mapboxgl.PopupOptions - The options type for popups.
 * @template CoordsPopup - The popup class for displaying coordinates.
 * @template CoordsPopupSettings - The settings type for coordinate popups.
 *
 * @fires fullscreenmode - Emitted when the map enters or exits fullscreen mode.
 * @fires unmatchedFeature - Emitted when a map click does not match any known feature.
 * @fires routeStyleLock - Dispatched when route operations lock/unlock style changes
 *
 * @remarks
 * - All controls and event listeners are automatically cleaned up by calling `destroy()`.
 * - The class is designed to be extensible and customizable via the `settings` parameter.
 * - Many methods are private and intended for internal use; public API is documented.
 */
export default class MapboxAssist extends EventTarget {
    map: mapboxgl.Map;
    mapOptions: Partial<mapboxgl.MapOptions>;
    settings: Settings;
    fitBounds: FitBounds;
    featureLayerManager: FeatureLayerManager;
    customLayers: mapboxgl.Layer[] = [];
    mapWrapper: HTMLElement;
    mapContainer: HTMLElement;
    private searchBox?: SearchBoxControl;
    private debug: boolean = false;
    private _route?: Route | null;
    private _urlCenter: boolean;
    private _styleControl?: StyleControl;
    private _geolocateControl?: mapboxgl.GeolocateControl;
    private _onScreenKeyboard: boolean = false;
    private _userCountry?: UserCountry;

    constructor(private mapParameters: MapParameters, settings: Partial<Settings> | null = null) {
        super();
        try {
            this.settings = merge(defaultSettings, settings ?? {}, { arrayMerge: dontMerge });
        } catch (error) {
            console.error("Error merging settings:", error);
            throw new Error("Failed to initialize MapboxAssist due to settings merge error.");
        }
        this.debug = this.settings.debug;
        if (this.debug) {
            console.debug("MapboxAssist: Initialized with parameters:", this.mapParameters);
            console.debug("MapboxAssist: Initialized with settings:", this.settings);
            (window as any).mapboxAssist = this;
        }
        this.mapOptions = mapParameters.mapOptions ?? {};
        const urlMapOptions: Partial<mapboxgl.MapOptions> = CameraUrl.getURL(this.debug) ?? {};
        const urlStyleIndex = StyleUrl.getURL(this.debug);
        const initialStyle = this.settings.mapStyles?.[urlStyleIndex ?? 0] ?? null;
        this.mapOptions = merge(this.mapOptions, urlMapOptions, { arrayMerge: dontMerge });
        this._urlCenter = !!urlMapOptions.center;
        if (!mapParameters.mapInstance) {
            if (!(this.mapOptions.accessToken || getMapboxAccessToken())) {
                throw new Error('Either a Mapbox access token or map instance is required');
            }
            if (!this.mapOptions.container) {
                throw new Error('Either a container or map instance is required');
            }
            const container = document.getElementById(this.mapOptions.container as string);
            if (container) {
                this.mapContainer = container;
            } else {
                throw new Error(`Container ${this.mapOptions.container} not found`);
            }
            if (initialStyle) this.mapOptions.style = initialStyle.source;
            this.map = new mapboxgl.Map({
                ...this.mapOptions,
                container: this.mapOptions.container
            });
        } else {
            this.map = mapParameters.mapInstance;
            this.mapContainer = this.map.getContainer();
            if (initialStyle) this.map.setStyle(initialStyle.source);
            if (this.mapOptions.bearing) this.map.setBearing(this.mapOptions.bearing);
            if (this.mapOptions.pitch) this.map.setPitch(this.mapOptions.pitch);
        }

        if (this.settings.loadSpritesheet?.path) {
            queueMicrotask(() => {
                loadSvgSpriteSheet(
                    this.settings.loadSpritesheet!.path,
                    this.settings.loadSpritesheet!.id
                );
            });
        }

        getUserCountry().then((userCountry) => {
            this._userCountry = userCountry;
            this._addMapControls();
        });

        this.mapWrapper = this._createMapWrapper();

        this.fitBounds = new FitBounds(this.map, this.settings.fitBounds, mapParameters.coordinates, this.debug);
        this.featureLayerManager = new FeatureLayerManager(this.map, this.mapOptions, this.settings.featureLayers, this.debug);

        this.route = new Route(
            this,
            mapParameters.route,
            this.fitBounds,
            this.debug
        );
        if (isStyleLoaded(this.map)) {
            this._onInitialStyleLoad();
        } else {
            this.map.once('style.load', () => { this._onInitialStyleLoad(); })
        }
    }

    /**
     * Cleans up and releases all resources used by the MapboxAssist instance.
     * 
     * This method removes all event listeners from the map and DOM elements,
     * destroys and removes all controls and child classes, and resets internal
     * state variables to their initial values. It should be called when the
     * MapboxAssist instance is no longer needed to prevent memory leaks and
     * unintended side effects.
     */
    public destroy(): void {
        // Remove map event listeners
        this._removeListeners();
        // Remove controls
        if (this.searchBox) this.map.removeControl(this.searchBox);
        this.searchBox = undefined;
        if (this._geolocateControl) this.map.removeControl(this._geolocateControl);
        this._geolocateControl = undefined;
        if (this._styleControl) this.map.removeControl(this._styleControl);
        this._styleControl = undefined;
        // Remove wrapper
        this.mapWrapper?.remove();
        // Destroy child classes
        this._route?.destroy();
        this._route = null;
        this.fitBounds?.destroy();
        this.fitBounds = null as unknown as FitBounds; // Type assertion to avoid type errors
        this.featureLayerManager?.destroy();
        this.featureLayerManager = null as unknown as FeatureLayerManager; // Type assertion to avoid type errors
        // Remove feature layer manager listeners
        this.featureLayerManager?.removeEventListener('unmatchedFeature', this._handleUnmatchedFeature);
        // tidy variables
        this.map = null as unknown as mapboxgl.Map; // Type assertion to avoid type errors
        this.mapParameters = null as unknown as MapParameters; // Type assertion to avoid type errors
        this.mapOptions = {};
        this.mapContainer = null as unknown as HTMLElement; // Type assertion to avoid type errors
        this.mapWrapper = null as unknown as HTMLElement; // Type assertion to avoid type errors
        this.settings = null as unknown as Settings; // Type assertion to avoid type errors
        this.customLayers = [];
    }

    /**
     * Indicates whether the map container is currently displayed in fullscreen mode.
     *
     * @returns `true` if the map container element is the current fullscreen element; otherwise, `false`.
     */
    get isFullscreen(): boolean {
        return document.fullscreenElement === this.mapContainer;
    }

    /**
     * Handles the initial loading of the map style and sets up the map accordingly.
     *
     * - Registers a listener for the "style.load" event to handle style changes.
     * - Adds event listeners required for map interaction.
     * - If no route waypoints are provided (via parameters or URL), places the map at a default location,
     *   optionally centering on the user's location if enabled in map parameters.
     * - If terrain is enabled in settings, loads the terrain source and sets the minimum pitch to 5 degrees
     *   to ensure correct feature placement.
     */
    private _onInitialStyleLoad = (): void => {
        // register all listeners for map events
        this._addListeners();
        // place map if no route waypoints passed into class (either via MapParameters or URL)
        // if mapParameters.useLocation is enabled, map will be centred on user location (if user permits)
        // otherwise, map will be centred on coordinates passed in via MapParameters (if any)
        if (!(this.route?.parameters.waypoints?.length ?? 0 > 0)) {
            this._placeMap();
        }
        // if using terrain, load the terrain source and set the minimum pitch to 5 degrees
        // with terrain enabled, pitch levels below 5 degrees causes placement of features to shift from correct place
        if (this.settings.terrain.enable) {
            this._loadTerrain();
            this.map.setMinPitch(TERRAIN.MIN_TERRAIN_PITCH);
        };
    }

    /**
     * Places or initializes the map view based on available parameters.
     *
     * - If both `_urlCenter` and `mapOptions.center` are defined, sets the map center and zoom accordingly.
     * - If user location should be shown on load and the Permissions API is available, attempts to retrieve the user's location asynchronously.
     *   - If successful, centers and zooms the map to the user's location.
     *   - If unsuccessful, fits the map to predefined parameter coordinates.
     * - Otherwise, fits the map to predefined parameter coordinates.
     *
     * @returns {void}
     */
    private _placeMap = async (): Promise<void> => {
        if (this._urlCenter && this.mapOptions.center) {
            this.map.setCenter(this.mapOptions.center);
            this.map.setZoom(this.mapOptions.zoom ?? MAPBOX.DEFAULT_ZOOM);
            if (this.debug) {
                console.debug('Map placed using mapOptions.center parameters:', this.mapOptions.center);
            }
            return;
        }
        if (!this._userCountry) this._userCountry = await getUserCountry();
        const canUseLocation: boolean = (
            !this.settings.limitToCountry || this._userCountry.ISO === this.settings.limitToCountry
        );
        if (!this.mapParameters.coordinates) {
            if (this.settings.limitToCountry) {
                this.mapParameters.coordinates = await getCountryBBox(this.settings.limitToCountry);
                if (this.debug) console.debug('Limiting map to country:', this.settings.limitToCountry, this.mapParameters.coordinates);
            } else {
                this.mapParameters.coordinates = this._userCountry.bounds;
                if (this.debug) console.debug('Using user country bounds:', this._userCountry);
            }
        }

        if (this.mapParameters.showUserLocationOnLoad && canUseLocation && 'permissions' in navigator) {
            queueMicrotask(async () => {
                const coords = await this._maybeRequestLocation();
                if (coords) {
                    if (this.debug) console.debug('User location:', coords);
                    this.map.jumpTo({
                        center: coords,
                        zoom: (this.mapOptions.zoom ?? MAPBOX.USER_LOCATION_ZOOM),
                    });
                } else {
                    this._fitParameterCoordinates();
                }
            });
        } else {
            this._fitParameterCoordinates();
        }
    }

    /**
     * Attempts to request the user's geolocation coordinates, handling permissions and a custom disclaimer dialog.
     *
     * This method checks if the user has previously seen and accepted a location disclaimer.
     * It uses the Permissions API to determine the current geolocation permission state:
     * - If permission is granted, it retrieves and returns the user's location.
     * - If permission is denied, it returns `undefined`.
     * - If permission is in the 'prompt' state and the disclaimer has not been seen, it shows the disclaimer dialog.
     *   If the user accepts, it retrieves and returns the location; otherwise, it returns `undefined`.
     * - If the disclaimer has already been seen and the state is not 'prompt', it attempts to get the location.
     *
     * @returns A promise that resolves to a tuple containing the latitude and longitude as `[number, number]`,
     * or `undefined` if the location could not be obtained or permission was denied.
     */
    private _maybeRequestLocation = async (): Promise<[number, number] | undefined> => {
        const seen = localStorage.getItem('seen-location-disclaimer') === 'true';

        let permission: PermissionStatus | undefined;
        try {
            permission = await navigator.permissions.query({ name: 'geolocation' });
        } catch {
            // Permissions API not supported or failed — treat as 'prompt'
        }

        const state = permission?.state ?? 'prompt';

        if (state === 'granted') {
            return await this._getLocation();
        }

        if (state === 'denied') {
            return undefined;
        }

        if (!seen) {
            const accepted = await this._showLocationDisclaimerDialog();
            localStorage.setItem('seen-location-disclaimer', 'true');
            if (accepted) {
                return await this._getLocation();
            } else {
                return undefined;
            }
        } else {
            if (state !== 'prompt') {
                return await this._getLocation();
            } else {
                return undefined;
            }
        }
    }

    /**
     * Attempts to retrieve the user's current geographic coordinates using the browser's Geolocation API.
     *
     * @returns A promise that resolves to a `Coordinates` tuple `[longitude, latitude]` if successful,
     * or `undefined` if geolocation is not available or an error occurs.
     *
     * @remarks
     * - Requires user permission to access location.
     * - If the browser does not support geolocation, or if an error occurs (e.g., permission denied),
     *   the promise resolves to `undefined`.
     */
    private _getLocation = async (): Promise<Coordinates | undefined> => {
        if (!('geolocation' in navigator)) return undefined;

        return new Promise((resolve) => {
            navigator.geolocation.getCurrentPosition(
                (pos) => {
                    const { longitude, latitude } = pos.coords;
                    resolve([longitude, latitude]);
                },
                (err) => {
                    console.warn('Geolocation error:', err);
                    resolve(undefined);
                }
            );
        });
    }

    /**
     * Adjusts the map view to fit the coordinates specified in `mapParameters`.
     *
     * If `mapParameters.coordinates` is defined, this method schedules a microtask
     * to update `fitBounds.points` with these coordinates and then calls
     * `fitBounds.fitScreenBounds()` to adjust the map's visible area accordingly.
     *
     * @private
     */
    private _fitParameterCoordinates = (): void => {
        if (this.mapParameters.coordinates) {
            queueMicrotask(() => {
                this.fitBounds.points = this.mapParameters.coordinates!;
                this.fitBounds.fitScreenBounds();
            });
        }
    }

    /**
     * Displays a modal dialog to show a location disclaimer to the user.
     *
     * The dialog content and appearance are configured via `this.settings.locationServices?.disclaimerModal`.
     * If the settings are not found, the method logs a warning and resolves with `null`.
     * Otherwise, it creates and displays a styled HTML dialog with a title, messages, and accept/decline buttons.
     *
     * Resolves to `true` if the user accepts, `false` if declined, or `null` if the dialog could not be shown.
     *
     * @returns A Promise that resolves to `true` if accepted, `false` if declined, or `null` if settings are missing.
     */
    private _showLocationDisclaimerDialog = (): Promise<boolean | null> => {
        return new Promise((resolve) => {
            const settings = this.settings.locationServices?.disclaimerModal;
            if (!settings) {
                console.warn('Location disclaimer modal settings not found. Skipping.');
                resolve(null);
            } else {
                const dialog: HTMLDialogElement = document.createElement('dialog');
                dialog.classList.add(...settings.classList); // style via external CSS
                if (settings.title) {
                    const title = document.createElement('div');
                    title.role = "heading";
                    if (settings.icon)
                        title.append(svgFromId(settings.icon, ['standard-icon']))
                    title.append(settings.title);
                    dialog.append(title);
                }
                const message = document.createElement('div');
                message.role = "note";
                settings.messages.forEach((item) => {
                    const paragraph = document.createElement('p');
                    paragraph.textContent = item;
                    message.append(paragraph);
                });
                const form = document.createElement('form');
                form.method = 'dialog';
                const menu = document.createElement('menu');
                const declineButton = document.createElement('button');
                declineButton.value = 'decline';
                declineButton.textContent = settings.denyButtonText;
                const acceptButton = document.createElement('button');
                acceptButton.value = 'accept';
                acceptButton.textContent = settings.acceptButtonText;
                menu.append(declineButton, acceptButton);
                form.append(menu);
                dialog.append(message, form);

                this.mapContainer.appendChild(dialog);

                dialog.addEventListener('close', () => {
                    const accepted = dialog.returnValue === 'accept';
                    dialog.remove();
                    resolve(accepted);
                });

                dialog.showModal();
            }
        });
    }

    /**
     * Adds various controls to the Mapbox map instance based on the current settings.
     *
     * Controls added may include:
     * - Search box control (with event handling for focus/expand)
     * - Navigation (compass) control (if not already added) styled with pitch if terrain enabled in settings
     * - Scale control (styled as a group) (if not already added)
     * - Fullscreen control (if not already added)
     * - Share control (if enabled in settings)
     * - Style control (if multiple map styles are available and enabled)
     * - Geolocate (user location) control (with debug event logging if enabled)
     *
     * Also removes any existing attribution controls with constructor names "sl" or "rl".
     *
     * @private
     * @returns {void}
     */
    private _addMapControls = (): void => {
        if (this.settings.search.show) {
            if (this.settings.limitToCountry) {
                this.settings.search.options.country = this.settings.limitToCountry;
                if (this.debug) console.debug('SearchBoxControl: limiting search to country', this.settings.limitToCountry);
            }
            this.searchBox = new SearchBoxControl(this.settings.search, this.debug);
            this.map.addControl(this.searchBox);
            this.searchBox.addEventListener('expandEvent', (event: Event) => {
                const customEvent = event as CustomEvent;
                if (customEvent.detail as SearchBoxState === SearchBoxState.Focused) {
                    if (this.route?.routeForm?.expanded) this.route.routeForm.expanded = false;
                    if (this.isFullscreen && this.route?.routeSummary?.detailedSummary.expanded)
                        this.route.routeSummary.detailedSummary.expanded = false;
                }
            });
            // Move top-right control position down by set amount to accomodate search box
            const topRight = this.mapContainer.querySelector('.mapboxgl-ctrl-top-right')
            if (topRight) (topRight as HTMLElement).style.top = UI.TOP_RIGHT_ADJUST_WITH_SEARCH;
        }
        if (!this.map._controls.some(c => c instanceof mapboxgl.NavigationControl)) {
            this.map.addControl(new mapboxgl.NavigationControl({ visualizePitch: this.settings.terrain.enable }));
        }
        if (!this.map._controls.some(c => c instanceof mapboxgl.ScaleControl)) {
            const scale: mapboxgl.ScaleControl = new mapboxgl.ScaleControl();
            this.map.addControl(scale, "bottom-right");
            scale._container.classList.add('mapboxgl-ctrl-group');
        }
        if (!this.map._controls.some(c => c instanceof mapboxgl.FullscreenControl)) {
            this.map.addControl(new mapboxgl.FullscreenControl());
        }
        if (this.settings.shareControl?.show) {
            this.map.addControl(
                new ShareControl(
                    {
                        label: this.settings.shareControl.label,
                        iconSvgId: this.settings.shareControl.iconSvgId,
                        fallbackMessage: this.settings.shareControl.fallbackMessage,
                    },
                    this.debug
                )
            );
        }
        if (this.settings.styleControl?.show && (this.settings.mapStyles?.length ?? 0) > 1) {
            this._styleControl = new StyleControl(
                this.settings.mapStyles!,
                this.settings.styleControl,
                this.debug
            );
            this.map.addControl(this._styleControl);
            if (this.route) {
                this.route.addEventListener('routeStyleLock', (event: Event) => {
                    const locked = (event as CustomEvent).detail as boolean;
                    this._styleControl!.state = locked ? StyleControlState.Busy : StyleControlState.Ready;
                    if (this.debug) console.debug('routeStyleLock:', locked);
                });
            }
        }

        if (this.settings.locationServices?.showUserLocationControl) {
            this._geolocateControl = new mapboxgl.GeolocateControl({
                positionOptions: {
                    enableHighAccuracy: true
                },
                trackUserLocation: true,
                showUserHeading: true
            });
            this.map.addControl(this._geolocateControl, 'top-right');
            if (this.debug) {
                this._geolocateControl.on('trackuserlocationstart', () => {
                    console.debug('Tracking started', this._geolocateControl!._watchState);
                });
                this._geolocateControl.on('trackuserlocationend', () => {
                    console.debug('Tracking stopped', this._geolocateControl!._watchState);
                });

                this._geolocateControl.on('geolocate', (e) => {
                    console.debug('Geolocation success:', e.coords);
                });
                this._geolocateControl.on('error', (err) => {
                    console.error('Geolocation error:', err);
                });
            }
        }
        // Help control
        if (this.settings.helpControl?.show) {
            this.map.addControl(
                new HelpControl(
                    this.mapContainer,
                    this.settings.helpControl,
                    this.settings.featureLayers.offCanvas,
                    this.debug
                )
            );
        }
        // remove attribution controls (mapbox logo and 'improve this map' link)
        const attribControls = this.map._controls.filter(obj => ["sl", "rl"].includes(obj.constructor.name))
        attribControls.forEach(c => this.map.removeControl(c));
    }

    /**
     * Adds all necessary event listeners and handlers to the map and related DOM elements.
     *
     * - Listens for the map's "style.load" event to handle style changes.
     * - Sets up a fullscreen change listener on the map container to adjust control placement and route summary.
     * - Updates CSS custom properties for map dimensions on the map container and listens for map resize events.
     * - Handles visual viewport resize events (e.g., on-screen keyboard appearance) to update map size variables.
     * - Updates the URL to reflect the current camera position when the map movement ends.
     * - Handles unmatched feature clicks by showing a default coordinates popup.
     * - Listens for search result positioning events to handle post-search map interactions.
     */
    private _addListeners = (): void => {
        this.map.on("style.load", this._handleStyleLoad);
        // helper function to set placement of various controls and route summary when toggling fullscreen mode
        this.mapContainer.addEventListener('fullscreenchange', this._handleFullScreenEvent);
        // add map dimension style variables to map container, update on map resize
        // used by SearchBoxControl and RouteForm to set scrollable heights
        this.mapContainer.style.setProperty('--map-height', `${this.map.getCanvas().scrollHeight}px`)
        this.mapContainer.style.setProperty('--map-width', `${this.map.getCanvas().scrollWidth}px`)
        this.map.on('resize', this._handleMapResize);
        // Resize the map size variables when the on screen keyboard is shown or hidden
        if (window.visualViewport) {
            window.visualViewport.addEventListener('resize', this._handleResizeVisualViewport);
        }
        // Add current display to URL if URL sharing enabled
        if (this.settings.route.enableUrlSharing) this.map.on('moveend', this._moveEndHandler);
        // handle click on point with no matched feature - default coords popup
        this.featureLayerManager?.addEventListener('unmatchedFeature', this._handleUnmatchedFeature);
        // handle search result click, emitted once result centred on map
        this.searchBox?.addEventListener('searchResultPositioned', this._handleSearchResultPositioned);
    }

    /**
     * Removes all event listeners previously attached by the MapboxAssist instance.
     *
     * This includes:
     * - Mapbox GL JS map events such as "style.load", "resize", and "moveend".
     * - DOM events on the map container, such as "fullscreenchange".
     * - Visual viewport resize events, if supported by the browser.
     * - Custom events from feature layer manager and search box components.
     *
     * This method should be called during cleanup to prevent memory leaks and unintended behavior.
     */
    private _removeListeners = (): void => {
        this.map.off("style.load", this._handleStyleLoad);
        this.map.off('resize', this._handleMapResize);
        this.map.off('moveend', this._moveEndHandler);
        this.mapContainer.removeEventListener('fullscreenchange', this._handleFullScreenEvent);
        if (window.visualViewport) {
            window.visualViewport.removeEventListener('resize', this._handleResizeVisualViewport);
        }
        this.featureLayerManager?.removeEventListener('unmatchedFeature', this._handleUnmatchedFeature);
        this.searchBox?.removeEventListener('searchResultPositioned', this._handleSearchResultPositioned);
    }

    /**
     * Handles the style load event for the map.
     * If terrain is enabled in the settings, it triggers the loading of terrain data.
     *
     * @private
     */
    private _handleStyleLoad = (): void => {
        if (this.settings.terrain.enable) this._loadTerrain();
    }

    /**
     * Handles events for unmatched features on the map.
     *
     * This method is triggered when a feature on the map does not match any known data.
     * It extracts the longitude and latitude (`lngLat`), an optional label, and popup options
     * from the event's detail, then creates and displays a popup at the specified coordinates.
     *
     * @param event - The event object, expected to be a `CustomEvent` containing `lngLat`, optional `label`, and `popupOptions` in its detail.
     */
    private _handleUnmatchedFeature = (event: Event) => {
        const customEvent = event as CustomEvent;
        const { lngLat, label, popupOptions } = customEvent.detail as { lngLat: mapboxgl.LngLat, label?: string, popupOptions: mapboxgl.PopupOptions };
        this._createCoordsPopup(lngLat, label, popupOptions).addTo(this.map);
    }

    /**
     * Handles the event triggered when a search result is positioned on the map.
     * Extracts the longitude and latitude (`lngLat`) and an optional label from the event's detail,
     * then creates and adds a marker to the map at the specified coordinates.
     *
     * @param event - The event object, expected to be a `CustomEvent` containing `lngLat`, an optional `label`, and `popupOptions` in its detail.
     */
    private _handleSearchResultPositioned = (event: Event) => {
        const customEvent = event as CustomEvent;
        const { lngLat, label } = customEvent.detail as { lngLat: mapboxgl.LngLat, label?: string, popupOptions: mapboxgl.PopupOptions };
        this._createCoordsMarker(lngLat, label).addTo(this.map);
    }

    /**
     * Handles the fullscreen mode event by emitting a custom "fullscreenmode" event.
     * This event can be used by dependent classes (e.g., RouteSummary) to react to changes
     * in fullscreen state, such as repositioning UI elements. Optionally logs the fullscreen
     * state to the console if debug mode is enabled.
     *
     * @private
     * @remarks
     * The custom event's `detail` property contains the current fullscreen state (`this.isFullscreen`).
     */
    private _handleFullScreenEvent = (): void => {
        // emit custom fullscreen event for dependent classes
        // used by RouteSummary to position summary container
        const isFullscreen = this.isFullscreen;
        const fullscreenmodeEvent = new CustomEvent("fullscreenmode", { detail: isFullscreen });
        this.dispatchEvent(fullscreenmodeEvent);
        this.mapContainer.dataset.fullscreen = isFullscreen ? 'true' : 'false';
        if (this.debug) console.debug('Map is now fullscreen:', isFullscreen);
    }

    /**
     * Handles resizing of the map container when the map's canvas size changes.
     * 
     * If the on-screen keyboard is not active, this method retrieves the current
     * scroll width and height of the map's canvas, updates the corresponding CSS
     * custom properties (`--map-width` and `--map-height`) on the map container,
     * and logs the new size to the console if debug mode is enabled.
     *
     * @private
     * @returns {void}
     */
    private _handleMapResize = (): void => {
        if (!this._onScreenKeyboard) {
            const canvasWidth: string = `${this.map.getCanvas().scrollWidth}px`
            const canvasHeight: string = `${this.map.getCanvas().scrollHeight}px`
            this.mapContainer.style.setProperty('--map-width', canvasWidth)
            this.mapContainer.style.setProperty('--map-height', canvasHeight)
            if (this.debug) console.debug(`Map resized to ${canvasWidth} x ${canvasHeight}`)
        }
    }

    /**
     * Handles changes in the visual viewport size, typically triggered by the appearance or disappearance
     * of the on-screen keyboard on mobile devices. Updates the map container's height CSS variable and toggles
     * a class on the map wrapper to reflect the keyboard state. Also scrolls the currently focused element into view
     * if the keyboard state changes.
     *
     * @private
     */
    private _handleResizeVisualViewport = (): void => {
        const height = window.visualViewport!.height;
        const isKeyboard = height < window.innerHeight - 100; // 100px safety margin to prevent false positive from small shifts in viewport height
        if (this._onScreenKeyboard !== isKeyboard) {
            if (this.debug) console.debug(`On screen keyboard ` + (isKeyboard ? 'opened' : 'closed'));
            if (isKeyboard) {
                this.mapContainer.style.setProperty('--map-height', `${height}px`)
            } else {
                this.mapContainer.style.setProperty('--map-height', `${this.map.getCanvas().scrollHeight}px`)
            }
            this.mapWrapper.classList.toggle('keyboard-open', isKeyboard);
            document.activeElement?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            this._onScreenKeyboard = isKeyboard;
        }
    }

    /**
     * Handles the map's 'moveend' event by updating the browser URL to reflect the current camera position.
     * Invokes the static `setURL` method of the `CameraUrl` class, passing the current map instance.
     *
     * @private
     */
    private _moveEndHandler = (): void => CameraUrl.setURL(this.map);

    /**
     * Creates and returns a `CoordsPopup` instance at the specified longitude and latitude.
     *
     * @param lngLat - The longitude and latitude coordinates where the popup should appear.
     * @param label - (Optional) A label to display in the popup.
     * @param popupOptions - (Optional) Additional options to customize the popup's appearance and behavior.
     * @returns A configured `CoordsPopup` instance with the specified coordinates and label.
     */
    private _createCoordsPopup = (lngLat: mapboxgl.LngLat, label?: string, popupOptions: mapboxgl.PopupOptions = {}): CoordsPopup => {
        const coordsPopupSettings: CoordsPopupSettings = structuredClone(this.settings.coordsPopup.popupOptions);
        coordsPopupSettings.options = { ...coordsPopupSettings.options, ...popupOptions }
        return new CoordsPopup(this.map, coordsPopupSettings, this.debug).setCoordsHTML(lngLat, label);
    }

    /**
     * Creates a new Mapbox marker at the specified longitude and latitude.
     * Optionally attaches a popup with a label to the marker.
     *
     * @param lngLat - The longitude and latitude where the marker will be placed.
     * @param label - Optional label text to display in the marker's popup.
     * @returns A configured Mapbox mapboxgl.Marker instance.
     */
    private _createCoordsMarker = (lngLat: mapboxgl.LngLat, label?: string): mapboxgl.Marker => {
        return new mapboxgl.Marker(this.settings.coordsPopup.markerOptions)
            .setPopup(this._createCoordsPopup(lngLat, label))
            .setLngLat(lngLat);
    }

    /**
     * Determines whether the current map style includes a terrain source.
     *
     * @returns {boolean} `true` if any of the map's sources are of type 'raster-dem', indicating terrain data is present; otherwise, `false`.
     * @throws Will return `false` if an error occurs while accessing the map style or its sources.
     */
    private _hasTerrain = (): boolean => {
        try {
            const style = this.map.getStyle() as mapboxgl.StyleSpecification;
            return (Object.values(style.sources).some(source => source.type === 'raster-dem'))
        } catch {
            return false
        }
    }

    /**
     * Loads and applies a terrain source to the map if it is not already present.
     *
     * This method asynchronously checks if the terrain source exists using `_hasTerrain()`.
     * If not, it adds a raster DEM (Digital Elevation Model) source to the map using the
     * configuration specified in `this.settings.terrain`, and sets the terrain with the
     * specified vertical exaggeration.
     *
     * @private
     * @returns {void}
     */
    private _loadTerrain = (): void => {
        queueMicrotask(() => {
            if (!this._hasTerrain()) {
                this.map.addSource('mapbox-dem', {
                    'type': 'raster-dem',
                    'url': TERRAIN.TERRAIN_DEM_URL,
                    'tileSize': TERRAIN.TERRAIN_TILE_SIZE,
                    'maxzoom': TERRAIN.TERRAIN_MAX_ZOOM
                });
                // add the DEM source as a terrain layer with exaggerated height
                this.map.setTerrain({
                    'source': 'mapbox-dem',
                    'exaggeration': this.settings.terrain.verticalExaggeration
                });
            }
        });
    }

    /**
     * Creates a wrapper `<div>` element around the map container and optionally adds a caption element.
     *
     * - The wrapper is assigned the class "mapbox-assist-wrapper".
     * - The map container is moved inside the wrapper.
     * - If a caption HTML is provided in `this.settings.caption.html`, a caption `<div>` is created,
     *   assigned the specified class list, and appended to the wrapper.
     *
     * @returns The newly created wrapper `<div>` element containing the map container and optional caption.
     */
    private _createMapWrapper = (): HTMLElement => {
        const wrapper: HTMLElement = document.createElement("div");
        wrapper.classList.add(UI.WRAPPER_CLASS);
        this.mapContainer.parentNode!.insertBefore(wrapper, this.mapContainer.nextSibling);
        wrapper.appendChild(this.mapContainer);
        if (!!this.settings.caption.html) {
            const caption: HTMLElement = document.createElement("div");
            caption.classList = this.settings.caption.classList;
            caption.innerHTML = this.settings.caption.html;
            wrapper.appendChild(caption);
        }
        return wrapper;
    }

    /**
     * Gets the current route associated with this instance.
     *
     * @returns The current {@link Route} object, or `undefined`/`null` if no route is set.
     */
    get route(): Route | undefined | null {
        return this._route;
    }

    /**
     * Sets the current route for the instance.
     * If a previous route exists, it will be cleared before assigning the new route.
     *
     * @param route - The new `Route` object to set.
     */
    set route(route: Route) {
        if (this._route) {
            this._route.clear();
        }
        this._route = route;
    }

};
