import mapboxgl, { LngLat, LngLatBounds } from 'mapbox-gl';
import type { MapboxglExt, UserCountry } from '../types.js';
import { MAPBOX } from '../constants.js';

/**
 * Represents a rectangle defined by its top, right, bottom, and left boundaries.
 *
 * @remarks
 * The `Rectangle` class provides properties to access the width and height of the rectangle,
 * as well as the boundary values. It is initialized with an object containing the boundary values.
 *
 * @example
 * ```typescript
 * const rect = new Rectangle({ top: 10, right: 50, bottom: 40, left: 20 });
 * console.debug(rect.width); // 30
 * console.debug(rect.height); // 30
 * ```
 *
 * @public
 */
export class Rectangle {
    public top: number;
    public right: number;
    public bottom: number;
    public left: number;

    constructor(bounds: { top: number; right: number; bottom: number; left: number; }) {
        this.top = bounds.top;
        this.right = bounds.right;
        this.bottom = bounds.bottom;
        this.left = bounds.left;
    }

    get width(): number {
        return this.right - this.left;
    }

    get height(): number {
        return this.bottom - this.top;
    }
}

/**
 * Generates a random lowercase alphabetic string of the specified length.
 *
 * @param length - The desired length of the generated string. Defaults to 8 if not provided.
 * @returns A random string consisting of lowercase letters (a-z).
 */
export const getRandomString = (length: number = 8): string => {
    // Generate a random n-character string
    let result: string = "";
    for (let i = 0; i < length; i++) {
        result += String.fromCharCode(97 + Math.floor(Math.random() * 26));
    }
    return result;
}


/**
 * Retrieves the current Mapbox access token from the MapboxGL configuration.
 *
 * @returns {string} The Mapbox access token.
 */
export function getMapboxAccessToken(): string {
    return (mapboxgl as MapboxglExt).config.ACCESS_TOKEN
}

/**
 * Checks if a Mapbox map's style is loaded. A more reliable method to check style 
 * loaded than map.isStyleLoaded() which can return true early
 *
 * This function attempts to retrieve the style of the provided Mapbox map instance.
 * If the style is successfully retrieved, it indicates that the style is loaded.
 * If an error occurs (e.g., the style is not yet loaded), the function returns `false`.
 *
 * @param map - The Mapbox map instance to check.
 * @returns `true` if the style is loaded, otherwise `false`.
 */
export function isStyleLoaded(map: mapboxgl.Map): boolean {
    try {
        map.getStyle();
        return true;
    } catch {
        return false;
    }
}

/**
 * Retrieves the active style URL from a Mapbox map instance.
 *
 * This function extracts the style URL in the format `mapbox://styles/{username}/{style_id}`
 * based on the map's current style configuration. If the style or sprite information
 * is unavailable or does not match the expected format, the function returns `undefined`.
 *
 * @param map - The Mapbox map instance from which to retrieve the active style URL.
 * @returns The active style URL in the format `mapbox://styles/{username}/{style_id}`,
 *          or `undefined` if the style information is not available or does not match
 *          the expected format.
 */
export function getActiveStyleUrl(map: mapboxgl.Map): string | undefined {
    let style: mapboxgl.StyleSpecification | null | undefined
    try {
        style = map.getStyle();
    } catch (error) {
        console.error("Error retrieving style:", error);
        return;
    }

    if (!(style?.sprite || style?.imports?.at(0)?.data?.sprite)) return;

    const spriteUrl = style.sprite ?? style.imports![0].data!.sprite as string;

    // Match the parts from a mapbox://sprites/{username}/{style_id}
    const match = spriteUrl.match(/^mapbox:\/\/sprites\/([^/]+)\/([^/]+)/);
    if (!match) return;

    const username = match[1];
    const styleId = match[2];

    return `mapbox://styles/${username}/${styleId}`;
}

/**
 * Creates an SVG element containing a <use> element that references an SVG symbol by its ID.
 *
 * @param id - The ID of the SVG symbol to reference (without the '#' prefix).
 * @param classList - An optional array of CSS class names to add to the created SVG element.
 * @returns The constructed SVGElement containing the referenced symbol.
 */
export function svgFromId(id: string, classList?: string[]): SVGElement {
    const svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
    const use = document.createElementNS("http://www.w3.org/2000/svg", "use");
    use.setAttributeNS("http://www.w3.org/1999/xlink", "xlink:href", `#${id}`);
    svg.appendChild(use);
    if (classList) svg.classList.add(...classList);
    return svg;
}

/**
 * Loads an SVG sprite sheet from a given path and appends it to the specified container.
 * 
 * This function fetches the SVG content from the provided path, parses it, and appends
 * the resulting SVG element to the specified container in the DOM. If an ID is provided,
 * it will be used as the ID for the SVG element; otherwise, it will derive an ID from the
 * file name.
 *
 * @param path - The URL or path to the SVG sprite sheet.
 * @param id - Optional ID for the SVG element. If not provided, it will be derived from the file name.
 * @param container - The HTML element to which the SVG sprite sheet will be appended. Defaults to document.body.
 */
export function loadSvgSpriteSheet(path: string, id?: string, container: HTMLElement = document.body): void {
    queueMicrotask(() => {
        try {
            const spriteID = id ?? path.split('/').at(-1)?.split('.')[0] ?? 'svg-sprite-sheet';
            if (!container.querySelector(`#${spriteID}`)) {
                fetch(path)
                    .then(response => {
                        if (!response.ok) {
                            throw new Error(`Failed to load ${path}: ${response.status} ${response.statusText}`);
                        }
                        const contentType = response.headers.get('Content-Type') || '';
                        if (!contentType.includes('image/svg+xml')) {
                            throw new Error(`Unexpected content type: ${contentType}`);
                        }
                        return response.text(); // Get the SVG content as text
                    })
                    .then(svgText => {
                        const parser = new DOMParser();
                        const doc = parser.parseFromString(svgText, 'image/svg+xml');
                        // Detect <parsererror>
                        const parserError = doc.querySelector('parsererror');
                        if (parserError) {
                            console.error('SVG parse error:', parserError.textContent);
                            return;
                        }
                        const svgEl = doc.documentElement;
                        svgEl.id = spriteID;
                        svgEl.style.display = 'none';
                        container.appendChild(svgEl);
                    })
                    .catch(error => console.error('Error loading sprite sheet:', error));
            }
        } catch (error) {
            console.error('loadSvgSpriteSheet', error);
        }
    });
};


/**
 * Utility class for parsing geographic coordinates from string representations.
 *
 * Supports parsing both decimal degrees (e.g., "40.7128, -74.0060") and
 * degrees-minutes-seconds (DMS) formats (e.g., "40° 42' 51" N 74° 0' 21" W").
 *
 * All parsing methods return coordinates in the format `[longitude, latitude]`
 * or `null` if the input is invalid or out of bounds.
 *
 * @example
 * ```typescript
 * CoordinateParser.parse("40.7128, -74.0060"); // [-74.0060, 40.7128]
 * CoordinateParser.parse("40° 42' 51\" N 74° 0' 21\" W"); // [-74.005833, 40.714167]
 * ```
 */
export class CoordinateParser {
    private static readonly REG_LNG_LAT = /^(-?\d+(\.\d+)?),\s*(-?\d+(\.\d+)?)$/;
    private static readonly REG_DMS = /(\d{1,3})[°\s]?(\d{1,2})['\s]?(\d{1,2}(?:\.\d+)?)[\"\s]?([NSEW])/gi;

    /**
     * Parses a coordinate string and returns a tuple containing latitude and longitude as numbers.
     * 
     * This method attempts to parse the input string as a decimal coordinate first.
     * If that fails, it attempts to parse the input as a DMS (Degrees, Minutes, Seconds) coordinate.
     * 
     * @param input - The coordinate string to parse.
     * @returns A tuple of [latitude, longitude] if parsing is successful, or `null` if parsing fails.
     */
    public static parse(input: string): [number, number] | null {
        return this.parseDecimal(input) ?? this.parseDMS(input);
    }

    /**
     * Parses a string containing decimal latitude and longitude values and returns them as a tuple.
     *
     * The input string is matched against the `REG_LNG_LAT` regular expression. If a valid match is found,
     * the latitude and longitude values are extracted, parsed as floats, and validated to ensure they are within
     * acceptable ranges (latitude: -90 to 90, longitude: -180 to 180).
     *
     * @param input - The string containing the decimal latitude and longitude values.
     * @returns A tuple `[longitude, latitude]` if parsing and validation succeed, or `null` if the input is invalid.
     */
    public static parseDecimal(input: string): [number, number] | null {
        const decimalMatch = input.trim().match(this.REG_LNG_LAT);
        if (decimalMatch) {
            const lat = parseFloat(decimalMatch[1]);
            const lon = parseFloat(decimalMatch[3]);
            if (lat < -90 || lat > 90 || lon < -180 || lon > 180) return null;
            return [lon, lat];
        }
        return null;
    }

    /**
     * Parses a string containing latitude and longitude in Degrees, Minutes, Seconds (DMS) format
     * and returns the coordinates as a tuple of [longitude, latitude] in decimal degrees.
     *
     * The input string should contain both latitude and longitude in DMS format, e.g.:
     * "40° 26' 46\" N 79° 58' 56\" W"
     *
     * @param input - The string containing DMS-formatted coordinates.
     * @returns A tuple [longitude, latitude] in decimal degrees if parsing is successful and values are valid,
     *          or `null` if parsing fails or coordinates are out of bounds.
     */
    public static parseDMS(input: string): [number, number] | null {
        const dmsMatches = input.matchAll(this.REG_DMS);
        let lat = null;
        let lon = null;
        for (const match of dmsMatches) {
            const deg = parseInt(match[1], 10);
            const min = parseInt(match[2], 10);
            const sec = parseFloat(match[3]);
            const dir = match[4].toUpperCase();
            const decimal = deg + min / 60 + sec / 3600;
            if (dir === 'N' || dir === 'S') {
                lat = dir === 'S' ? -decimal : decimal;
            } else if (dir === 'E' || dir === 'W') {
                lon = dir === 'W' ? -decimal : decimal;
            }
        }
        if (lat !== null && lon !== null) {
            if (lat < -90 || lat > 90 || lon < -180 || lon > 180) return null;
            return [lon, lat];
        }
        return null;
    }
}

export async function getCountryBBox(isoCode: string): Promise<LngLatBounds> {
    try {
        const mapboxAccessToken = getMapboxAccessToken();
        const url = `https://api.mapbox.com/search/geocode/v6/forward?q=${isoCode}&types=country&access_token=${mapboxAccessToken}`;
        const resp = await fetch(url);
        const data = await resp.json();
        const countryFeature = data.features?.find((f: any) => f.properties?.feature_type === 'country');
        const bbox = countryFeature?.properties?.bbox;
        return mapboxgl.LngLatBounds.convert(bbox);
    } catch (error) {
        console.error('Error fetching country bounding box:', error);
        return mapboxgl.LngLatBounds.convert(MAPBOX.FALLBACK_LNGLAT_BOUNDS);
    }
}

export const getUserCountry = async (): Promise<UserCountry> => {
    try {
        const response = await fetch('https://ipapi.co/country/');
        if (!response.ok) throw new Error('Failed to fetch country');
        const country = (await response.text()).trim();
        const bounds = await getCountryBBox(country);
        return { ISO: country, bounds: bounds };
    } catch (error) {
        console.error('Error getting user country:', error);
        return { ISO: "xx", bounds: mapboxgl.LngLatBounds.convert(MAPBOX.FALLBACK_LNGLAT_BOUNDS) };
    }
};