import mapboxgl from 'mapbox-gl';
import Toast from '../widgets/Toast.js';
import type { ShareControlSettings } from '../types.js';
import { svgFromId } from '../utility/utility.js';

/**
 * A custom Mapbox GL control for sharing the current map view.
 * This control provides a button that allows users to share the current URL
 * using the Web Share API if available, or copies the URL to the clipboard as a fallback.
 * 
 * @class ShareControl
 * @implements {mapboxgl.IControl}
 * 
 * @example
 * ```typescript
 * const shareControl = new ShareControl('Share map', '/assets/share-icon.svg');
 * map.addControl(shareControl, 'top-right');
 * ```
 */
export default class ShareControl implements mapboxgl.IControl {
    private _map?: mapboxgl.Map;
    private _container!: HTMLDivElement;
    private _button!: HTMLButtonElement;

    /**
     * Creates an instance of ShareControl. Default position is 'top-right'.
     * 
     * @param settings - Configuration settings for the share button.
     * @param settings.label - The label for the share button (used for accessibility).
     * @param settings.icon - The URL of the icon to be used for the share button.
     * @param settings.fallbackMessage - The message to be displayed when the Web Share API is not available.
     * @param debug - Optional flag to enable debug logging (defaults to false)
     */
    constructor(private readonly settings: ShareControlSettings, private readonly debug: boolean = false) { }

    /**
     * Adds the custom Share control to the Mapbox map.
     *
     * This method is called by the Mapbox GL JS API when the control is added to the map.
     * It creates the control's container and button elements, sets up accessibility attributes,
     * attaches the click event handler, and appends the SVG icon.
     *
     * @param map - The Mapbox GL JS map instance to which the control is being added.
     * @returns The HTML element representing the control's container, which will be added to the map UI.
     */
    onAdd(map: mapboxgl.Map): HTMLElement {
        this._map = map;
        this._container = document.createElement('div');
        this._container.className = "mapboxgl-ctrl mapboxgl-ctrl-group";
        this._button = document.createElement('button');
        this._button.type = "button";
        this._button.setAttribute("aria-label", this.settings.label);
        this._button.addEventListener('click', this._clickHandler);
        this._button.className = "mapboxgl-ctrl-share";
        const span = document.createElement('span');
        span.className = "mapboxgl-ctrl-icon";
        span.title = this.settings.label;
        span.setAttribute("aria-hidden", "true");
        span.append(svgFromId(this.settings.iconSvgId));
        this._button.appendChild(span);
        this._container.appendChild(this._button);
        return this._container;
    }

    /**
     * Removes the control from the map and cleans up resources.
     *
     * This method detaches the control's container element from its parent node in the DOM,
     * and clears the reference to the map instance to aid garbage collection.
     *
     * @remarks
     * This method is typically called by the map when the control is removed.
     */
    onRemove(): void {
        this._button.removeEventListener('click', this._clickHandler);
        if (this._container.parentNode) {
            this._container.parentNode.removeChild(this._container);
        }
        this._map = undefined;
    }

    getDefaultPosition(): mapboxgl.ControlPosition {
        return 'top-right';
    }

    /**
     * Copies the current page URL to the user's clipboard and displays a toast notification.
     * If debug mode is enabled, logs a message to the console indicating the action.
     *
     * @private
     * @returns {void}
     */
    private _copyToClipboard = (): void => {
        navigator.clipboard.writeText(window.location.href);
        Toast.show(this._map!.getContainer(), this.settings.fallbackMessage, 2000);
        if (this.debug) console.debug('Sharing API not available, copied url to clipboard');
    }

    /**
     * Handles the click event for sharing the current page URL.
     *
     * If the Web Share API is available (`navigator.share`), attempts to share the current page URL using the native share dialog.
     * On successful sharing, logs a success message if debug mode is enabled.
     * If sharing fails or the Web Share API is not available, falls back to copying the URL to the clipboard.
     *
     * @private
     */
    private _clickHandler = () => {
        if (navigator.share) {
            navigator.share({
                url: window.location.href,
            })
                .then(() => { if (this.debug) console.debug('Shared successfully'); })
                .catch((err) => {
                    console.error('Share failed:', err);
                    this._copyToClipboard();
                });
        } else {
            this._copyToClipboard();
        }
    }
}