import mapboxgl from 'mapbox-gl';
import type { GeoCircle } from '../bounds/index.js';
import type { RouteParameters } from '../route/route.js';
import type { CoordinatesArray } from '../../types.js';

export interface MapParameters {
    // at least one of mapInstance or {options.accessToken, options.container} must be defined
    mapOptions?: Partial<mapboxgl.MapOptions>; // Used if creating a new map
    mapInstance?: mapboxgl.Map // Map instance to use - if not defined, a new map will be created
    route?: RouteParameters; // Optional route to display on load
    showUserLocationOnLoad?: boolean; // Optional flag to use the user's location as the starting point for the map
    // Optional set of points or centre + radius to be contained in the initial map view
    // Ignored if route defined, fallback if user location requested but denied
    coordinates?: CoordinatesArray | mapboxgl.LngLat[] | mapboxgl.LngLatBounds | GeoCircle;
}