import type { CoordinatesArray, ElevationRGBSettings } from '../types.js';
import { getMapboxAccessToken } from '../utility/utility.js';
import { MAPBOX } from '../constants.js';


/**
 * Provides methods for retrieving elevation data from Mapbox Terrain-RGB tiles for arrays of geographic coordinates.
 * 
 * The `ElevationRGB` class efficiently fetches, decodes, and caches elevation values for given longitude/latitude pairs
 * using Mapbox's Terrain-RGB tile service. It supports chunking, concurrency, and retry logic for robust and scalable
 * elevation queries, and includes internal caching to minimize redundant network requests.
 * 
 * The `getElevationsFromTerrainRGB` method was written to replace the MapBox method queryTerrainElevation which does not 
 * return consistent terrain data. `queryTerrainElevation` is dependent on zoom, pitch and screen resolution and can result 
 * in errors of more than 50%. This method is independent of all those factors and will return consistent data. 
 * 
 * ## Features
 * - Rounds coordinates for cache efficiency and precision control.
 * - Cleans up expired or excess cache entries automatically.
 * - Splits large coordinate arrays into overlapping chunks for parallel processing.
 * - Groups coordinates by tile to minimize network requests.
 * - Fetches and decodes Terrain-RGB tiles concurrently, with retry and timeout logic.
 * - Decoded tiles are cached to speed subsequent elevation queries and reduce API calls.
 * - Interpolates zero (missing) elevations using neighboring values.
 * - Configurable settings for cache, chunk size, concurrency, retries, and more.
 * 
 * ## Usage
 * 
 * ```typescript
 * const elev = new ElevationRGB({ ACCESS_TOKEN: 'your-mapbox-token' });
 * const elevations = await elev.getElevationsFromTerrainRGB([
 *   [longitude1, latitude1],
 *   [longitude2, latitude2],
 *   // ...
 * ]);
 * ```
 * 
 * @remarks
 * - Requires a valid Mapbox access token.
 * - Designed for use in browser environments supporting OffscreenCanvas and ImageBitmap.
 * - Returns `0` (sea level) for coordinates outside valid tile data or on error.
 * 
 * @public
 */
export class ElevationRGB {
    // elevation data caching
    private _tileCache = new Map<
        string, // A string in the form "x,y" — identifying the tile in the global tile grid at the configured zoom level
        {
            timestamp: number;  // When this entry was cached (in ms since epoch)
            data: Int32Array;   // A flattened array of decoded elevation values for the 256×256 tile.
        }
    >();
    private _cachePurgeInterval?: ReturnType<typeof setInterval>; // timer to remove stale cache entries
    // constants
    private static readonly NO_DATA = 0; // set erronious values to sea level
    private static readonly BYTE_SIZE = 256; // distinct values per RGB channel
    private static readonly TILE_SIZE = 256;
    private static readonly SCALE_FACTOR = 0.1; // converts stored RGB value back to metres
    private static readonly BASE_ELEVATION = -10000; // mapbox RGB base elevation
    private static readonly DEFAULTS: ElevationRGBSettings = {
        CACHE_TTL_MS: 1000 * 60 * 60, // 60 minutes
        COORDINATE_MAX_DP: 5, // approx 1.1m max resolution error
        MAX_CACHE_ENTRIES: 80, // at dp=5, approx 256kb per entry, 20MB max cache size
        ZOOM: 14, // do not use higher as this is the zoom level of the max resolution of the terrain tiles
        CONCURRENCY: 6,
        MAX_RETRIES: 2,
        TILE_TIMEOUT_MS: 5000
    };
    private settings: ElevationRGBSettings;
    private debug: boolean;

    constructor({
        settings,
        debug = false
    }: {
        settings?: Partial<ElevationRGBSettings>;
        debug?: boolean;
    }) {
        this.settings = {
            ...ElevationRGB.DEFAULTS,
            ...settings
        };
        this.debug = debug;
    }

    /**
     * Retrieves elevation data for an array of geographic coordinates using Mapbox's Terrain-RGB tiles.
     * 
     * This method performs the following steps:
     * 1. Rounds coordinates to a specified decimal precision for cache efficiency.
     * 2. Cleans up the internal elevation cache by evicting expired or excess entries.
     * 3. If the number of coordinates exceeds the configured chunk size, splits the request into overlapping chunks and processes them in parallel, stitching results together.
     * 4. Checks the cache for previously fetched results.
     * 5. Groups coordinates by their corresponding terrain tile.
     * 6. Fetches and decodes the required Terrain-RGB tiles concurrently, extracting elevation values for each coordinate.
     * 7. Interpolates zero elevations using neighboring values where possible.
     * 8. Caches the results and returns the elevation array.
     * 
     * @param coords - An array of [longitude, latitude] pairs for which to retrieve elevations.
     * @returns A promise that resolves to an array of elevation values (in metres) corresponding to the input coordinates.
     * 
     * @remarks
     * - Uses an internal cache to minimize redundant network requests.
     * - Handles chunking and concurrency to efficiently process large coordinate sets.
     * - Retries failed tile fetches with exponential backoff.
     * - Requires valid Mapbox access token and appropriate settings to be configured.
     * - Returns `ElevationRGB.NO_DATA` for coordinates outside valid tile data.
     */
    getElevationsFromTerrainRGB = async (coords: CoordinatesArray): Promise<number[]> => {
        // —————————————
        // 1) PRE-PROCESS COORDINATES TO REQUIRED ACCURACY
        const roundedCoords = coords.map(([lng, lat]) => [
            +lng.toFixed(this.settings.COORDINATE_MAX_DP),
            +lat.toFixed(this.settings.COORDINATE_MAX_DP)
        ]) as CoordinatesArray;

        // —————————————
        // 2) MAP POINTS TO TILES + PIXEL INDICES
        type Pt = { key: string; idx: number; px: number; py: number };
        const tilePoints: Pt[] = roundedCoords.map(([lng, lat], idx) => {
            return this._pointsToTilesIndices(lng, lat, idx);
        });

        const uniqueTiles = Array.from(
            new Set(tilePoints.map((tp) => tp.key))
        );

        // —————————————
        // 3) FETCH & CACHE TILES IN CONCURRENCY BATCHES
        let fetchCount: number = 0;
        const tileTasks = uniqueTiles.map((key) => async () => {
            if (this._tileCache.has(key)) return;
            fetchCount++;
            const buf: Int32Array<ArrayBuffer> = await this._decodeRemoteTile(key);
            this._tileCache.set(key, { timestamp: Date.now(), data: buf });
        });

        for (let i = 0; i < tileTasks.length; i += this.settings.CONCURRENCY) {
            await Promise.all(
                tileTasks
                    .slice(i, i + this.settings.CONCURRENCY)
                    .map((fn) => fn().catch((e) => console.error(e)))
            );
        }

        // —————————————
        // 4) BUILD RESULT ARRAY
        const results = new Array<number>(coords.length);
        for (const { key, idx, px, py } of tilePoints) {
            const entry = this._tileCache.get(key)!;
            entry.timestamp = Date.now(); // refresh timestamp on access - accessed tile chaches are kept fresh
            results[idx] = entry.data[py * ElevationRGB.TILE_SIZE + px] / 100;
        }

        // —————————————
        // 5) INTERPOLATE NO_DATA ELEVATIONS
        if (results.includes(ElevationRGB.NO_DATA)) {
            // If a no-data point exists between two data points, likely an error point - interpolate the elevation instead
            // Points on tile edge can trigger this condition.
            for (let i = 1; i < results.length - 1; i++) {
                if (results[i] === ElevationRGB.NO_DATA && results[i - 1] !== ElevationRGB.NO_DATA && results[i + 1] !== ElevationRGB.NO_DATA) {
                    results[i] = (results[i - 1] + results[i + 1]) / 2;
                    if (this.debug) console.debug(`ElevationRGB: Data for point index ${i} not found and was interpolated to ${results[i]}m.`);
                }
            }
        }

        // —————————————
        // 6) CACHE MAINTENNANCE
        queueMicrotask(() => {
            this._purgeStaleCacheItems();       // remove stale items
            this._trimCache();                  // remove excess items if over the limit
            this._startPeriodicCachePurge();    // remove stale items every 1/4 of TTL
        });

        if (this.debug) console.debug(
            'ElevationRGB:',
            `Returned elevation data for ${results.length} coordinates.`,
            `${tileTasks.length} terrain tiles read (${fetchCount} fetched, ${tileTasks.length - fetchCount} cached).`,
            `Cache contains ${this._tileCache.size} tiles after operation (${this._getCacheSize().toFixed(2)}MB).`
        );
        return results;
    }

    /**
     * Trims the elevation cache to ensure it does not exceed the maximum allowed entries.
     *
     * If the cache size exceeds `MAX_CACHE_ENTRIES` as specified in the settings,
     * this method removes the oldest entries (based on their timestamp) until the
     * cache size is within the allowed limit.
     *
     * @private
     */
    private _trimCache = (): void => {
        const maxEntries = this.settings.MAX_CACHE_ENTRIES;
        if (this._tileCache.size <= maxEntries) return;

        // Convert entries to array, sort by timestamp ascending (oldest first)
        const entries = Array.from(this._tileCache.entries());
        entries.sort((a, b) => a[1].timestamp - b[1].timestamp);

        const toDelete = entries.length - maxEntries;
        for (let i = 0; i < toDelete; i++) {
            this._tileCache.delete(entries[i][0]);
        }
        if (this.debug) console.debug(
            `ElevationRGB._trimCache: reduced cache by ${toDelete} entries.`,
            `Cache size ${this._getCacheSize().toFixed(2)}MB.`
        );
    };


    /**
     * Removes stale entries from the elevation cache based on their age.
     *
     * Iterates through the `_elevationCache` and deletes any entries whose
     * timestamp exceeds the configured cache time-to-live (`CACHE_TTL_MS`).
     * This helps to prevent the cache from growing indefinitely and ensures
     * that only fresh elevation data is retained.
     *
     * @private
     */
    private _purgeStaleCacheItems = (): void => {
        // Evict by TTL
        const now = Date.now();
        let i: number = 0;
        for (const [key, entry] of this._tileCache) {
            if (now - entry.timestamp > this.settings.CACHE_TTL_MS) {
                this._tileCache.delete(key);
                i++;
            }
        }
        if (this.debug) console.debug(
            `ElevationRGB: cache purged of ${i} stale entries.`,
            `Cache size ${this._getCacheSize().toFixed(2)}MB.`
        );
    }

    /**
     * Starts a periodic timer to purge stale items from the elevation cache.
     * The purge interval is determined by dividing the cache TTL by 4, with a minimum of 1000ms.
     * If the cache becomes empty during a purge, the periodic purge is automatically stopped.
     * Does nothing if the periodic purge is already running.
     *
     * @private
     */
    private _startPeriodicCachePurge = (): void => {
        if (this._cachePurgeInterval !== undefined) return; // already running
        const interval = Math.max(1000, this.settings.CACHE_TTL_MS / 4);
        this._cachePurgeInterval = setInterval(() => {
            this._purgeStaleCacheItems();
            if (this._tileCache.size === 0) {
                this._stopPeriodicCachePurge(); // stop if cache is empty
                if (this.debug) console.debug(`ElevationRGB: cache purged of all entries.`);
            }
        }, interval);
    };

    /**
     * Stops the periodic cache purge interval if it is currently active.
     * Clears the interval timer and resets the internal reference to `undefined`.
     * This prevents further automatic cache purging until restarted.
     *
     * @private
     */
    private _stopPeriodicCachePurge = (): void => {
        if (this._cachePurgeInterval !== undefined) {
            clearInterval(this._cachePurgeInterval);
            this._cachePurgeInterval = undefined;
        }
    };

    // HELPER FUNCTIONS

    /**
     * Converts RGB color values to an elevation value based on the Mapbox RGB encoding scheme.
     *
     * @param r - The red channel value (0-255).
     * @param g - The green channel value (0-255).
     * @param b - The blue channel value (0-255).
     * @returns The calculated elevation in meters, or `ElevationRGB.NO_DATA` if the RGB values are invalid.
     *
     * @remarks
     * The conversion uses the formula:
     * `elevation = BASE_ELEVATION + ((r * BYTE_SIZE^2 + g * BYTE_SIZE + b) * SCALE_FACTOR)`
     * where `BYTE_SIZE` is typically 256, and `SCALE_FACTOR` and `BASE_ELEVATION` are constants defined in `ElevationRGB`.
     */
    private _rgbToElevation = (r: number, g: number, b: number): number => {
        if (!this._isValidRGB(r, g, b)) return ElevationRGB.NO_DATA;
        const elevation = ElevationRGB.BASE_ELEVATION +
            ((r * ElevationRGB.BYTE_SIZE * ElevationRGB.BYTE_SIZE +
                g * ElevationRGB.BYTE_SIZE + b) *
                ElevationRGB.SCALE_FACTOR);
        return elevation
    }

    /**
     * Checks whether all provided channel values are valid 8-bit RGB values.
     *
     * @param channels - The channel values to validate (e.g., red, green, blue).
     * @returns `true` if every channel is an integer between 0 (inclusive) and `ElevationRGB.BYTE_SIZE` (exclusive); otherwise, `false`.
     */
    private _isValidRGB = (...channels: number[]): boolean => {
        return channels.every(c =>
            Number.isInteger(c) && c >= 0 && c < ElevationRGB.BYTE_SIZE);
    }

    /**
     * Wraps a promise with a timeout, rejecting if the promise does not settle within the specified time.
     *
     * @template T The type of the resolved value of the promise.
     * @param p - The promise to wrap with a timeout.
     * @param ms - The timeout duration in milliseconds.
     * @param info - Optional additional information to include in the timeout error message.
     * @returns A promise that resolves or rejects with the original promise, or rejects with a timeout error if the specified time elapses.
     */
    private _withTimeout = <T>(p: Promise<T>, ms: number, info = ''): Promise<T> =>
        new Promise((res, rej) => {
            const t = setTimeout(() => rej(new Error(`Timeout ${ms}ms: ${info}`)), ms);
            p.then(v => { clearTimeout(t); res(v); })
                .catch(e => { clearTimeout(t); rej(e); });
        });

    /**
     * Attempts to fetch an image from the specified URL and create an ImageBitmap from it,
     * retrying the operation with exponential backoff if it fails.
     *
     * @param url - The URL of the image to fetch.
     * @param attempt - The current retry attempt (default is 0).
     * @returns A promise that resolves to an ImageBitmap of the fetched image.
     * @throws If the fetch fails after the maximum number of retries.
     */
    private _retryFetchBitmap = async (url: string, attempt = 0): Promise<ImageBitmap> => {
        try {
            const resp = await this._withTimeout(fetch(url), this.settings.TILE_TIMEOUT_MS, url);
            if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
            const blob = await resp.blob();
            return await createImageBitmap(blob);
        } catch (err) {
            if (attempt < this.settings.MAX_RETRIES) {
                await new Promise(r => setTimeout(r, 200 * 2 ** attempt));
                return this._retryFetchBitmap(url, attempt + 1);
            }
            throw err;
        }
    };

    /**
     * Generates a Mapbox Terrain-RGB tile URL for the specified tile coordinates and zoom level.
     *
     * @param x - The x coordinate of the tile.
     * @param y - The y coordinate of the tile.
     * @param z - The zoom level of the tile.
     * @returns The URL string to fetch the Terrain-RGB tile from Mapbox.
     *
     * @remarks
     * The function uses the access token from the settings or from the Mapbox GL configuration.
     */
    private _terrainTileUrl = (x: number, y: number, z: number): string => {
        const accessToken: string = this.settings.ACCESS_TOKEN ?? getMapboxAccessToken();
        return `${MAPBOX.API_URL}mapbox.terrain-rgb/${z}/${x}/${y}.pngraw?access_token=${accessToken}`;
    }

    /**
     * Decodes a remote terrain tile into an Int32Array of elevation values.
     *
     * Fetches a bitmap image for the specified tile key, draws it onto an offscreen canvas,
     * and extracts the pixel data. Each pixel's RGB values are converted to an elevation value,
     * which is then stored in the resulting Int32Array (with elevation values multiplied by 100).
     *
     * @param key - The tile key in the format "z/tx/ty" representing zoom, tile x, and tile y.
     * @returns A promise that resolves to an Int32Array containing elevation values (×100) for the tile.
     * @throws If fetching or decoding the bitmap fails.
     */
    private _decodeRemoteTile = async (key: string): Promise<Int32Array<ArrayBuffer>> => {
        const [z, tx, ty] = key.split("/").map((n) => parseInt(n, 10));
        const bmp = await this._retryFetchBitmap(this._terrainTileUrl(tx, ty, z));
        const canvas = new OffscreenCanvas(
            ElevationRGB.TILE_SIZE,
            ElevationRGB.TILE_SIZE
        );
        const ctx = canvas.getContext("2d")!;
        ctx.drawImage(bmp, 0, 0);
        const img = ctx
            .getImageData(0, 0, ElevationRGB.TILE_SIZE, ElevationRGB.TILE_SIZE)
            .data;

        // decode into Int32Array (elevation ×100)
        const buf = new Int32Array(ElevationRGB.TILE_SIZE ** 2);
        for (let i = 0; i < buf.length; i++) {
            const r = img[i * 4],
                g = img[i * 4 + 1],
                b = img[i * 4 + 2];
            const elev = this._rgbToElevation(r, g, b);
            buf[i] = Math.round(elev * 100);
        }
        return buf
    }

    /**
     * Converts geographic coordinates (longitude and latitude) to tile indices and pixel positions within a tile
     * at the zoom level specified in the settings. Returns an object containing the tile key, the provided index,
     * and the pixel coordinates within the tile.
     *
     * @param lng - The longitude in degrees.
     * @param lat - The latitude in degrees.
     * @param idx - An index associated with the point, passed through to the result.
     * @returns An object containing:
     *   - `key`: A string representing the tile in the format `${z}/${tx}/${ty}`.
     *   - `idx`: The provided index.
     *   - `px`: The x pixel coordinate within the tile.
     *   - `py`: The y pixel coordinate within the tile.
     */
    private _pointsToTilesIndices(lng: number, lat: number, idx: number): {
        key: string;
        idx: number;
        px: number;
        py: number;
    } {
        const z = this.settings.ZOOM;
        const xF = ((lng + 180) / 360) * 2 ** z;
        const yF = ((1 -
            Math.log(Math.tan((lat * Math.PI) / 180) +
                1 / Math.cos((lat * Math.PI) / 180)) /
            Math.PI) /
            2) *
            2 ** z;
        const tx = Math.floor(xF), ty = Math.floor(yF), px = Math.floor((xF - tx) * ElevationRGB.TILE_SIZE), py = Math.floor((yF - ty) * ElevationRGB.TILE_SIZE);
        return { key: `${z}/${tx}/${ty}`, idx, px, py };
    }

    /**
     * Calculates the total size of the tile cache in megabytes (MB).
     *
     * Iterates over all entries in the `_tileCache` and sums the `byteLength` of each entry's `data` property.
     * The total size is then converted from bytes to megabytes.
     *
     * @returns The total cache size in megabytes.
     */
    private _getCacheSize = (): number => {
        let total = 0;
        for (const entry of this._tileCache.values()) {
            total += entry.data.byteLength; // 262,144 per tile
        }
        return total / (1024 * 1024);
    }

}