import type { OffCanvasSettings } from '../types.js';
import { svgFromId } from '../utility/utility.js';

/**
 * Represents an off-canvas panel component for displaying overlay content.
 * 
 * The `Offcanvas` class provides methods to show and hide a side panel (off-canvas)
 * with customizable content. It manages the creation and destruction of the panel,
 * its overlay, and close button, and handles user interactions for closing the panel.
 * 
 * @example
 * ```typescript
 * const offcanvas = new Offcanvas(document.body, {
 *   classLists: {
 *     panel: ['offcanvas-panel'],
 *     body: ['offcanvas-body'],
 *     closeBtn: ['offcanvas-close'],
 *     overlay: ['offcanvas-overlay']
 *   },
 *   svg: {
 *     closeBtn: 'close-icon'
 *   }
 * });
 * offcanvas.show('<p>Hello, world!</p>');
 * ```
 * 
 * @remarks
 * - The panel can be closed by clicking the close button or the overlay.
 * - Content can be provided as a string, HTMLElement, or DocumentFragment.
 * 
 * @public
 * @class
 */
export default class Offcanvas {
    private HIDE_TIMEOUT = 500; // Timeout for hiding the panel after it is closed
    private _elements: {
        panel: HTMLDialogElement,
        body: HTMLElement,
        closeBtn: HTMLElement,
    }

    constructor(parentElement: HTMLElement, private readonly settings: OffCanvasSettings) {
        this._elements = this._buildPanel(parentElement);
        this._addEventListeners();
    }

    /**
     * Cleans up the OffCanvas component by removing its panel and overlay elements from the DOM,
     * and detaches event listeners for closing the panel.
     *
     * @remarks
     * This method should be called when the OffCanvas component is no longer needed to prevent memory leaks.
     */
    destroy(): void {
        this._elements.body.innerHTML = "";
        this._removeEventListeners();
        this._elements.panel.remove();
    }

    /**
     * Displays the off-canvas panel with the specified content.
     *
     * Clears any existing content in the panel body and inserts the provided content.
     * If the content is an `HTMLElement` or `DocumentFragment`, it is appended directly.
     * Otherwise, the content is set as the inner HTML of the panel body.
     * Also adds the "show" class to both the panel and overlay elements to make them visible.
     *
     * @param content - The content to display inside the panel. Can be a string, HTMLElement, or DocumentFragment.
     */
    show = (content: string | HTMLElement | DocumentFragment): void => {
        this._elements.body.innerHTML = "";
        if (content instanceof HTMLElement || content instanceof DocumentFragment) {
            this._elements.body.append(content);
        } else {
            this._elements.body.innerHTML = content;
        }
        this._elements.panel.showModal(); // Show the dialog as a modal
        this._elements.panel.classList.add("show");
    }

    /**
     * Hides the off-canvas panel and overlay by removing the "show" class from their elements.
     * After a delay specified by `HIDE_TIMEOUT`, clears the inner HTML content of the panel body.
     *
     * @returns {void}
     */
    hide = (): void => {
        this._elements.panel.classList.remove("show");
        setTimeout(() => {
            this._elements.panel.close(); // Close the dialog
            this._elements.body.innerHTML = "";
        }, this.HIDE_TIMEOUT);
    }

    /**
     * Builds and appends an off-canvas panel, its body, close button, and overlay to the specified parent element.
     *
     * @param parentElement - The HTML element to which the panel and overlay will be appended.
     * @returns An object containing references to the created panel, body, close button, and overlay elements.
     *
     * @remarks
     * - The panel and overlay are appended to the parent element.
     * - The close button and overlay are both wired to trigger the `hide` method when clicked.
     * - CSS classes and SVG icons are applied based on the current settings.
     */
    private _buildPanel = (parentElement: HTMLElement): typeof this._elements => {
        const panel = document.createElement('dialog');
        panel.classList.add(...this.settings.classLists.panel);
        // panel.setAttribute('closedby', 'any');
        parentElement.append(panel);
        const body = document.createElement('div');
        body.classList.add(...this.settings.classLists.body);
        const closeBtn = document.createElement('button');
        closeBtn.classList.add(...this.settings.classLists.closeBtn);
        closeBtn.append(svgFromId(this.settings.svg.closeBtn))
        panel.append(closeBtn, body)
        parentElement.append(panel);
        return {
            panel: panel,
            body: body,
            closeBtn: closeBtn
        }
    }

    private _handleBackdropContextMenu = (event: MouseEvent): void => {
        if (event.target === this._elements.panel) {
            event.preventDefault();
        }
    }

    private _handleBackdropMouseDown = (event: MouseEvent): void => {
        if (event.target === this._elements.panel) {
            if (event.button !== 2) { // Not right mouse button
                this.hide();
            } else {
                event.preventDefault(); // Prevent default context menu on right click
            }
        }
    }

    private _addEventListeners = (): void => {
        this._elements.panel.addEventListener('contextmenu', this._handleBackdropContextMenu);
        this._elements.panel.addEventListener('mousedown', this._handleBackdropMouseDown);
        this._elements.closeBtn.addEventListener("click", this.hide);
    }

    private _removeEventListeners = (): void => {
        this._elements.panel.removeEventListener('contextmenu', this._handleBackdropContextMenu);
        this._elements.panel.removeEventListener('mousedown', this._handleBackdropMouseDown);
        this._elements.closeBtn.removeEventListener("click", this.hide);
    }
}