import mapboxgl from 'mapbox-gl';
import type { 
    CoordsPopupSettings, 
    FeatureLayerSettings, 
    FitBoundsSettings, 
    HelpControlSettings, 
    LocationServicesSettings, 
    RouteSettings, 
    SearchSettings, 
    ShareControlSettings, 
    StyleControlSettings, 
    Terrain 
} from './settings/index.js';
import type { MapStyle } from './controls/style.js';

export * from './settings/index.js';
export interface Settings {
    mapStyles?: MapStyle[];
    terrain: Terrain;
    route: RouteSettings;
    search: SearchSettings;
    featureLayers: FeatureLayerSettings;
    shareControl?: ShareControlSettings;
    styleControl?: StyleControlSettings;
    helpControl?: HelpControlSettings;
    locationServices?: LocationServicesSettings;
    limitToCountry?: string;
    fitBounds?: FitBoundsSettings;
    coordsPopup: {
        popupOptions: CoordsPopupSettings;
        markerOptions?:  mapboxgl.MarkerOptions;
    }
    caption: {
        html?: string; // html to display underneath the map
        classList: string;
    };
    loadSpritesheet?: {
        path: string;
        id?: string;
    }
    debug: boolean; // draw bounds, padding etc, verbose actions to console log
};