import mapboxgl from 'mapbox-gl';
import type { MapStyle, StyleControlSettings } from '../types.js';
import { getActiveStyleUrl, isStyleLoaded } from '../utility/utility.js';
import { StyleUrl } from '../url/Url.js';

/**
 * Represents the possible states of the style control UI component.
 *
 * @enum {string}
 * @property {string} Loading - Indicates the style control is currently loading resources or data.
 * @property {string} Ready - Indicates the style control is ready for user interaction.
 * @property {string} Expanded - Indicates the style control is expanded to show additional options or details.
 * @property {string} Busy - Indicates the style control is performing an operation and may not be responsive.
 */
export enum StyleControlState {
    Loading = 'loading',
    Ready = 'ready',
    Expanded = 'expanded',
    Busy = 'busy'
}

/**
 * A Mapbox GL JS control that allows users to switch between multiple map styles using a visual tile-based UI.
 *
 * The `StyleControl` displays a set of style tiles (images) representing available map styles. Users can click or tap a tile to switch the map's style.
 * The control manages its own UI state (loading, ready, expanded & busy) and updates the active style indicator as the map style changes.
 *
 * @typedef {Object} MapStyle
 * @property {string} title - Displayed in the style selector.
 * @property {string} source - Mapbox style source URL.
 * @property {string} tileImageSrc - URL for a static preview image of the style.
 *
 * @typedef {Object} StyleControlSettings
 * @property {boolean} show - Optional. Show the control if true otherwise, render an empty container.
 * @property {string[]} mapStyleContainerClassList - Optional. CSS classes to apply to the container.
 * @property {boolean} [enableUrlSharing] - Optional. If true, write the selected style index to the URL.
 * 
 * @param {MapStyle[]} styles - The available map styles.
 * 
 * - {string} title - Displayed in the style selector.
 * - {string} source - Mapbox style source URL.
 * - {string} tileImageSrc - Static image of the style.
 * 
 * @param {StyleControlSettings} settings - Optional. Control settings (visibility, styling, URL sharing).
 * 
 * - {boolean} show - Optional. Show the control if true otherwise, render an empty container.
 * - {string[]} mapStyleContainerClassList - Optional. CSS classes for the control container in addition to control and state css classes.
 * - {boolean} [enableUrlSharing] - Optional. Write the selected style index to the URL if not zero.
 * 
 * @param {boolean} [debug=false] - Whether to enable debug logging.
 * 
 * @remarks
 * - Requires at least two styles to be provided; otherwise, the control will not be added.
 * - Defaults to 'bottom-right' control position, overrideable.
 * - States add appropriate css classes to the control container: 'stylecontrol--loading', 'stylecontrol--ready', 'stylecontrol--expanded'.
 * - Busy state prevents disables the style changer and can be used to prevnt reloading map styles while another process requires a loaded style.
 * - Active style image tile will get additional 'stylecontrol--loading' helper css class for interaactive display.
 * - enableUrlSharing setting will write the styleIndex to url search parameter "s" if not 0 using StyleUrl helper class also defined in this module..
 * - Handles pointer, touch, and mouse events for interaction.
 * - Supports debug logging for development purposes.
 *
 * @example
 * ```typescript
 * const styles: MapStyle[] = [
 *   { source: 'mapbox://styles/mapbox/streets-v12', tileImageSrc: 'streets.png', title: 'Streets' },
 *   { source: 'mapbox://styles/mapbox/satellite-v12', tileImageSrc: 'satellite.png', title: 'Satellite' }
 * ];
 * const styleControl = new StyleControl(styles, { mapStyleContainerClassList: ['custom-style-control'] }, true);
 * map.addControl(styleControl, 'bottom-right');
 * ```
 *
 * @implements {mapboxgl.IControl}
 */
export default class StyleControl implements mapboxgl.IControl {
    private _map?: mapboxgl.Map;
    private _container!: HTMLDivElement;
    private _styleTiles: HTMLElement[] = [];
    private _activeTile?: HTMLElement;
    private _state: StyleControlState = StyleControlState.Loading;
    private readonly stateClasses = {
        [StyleControlState.Loading]: ['stylecontrol--loading'],
        [StyleControlState.Ready]: ['stylecontrol--ready'],
        [StyleControlState.Expanded]: ['stylecontrol--ready', 'stylecontrol--expanded'],
        [StyleControlState.Busy]: ['stylecontrol--busy'],
    };

    constructor(private readonly styles: MapStyle[], private readonly settings: StyleControlSettings = {}, private readonly debug: boolean = false) { }

    /**
     * Adds the style control to the given Mapbox map instance.
     *
     * This method creates the control's container element and populates it with style tiles
     * if multiple styles are available. It initializes the control and sets up the internal state.
     * If fewer than two styles are provided, the control is not added and a warning is logged in debug mode.
     *
     * @param map - The Mapbox map instance to which the control will be added.
     * @returns The HTML container element for the control.
     */
    onAdd(map: mapboxgl.Map): HTMLElement {
        this._container = document.createElement('div');
        if (!this.settings.show) return this._container;
        this._map = map;
        this.state = StyleControlState.Loading;
        if (this.styles.length > 1) {
            try {
                this._container.classList.add('mapboxgl-ctrl', 'mapboxgl-ctrl-group', ...(this.settings.mapStyleContainerClassList ?? []));
                this.styles.forEach((style, index) => {
                    const template = document.createElement('template');
                    template.innerHTML = style.tileImageHTML.trim();
                    const styleTile = template.content.firstElementChild as HTMLElement;
                    styleTile.title = style.title;
                    styleTile.dataset.styleIndex = index.toString();
                    this._container.append(styleTile);
                    this._styleTiles.push(styleTile);
                });
                if (this.debug) console.debug("StyleControl: Control initialized with styles:", this.styles);
                this._initializeControl();
            } catch (error) {
                if (this.debug) {
                    console.error("StyleControl: Error initializing control:", error);
                }
            }
        } if (this.debug) {
            console.warn("StyleControl: Minimum 2 styles are required. No control will be added.");
        }

        return this._container;
    }

    /**
     * Initializes the style control by setting up event listeners and updating the control state.
     * 
     * - Checks if the map instance is available; if not, exits early.
     * - If the control container exists:
     *   - Waits for the map style to load if it hasn't already, then re-invokes initialization.
     *   - Sets the active tile and attaches event listeners for pointer, touch, and mouse events.
     *   - Updates the control state to `Ready`.
     * - If the container is missing and debug mode is enabled, logs a warning to the console.
     *
     * @private
     * @returns {void}
     */
    private _initializeControl = (): void => {
        if (!this._map) return;
        if (this._container) {
            if (!isStyleLoaded(this._map)) {
                this._map.once('style.load', this._initializeControl);
                return;
            }
            this._setActiveTile();
            this._container.addEventListener('pointerdown', this._onPointerDown);
            this._container.addEventListener('touchstart', this._onTouchStart);
            this._container.addEventListener('mouseenter', this._onMouseEnter);
            this._container.addEventListener('mouseleave', this._onMouseLeave);
            this.state = StyleControlState.Ready;
        } else {
            if (this.debug) {
                console.warn("StyleControl: Control not initialized. Call onAdd() first.");
            }
        }
    }

    /**
     * Sets the map style based on the provided tile element.
     * 
     * This method checks if the control is not busy, retrieves the style index from the tile's dataset,
     * and applies the corresponding style to the map. It also updates the active tile and, if URL sharing
     * is enabled in the settings, updates the URL to reflect the selected style.
     * 
     * @param tile - The HTML element representing the style tile that was selected.
     */
    private _setMapStyleFromTile = (tile: HTMLElement): void => {
        if (this.state === StyleControlState.Busy) return;
        const styleIndex = parseInt(tile.dataset.styleIndex ?? "");
        if (styleIndex !== undefined) {
            const style: MapStyle | undefined = this.styles[styleIndex];
            if (style) {
                this._map!.setStyle(style.source);
                this._setActiveTile(tile);
                if (this.settings.enableUrlSharing) {
                    StyleUrl.setURL(styleIndex, this.debug);
                }
            }
        }
    }

    /**
     * Sets the currently active style tile in the style control UI.
     * 
     * If a specific tile element is provided, it will be set as active.
     * If no tile is provided, the method attempts to determine the active tile
     * based on the current style URL of the map. If the current style is not found
     * in the styles array, the first tile is set as active by default.
     * 
     * The method updates the visual state by removing the 'stylecontrol--active'
     * class from the previously active tile and adding it to the new active tile.
     * 
     * @param tile - The HTMLElement representing the style tile to set as active. If omitted, the active tile is determined automatically.
     */
    private _setActiveTile = (tile?: HTMLElement): void => {
        if (!tile) {
            const styleUrl = getActiveStyleUrl(this._map!);
            const currentStyleIndex: number = this.styles.findIndex(s => s.source === styleUrl);
            tile = this._styleTiles[currentStyleIndex];
            if (!tile) {
                console.warn("StyleControl: Current style not found in styles array.");
                tile = this._styleTiles[0];
            }
        }
        this._activeTile?.classList.remove('stylecontrol--active');
        this._activeTile = tile;
        this._activeTile.classList.add('stylecontrol--active');
    }

    /**
     * Handles the pointer down event on style tiles.
     * 
     * - Ignores the event if the control is in the `Busy` state.
     * - Determines if the pointer event target is an image tile and not the currently active tile.
     * - If a valid style index is found on the clicked tile, blurs the container and updates the map style.
     * 
     * @param event - The pointer event triggered by user interaction.
     */
    private _onPointerDown = (event: PointerEvent): void => {
        if (this.state === StyleControlState.Busy) return;
        const clickedTile = (event.target as HTMLElement).closest("img");
        if (clickedTile && clickedTile !== this._activeTile) {
            const styleIndex = parseInt(clickedTile.dataset.styleIndex ?? "");
            if (styleIndex !== undefined) {
                this._container.blur();
                this._setMapStyleFromTile(clickedTile);
            }
        }
    }
    /**
     * Handles the mouse enter event for the style control.
     * 
     * If the control is not in the `Busy` state, sets its state to `Expanded`.
     * Prevents state change if the control is currently busy.
     *
     * @private
     */
    private _onMouseEnter = (): void => {
        if (this.state === StyleControlState.Busy) return;
        this.state = StyleControlState.Expanded;
    }

    /**
     * Handles the mouse leave event for the style control.
     * 
     * Sets the control's state to `Ready` when the mouse leaves the control area.
     * 
     * @private
     */
    private _onMouseLeave = (): void => {
        this.state = StyleControlState.Ready;
    }

    /**
     * Handles the touch start event for the style control.
     *
     * - If the control is in the `Busy` state, the event is ignored.
     * - If the touch event originates from an `<img>` element or its descendant,
     *   toggles the control's state between `Expanded` and `Ready`.
     *
     * @param event - The touch event triggered by the user interaction.
     */
    private _onTouchStart = (event: TouchEvent): void => {
        if (this.state === StyleControlState.Busy) return;
        if ((event.target as HTMLElement).closest("img")) {
            this.state = (this.state === StyleControlState.Expanded) ? StyleControlState.Ready : StyleControlState.Expanded;
        }
    }

    /**
     * Removes the style control from the map and cleans up resources.
     * 
     * This method removes the control's container from the DOM, clears the map reference,
     * resets the style tiles array, and removes all event listeners associated with the control.
     * 
     * @returns {void}
     */
    onRemove(): void {
        if (this._container.parentNode) {
            this._container.parentNode.removeChild(this._container);
        }
        this._map = undefined;
        this._styleTiles = [];
        this._container.removeEventListener('pointerdown', this._onPointerDown);
        this._container.removeEventListener('touchstart', this._onTouchStart);
        this._container.removeEventListener('mouseenter', this._onMouseEnter);
        this._container.removeEventListener('mouseleave', this._onMouseLeave);
        this._container = undefined!;
        if (this.debug) console.debug('StyleControl: removed');
    }

    getDefaultPosition(): mapboxgl.ControlPosition {
        return 'bottom-left';
    }

    // --- state management ---

    /**
     * Gets or sets the current state of the style control.
     * 
     * The state can be one of the following:
     * - `Loading`: The control is loading resources.
     * - `Ready`: The control is ready for user interaction.
     * - `Expanded`: The control is expanded to show additional options.
     * - `Busy`: The control is performing an operation and may not be responsive.
     *
     * @returns {StyleControlState} The current state of the style control.
     */
    get state(): StyleControlState {
        return this._state;
    }

    /**
     * Sets the state of the style control and updates the UI accordingly.
     * 
     * This method updates the control's container class list based on the new state,
     * sets ARIA attributes for accessibility, and logs the state change if debug mode is enabled.
     * 
     * @param {StyleControlState} newState - The new state to set for the style control.
     */
    set state(newState: StyleControlState) {
        const oldState = this._state;
        if (oldState === newState) return;
        this._container?.classList.remove(...this.stateClasses[oldState]);
        this._container?.classList.add(...this.stateClasses[newState]);
        this._container.setAttribute('aria-expanded', `${newState === StyleControlState.Expanded}`);
        this._container.setAttribute('aria-busy', `${newState === StyleControlState.Busy}`);
        this._state = newState;
        if (this.debug) {
            console.debug(`StyleControl: State changed from ${oldState} to ${newState}`);
        }
    }
}


