import mapboxgl from 'mapbox-gl';
import axios from 'axios';
import FitBounds from '../bounds/Bounds.js';
import MapboxAssist from '../MapboxAssist.js';
import RouteForm from './Form.js';
import RouteSummary from './Summary.js';
import { CameraUrl, RouteUrl } from '../url/Url.js';
import type { 
    Coordinates, CoordinatesArray, DirectionsParameters, DirectionsResponse, LayerDefinition, 
    RouteData, RouteLegData, RouteParameters, RouteSettings, Waypoint, WayPoints 
} from '../types.js';
import type { FeatureCollection, LineString, Point as GeoJsonPoint } from 'geojson';
import { FeatureLayerManager } from '../feature/Feature.js';
import { getMapboxAccessToken, isStyleLoaded } from '../utility/utility.js';
import { MAPBOX } from '../constants.js';
import Toast from '../widgets/Toast.js';


/**
 * Represents a route manager for Mapbox maps, providing functionality to display, update, and interact with routes and waypoints.
 * 
 * The `Route` class extends `EventTarget` and encapsulates the logic for:
 * - Managing waypoints and route parameters.
 * - Fetching and displaying routes using the Mapbox Directions API.
 * - Handling both routable and non-routable waypoints, with straight-line fallbacks.
 * - Managing map layers and sources for routes, endpoints, and waypoints.
 * - Integrating with UI components such as route forms and summaries.
 * - Supporting URL sharing, elevation profiles, and custom event emission for route-related actions.
 * - Handling map style reloads and maintaining route state across style changes.
 * - Providing mouse interaction for waypoint features.
 * 
 * @remarks
 * - The class is tightly coupled with Mapbox GL JS and expects a `MapboxAssist` instance for map and settings access.
 * - It supports both API-driven and straight-line routes, with a maximum of 25 waypoints for routed paths.
 * - Custom events are dispatched for key actions (e.g., waypoints updated, directions returned, fit bounds complete).
 * - Debug logging is available via the `debug` flag.
 * 
 * @example
 * ```typescript
 * const route = new Route(mapboxAssistInstance, { waypoints: [...] }, fitBoundsInstance);
 * route.addToMap();
 * ```
 * 
 * @fires routeStyleLock - Emitted when the route locks or unlocks the map style.
 * @fires waypointsUpdated - Emitted when waypoint labels are updated.
 * @fires waypointsReady - Emitted when waypoints are ready for display.
 * @fires directionsReturned - Emitted when directions data is fetched or generated.
 * @fires fitBoundsEnd - Emitted when the map has finished fitting the route bounds.
 * 
 * @public
 */
export default class Route extends EventTarget {
    routeData?: RouteData;
    routeSummary?: RouteSummary;
    routeForm?: RouteForm;
    waypoints: WayPoints = [];
    map: mapboxgl.Map;
    mapContainer: HTMLElement;
    mapWrapper: HTMLElement;
    mapOptions: Partial<mapboxgl.MapOptions>;
    featureLayerManager: FeatureLayerManager;
    settings: RouteSettings;
    showElevationProfile?: boolean;
    private routeLayers: LayerDefinition[] = [];

    private _fitToScreen: boolean = false; // flag that denotes if displayed route has been fitted to screen
    private hoveredFeatureId: string | number | null = null;
    private mouseenterHandler?: (e: mapboxgl.MapMouseEvent) => void;
    private mouseleaveHandler?: () => void;

    /**
     * Constructs a new Route instance with the provided MapboxAssist instance and route parameters.
     * Initializes map properties, settings, and event listeners for style loading.
     *
     * @param mapboxAssist - An instance of MapboxAssist that provides access to the map and its features.
     * @param parameters - Optional route parameters including waypoints and route type.
     * @param fitBounds - An instance of FitBounds to manage map bounds fitting.
     */
    constructor(private readonly mapboxAssist: MapboxAssist, public parameters: RouteParameters = { waypoints: [] }, private fitBounds: FitBounds, private readonly debug: boolean = false) {
        super();
        ({ 
            map: this.map, 
            mapContainer: this.mapContainer, 
            mapWrapper: this.mapWrapper, 
            mapOptions: this.mapOptions, 
            featureLayerManager: this.featureLayerManager,
        } = this.mapboxAssist);
        this.settings = this.mapboxAssist.settings.route;

        if (this.debug) console.debug('Route: initialized with parameters:', this.parameters);
        // load from url parameters if no waypoints provided
        if (this.settings.enableUrlSharing && !parameters.waypoints?.length) {
            const routeFromURL = RouteUrl.getURL(this.debug);
            if (routeFromURL) {
                this.parameters = routeFromURL;
                if (this.debug) console.debug('Route: URL parameters loaded:', routeFromURL);
            }
        }
        this.routeSummary = new RouteSummary(this, this.debug);
        if (isStyleLoaded(this.map)) {
            this.onInitialStyleLoad();
        } else {
            this.map.once("style.load", this.onInitialStyleLoad);
        }
    }

    /**
     * Handles the initial loading of the map's style.
     * 
     * - Retrieves the waypoint layer specification.
     * - Adds the route to the map if there are more than one waypoint.
     * - Initializes the route form if the form setting is enabled.
     * - Registers a listener for subsequent "style.load" events to handle style reloads.
     *
     * @private
     */
    private onInitialStyleLoad = (): void => {
        this.getWaypointLayerSpecification();
        if ((this.parameters.waypoints ?? []).length > 1) this.addToMap();
        if (this.settings.form.show) this.routeForm = new RouteForm(this, this.debug);
        this.map.on("style.load", this.onStyleLoad);
    }
    
    /**
     * Callback invoked when the map's style has finished loading.
     * Adds custom map layers and retrieves the specification for the waypoint layer.
     *
     * @private
     */
    private onStyleLoad = (): void => {
        this.addMapLayers();
        this.getWaypointLayerSpecification();
    }

    /**
     * Cleans up and destroys the route instance by:
     * - Clearing any internal state.
     * - Removing the "style.load" event listener from the map.
     * - Removing waypoint interaction handlers.
     * - Destroying and dereferencing the route summary and route form components.
     * - Logging the destruction if debug mode is enabled.
     */
    destroy(): void {
        this.clear();
        this.map.off("style.load", this.onStyleLoad);
        this.removeWaypointInteraction();
        this.routeSummary?.destroy();
        this.routeSummary = undefined;
        this.routeForm?.destroy();
        if (this.debug) console.debug('Route: destroyed');
    }

    /**
     * Clears the current route state, including map layers, route data, waypoints, and summary.
     * Also updates the waypoint layer source, resets the fit-to-screen flag, and manages URL sharing state.
     * If debugging is enabled, logs the clear action to the console.
     */
    clear(): void {
        this.removeMapLayers();
        this.routeData = undefined;
        this.waypoints = [];
        this.routeSummary?.clear();
        this.updateWaypointLayerSource([]);
        this._fitToScreen = false;
        if (this.settings.enableUrlSharing) {
            RouteUrl.clearURL();
            CameraUrl.setURL(this.map, this.debug);
        };
        if (this.debug) console.debug('Route: cleared');
    }

    /**
     * Emits a custom "routeStyleLock" event with the specified lock state. Used by MapboxAssist class to 
     * prevent changes to the map style while the route is being drawn.
     *
     * @param value - A boolean indicating whether the route style is locked (`true`) or unlocked (`false`).
     * @remarks
     * This method creates and dispatches a `CustomEvent` named "routeStyleLock" with the lock state
     * provided in the `detail` property of the event. Listeners can use this event to react to changes
     * in the route style lock status.
     */
    private _emitStyleLock = (value: boolean): void => {
        const routeStyleLockEvent = new CustomEvent("routeStyleLock", { detail: value });
        this.dispatchEvent(routeStyleLockEvent);
    }

    /**
     * Adds the current route to the Mapbox map based on the provided waypoints and parameters.
     * 
     * - Validates that at least two waypoints are present; otherwise, logs a warning and exits.
     * - Limits the number of waypoints to 25, as per Mapbox Directions API constraints, and logs a warning if exceeded.
     * - 25 point limit is not applied for point-to-point routes (i.e route type undefined) as no call to the api is made for this type.
     * - Checks for a valid Mapbox access token; if missing, disables routeType and logs a warning.
     * - Clears any existing route from the map before adding a new one.
     * - If a valid `routeType` is set and at least one pair of consecutive routable waypoints exists, 
     *   adds a routed path to the map; otherwise, falls back to a straight line route.
     * - Optionally renders route summary information if enabled.
     * - Updates the URL for sharing if the form and URL sharing are enabled.
     * 
     * @remarks
     * This method is asynchronous in effect, as it uses `queueMicrotask` to defer route rendering and summary updates.
     * 
     * @throws Does not throw, but logs warnings for invalid state or configuration.
     */
    public addToMap(): void {
        if (!this.parameters.waypoints || (this.parameters.waypoints ?? []).length < 2) {
            console.warn('Route: At least two waypoints are required to create a route.');
            return;
        }
        if ((this.parameters.waypoints ?? []).length > MAPBOX.MAX_DIRECTIONS_WAYPOINTS && this.parameters.routeType) {
            Toast.show(this.mapContainer, this.settings.waypointCountWarning.message, this.settings.waypointCountWarning.duration);
            console.warn(`Route: More than ${MAPBOX.MAX_DIRECTIONS_WAYPOINTS} waypoints is not supported by Mapbox Directions API. Showing route for first ${MAPBOX.MAX_DIRECTIONS_WAYPOINTS} waypoints only.`);
            this.parameters.waypoints = this.parameters.waypoints.slice(0, MAPBOX.MAX_DIRECTIONS_WAYPOINTS);
        }
        if (!(this.mapOptions.accessToken || getMapboxAccessToken()) && this.parameters.routeType) {
            console.warn('Access token is required to use Mapbox route facilities, defaulting to point-to-point route instead.');
            this.parameters.routeType = undefined;
        }
        this.clear();

        // only show elevation profile if all factors allow
        this.showElevationProfile = (
            (this.parameters.showElevationProfile ?? this.settings.summary.elevationProfile.show) &&
            this.parameters.showSummary === "detailed" &&
            this.mapboxAssist.settings.terrain.enable
        );

        queueMicrotask(async () => {
            this.parameters.waypoints = await this.updateWaypointLabels(this.parameters.waypoints!);
            const waypointEvent = new CustomEvent("waypointsUpdated", {});
            this.dispatchEvent(waypointEvent);
            if (this.settings.form.show && this.settings.enableUrlSharing) {
                RouteUrl.setURL(this.parameters, this.debug);
            }
        });
        queueMicrotask(async () => {
            if (this.parameters.routeType) {
                const hasRoutablePair = this.parameters.waypoints!.some((w, i, arr) =>
                    i > 0 && w.isRoutable !== false && arr[i - 1].isRoutable !== false
                );
                if (hasRoutablePair) {
                    this.addRouteToMap();
                    return;
                } else {
                    if (this.debug) console.debug("Route.addToMap(): No routable pairs found, switching to straight line mode.")
                }
            }
            this.parameters.routeType = undefined;
            this.addStraightLineRouteToMap();
        });
        if (this.parameters.showSummary) {
            queueMicrotask(() => {
                this.routeSummary!.renderRouteInformation();
            });
        }
    }

    /**
     * Adds the route's map layers and sources to the Mapbox map instance.
     *
     * - Iterates through each route layer definition in `this.routeLayers`.
     * - Adds a GeoJSON source to the map if it does not already exist.
     * - Adds the corresponding layer to the map if it does not already exist.
     * - Moves the waypoints layer (identified by `MAPBOX.WAYPOINTS_LAYER_ID`) to the top if it exists.
     *
     * @remarks
     * This method is called after the route is calculated and ready to be displayed on the map, and
     * whenever the map style is changed to ensure that the route layers are correctly applied.
     * It also logs the addition of layers if debug mode is enabled.
     * 
     * @returns {void}
     * @private
     */
    private addMapLayers(): void {
        if (this.debug) console.debug('Route: Adding map layers', this.routeLayers);
        this.routeLayers.forEach(definition => {
            if (!this.map.getSource(definition.source.id)) {
                this.map.addSource(definition.source.id, {
                    type: 'geojson',
                    data: definition.source.geoJsonData
                });
            }
            if (!this.map.getLayer(definition.layer.id)) {
                this.map.addLayer(definition.layer);
            }
        });
        if (this.map.getLayer(MAPBOX.WAYPOINTS_LAYER_ID))
            this.map.moveLayer(MAPBOX.WAYPOINTS_LAYER_ID);
    }

    /**
     * Removes all map layers and sources associated with the current route from the map instance.
     * Iterates through each layer and source definition in `routeLayers`, checks for their existence
     * on the map, and removes them if present. Optionally logs removal actions if debug mode is enabled.
     * After removal, clears the `routeLayers` array.
     * 
     * @remarks
     * Called whenever the map style is changed or when the route is cleared.
     *
     * @private
     */
    private removeMapLayers(): void {
        this.routeLayers.forEach(definition => {
            if (!!this.map.getLayer(definition.layer.id)) {
                this.map.removeLayer(definition.layer.id);
                if (this.debug) console.debug('Removed layer:', definition.layer.id);
            }
            if (!!this.map.getSource(definition.source.id)) {
                this.map.removeSource(definition.source.id);
                if (this.debug) console.debug('Removed source:', definition.source.id);
            }
        });
        this.routeLayers = [];
    }
    
    /**
     * Adds the calculated route to the map by fetching directions, processing route data,
     * handling non-routable waypoints with straight line fallbacks, and drawing the route.
     * 
     * - Emits a style lock event while processing.
     * - Fetches directions asynchronously and updates internal route data.
     * - Applies straight line fallback for legs with non-routable waypoints.
     * - Dispatches "directionsReturned" and "waypointsReady" custom events.
     * - Updates waypoint labels and internal waypoint state.
     * - Draws the route on the map using step coordinates, ensuring no duplicate points.
     * - Handles map style loading state before drawing.
     * - Emits a style unlock event after processing or on error.
     * - Logs route data if debug mode is enabled.
     * 
     * @private
     * @throws {Error} If route data cannot be returned or processed.
     */
    private addRouteToMap(): void {
        this._emitStyleLock(true);
        this.fetchDirections().then(async (data) => {
            try {
                this.routeData = data.routes[0];
                // replace any legs touching a non-routable waypoint with straight line data
                this.applyStraightLineFallback();

                const directionsEvent = new CustomEvent("directionsReturned", { detail: data.routes[0] });
                this.dispatchEvent(directionsEvent);

                if (this.debug) {
                    console.debug('Directions API route data:', this.routeData)
                }
                this.waypoints = await this.updateWaypointLabels(this.parameters.waypoints!);
                this.waypoints = this.parameters.waypoints!;
                const waypointEvent = new CustomEvent("waypointsReady", {});
                this.dispatchEvent(waypointEvent);

                const stepCoordinates: CoordinatesArray = this.routeData!.legs
                    .flatMap(leg => leg.steps.flatMap(step => step.geometry.coordinates))
                    .filter((coord, index, array) =>
                        index === 0 || Math.abs(coord[0] - array[index - 1][0]) > 1e-6 || Math.abs(coord[1] - array[index - 1][1]) > 1e-6
                    );

                const drawRouteWithCoords = () => {
                    this.drawRoute(stepCoordinates)
                    this._emitStyleLock(false);
                };

                if (isStyleLoaded(this.map)) {
                    drawRouteWithCoords();
                } else {
                    this.map.once('style.load', drawRouteWithCoords);
                }
            } catch (error) {
                this._emitStyleLock(false);
                throw new Error(`Failed to return route data: ${error}`)
            }
        }).catch((error) => { console.error(error); return; });
    }

    /**
     * Fetches route directions from the Mapbox Directions API based on the current route parameters and settings.
     *
     * Constructs the API request URL and parameters, including geometry format, step-by-step instructions,
     * and access token. If the route type is "walking", applies additional walking-specific parameters.
     * Sends a GET request to the API and validates that the response contains step data.
     *
     * @returns {Promise<DirectionsResponse>} A promise that resolves to the directions response from the API.
     * @throws {Error} If the API response does not contain step data or if the request fails.
     */
    private async fetchDirections(): Promise<DirectionsResponse> {
        const apiParams: DirectionsParameters = {
            geometries: 'geojson',
            steps: true,
            access_token: this.mapOptions.accessToken || getMapboxAccessToken()
        };

        if (this.parameters.routeType === "walking") {
            apiParams.walkway_bias = 1;
            apiParams.walking_speed = this.settings.directionsAPI.walking_speed;
        }

        const pointsString: string = this.parameters.waypoints!.map(
            (coord: Waypoint) => [coord.longitude, coord.latitude].join()
        ).join(";");


        let url: string = MAPBOX.DIRECTIONS_API_URL;
        if (!url.endsWith('/')) url += '/';
        url += this.parameters.routeType!;
        url += `/${pointsString}/`;

        try {
            const { data } = await axios.get(url, { params: apiParams });
            // Validate that we received step data
            if (!data.routes?.[0]?.legs?.[0]?.steps) {
                throw new Error('No step data received from directions API');
            }
            return data;
        } catch (error) {
            console.error('Error fetching directions:', error);
            throw error;
        }
    }

    /**
     * Applies a straight-line fallback to route legs that are explicitly marked as non-routable.
     *
     * This method iterates through the route legs and checks if either the start or end waypoint
     * of a leg is marked as non-routable (`isRoutable === false`). For such legs, it replaces the
     * leg with a single "fake" step representing a straight line between the two waypoints,
     * calculating the distance and setting the duration based on the configured walking speed.
     *
     * If any non-routable waypoints are found, the overall route geometry is rebuilt by
     * concatenating the coordinates of all steps, ensuring the map bounds reflect the updated route.
     *
     * @private
     * @throws {Error} Throws an error if the fallback process fails.
     */
    private applyStraightLineFallback = (): void => {
        if (!this.routeData) return;

        let hasNonRoutable: boolean = false;

        const legs = this.routeData.legs;
        const wps = this.parameters.waypoints!;

        try {
            legs.forEach((leg, idx) => {
                const startWp = wps[idx];
                const endWp = wps[idx + 1];

                // Only override if explicitly non-routable (undefined or true = routable)
                if (startWp.isRoutable === false || endWp.isRoutable === false) {
                    hasNonRoutable = true;
                    const start = new mapboxgl.LngLat(startWp.longitude, startWp.latitude);
                    const end = new mapboxgl.LngLat(endWp.longitude, endWp.latitude);
                    const dist = start.distanceTo(end);

                    legs[idx] = {
                        // Single “fake” step
                        steps: [{
                            maneuver: {
                                location: [start.lng, start.lat],
                                instruction: ''
                            },
                            geometry: {
                                coordinates: [
                                    [start.lng, start.lat],
                                    [end.lng, end.lat]
                                ]
                            },
                            duration: 0,
                            distance: dist,
                            name: startWp.name ?? ""
                        }],
                        duration: dist / this.settings.directionsAPI.walking_speed,
                        distance: dist
                    };
                }

                // rebuild the route geometry if any waypoins not routable, used to set the map bounds
                if (hasNonRoutable) {
                    const steps = this.routeData!.legs.flatMap(leg => leg.steps);
                    this.routeData!.geometry.coordinates = steps.flatMap(step => step.geometry.coordinates);

                }
            });
        } catch (error) {
            console.error('Error applying straight line fallback:', error);
            throw new Error('Failed to apply straight line fallback');
        }
    }

    /**
     * Draws the route on the map using the provided step coordinates.
     *
     * This method updates the route and endpoint layers, refreshes the waypoint layer source,
     * and fits the map view to the bounds of the route. It also handles debug logging and
     * dispatches a custom event when the fit-to-bounds operation is complete.
     *
     * @param stepCoordinates - An array of coordinates representing the steps of the route.
     */
    private drawRoute(stepCoordinates: CoordinatesArray): void {
        queueMicrotask(() => {
            this.routeLayers = [
                this.getEndpointLayerSpecification(
                    stepCoordinates[0],
                    stepCoordinates.at(-1)!
                ),
                this.getRouteLayerSpecification(stepCoordinates),
            ];
            this.updateWaypointLayerSource();

            if (this.debug) {
                console.debug('Route Layer Specifications:', this.routeLayers)
            }

            this.addMapLayers()

            this.fitBounds.points = this.routeData!.geometry.coordinates;
            const fitBoundsEvent = new CustomEvent("fitBoundsEnd", {});
            const fitBoundsHandler = () => {
                this._fitToScreen = true;
                this.dispatchEvent(fitBoundsEvent);
                if (this.debug) console.debug('Route fitBounds complete');
                this.fitBounds.removeEventListener('fitScreenBoundsEnd', fitBoundsHandler);
            };
            this.fitBounds.addEventListener('fitScreenBoundsEnd', fitBoundsHandler);
            this.fitBounds.fitScreenBounds();
        })
    }

    /**
     * Adds a straight-line route to the map using the current waypoints.
     * 
     * This method ensures the map style is loaded before proceeding. It updates waypoint labels,
     * generates straight-line route data, and dispatches relevant custom events (`waypointsReady`, `directionsReturned`).
     * The method then prepares and adds the necessary map layers for the route and endpoints.
     * 
     * After updating the map, it fits the route within the map bounds and dispatches a `fitBoundsEnd` event
     * when the fitting is complete. Debug information is logged if enabled.
     * 
     * @private
     * @returns {void}
     */
    private addStraightLineRouteToMap(): void {
        queueMicrotask(async () => {
            if (!isStyleLoaded(this.map)) {
                this.map.once("style.load", () => {
                    this.addStraightLineRouteToMap();
                });
                return;
            }
            this.waypoints = await this.updateWaypointLabels(this.parameters.waypoints!);
            this.routeData = this.getStraightLineRouteData();
            const waypointEvent = new CustomEvent("waypointsReady", {});
            this.dispatchEvent(waypointEvent);
            const directionsEvent = new CustomEvent("directionsReturned", { detail: this.routeData });
            this.dispatchEvent(directionsEvent);
            if (this.debug)
                console.debug('Route Data', this.routeData);
            const coordinatesArray: CoordinatesArray = this.waypoints.map(
                ({ longitude, latitude }) => [longitude, latitude]
            );
            this.routeLayers = [
                this.getEndpointLayerSpecification(
                    coordinatesArray[0],
                    coordinatesArray.at(-1)!
                ),
                this.getRouteLayerSpecification(coordinatesArray),
            ];
            this.updateWaypointLayerSource()
            this.addMapLayers();

            this.fitBounds.points = coordinatesArray;
            const fitBoundsEvent = new CustomEvent("fitBoundsEnd", {});
            const fitBoundsHandler = () => {
                this._fitToScreen = true;
                this.dispatchEvent(fitBoundsEvent);
                if (this.debug) console.debug('Route fitBounds complete');
                this.fitBounds.removeEventListener('fitScreenBoundsEnd', fitBoundsHandler);
            };
            this.fitBounds.addEventListener('fitScreenBoundsEnd', fitBoundsHandler);
            this.fitBounds.fitScreenBounds();
        })
    }

    /**
     * Generates route data representing a straight-line path between each pair of consecutive waypoints.
     *
     * Iterates through the list of waypoints, creating a route leg for each segment between two points.
     * Each leg contains a single step with geometry and distance information. The total distance is
     * accumulated across all legs. The resulting route data includes all legs, the total distance,
     * and placeholder values for duration and weight.
     *
     * @returns {RouteData} An object containing the geometry, legs, total distance, and other route metadata.
     */
    private getStraightLineRouteData(): RouteData {
        const legs: RouteLegData[] = [];
        const wps: WayPoints = this.waypoints;
        let cumulativeDistance: number = 0;
        let startLngLat: mapboxgl.LngLat = new mapboxgl.LngLat(wps[0].longitude, wps[0].latitude);
        wps.forEach((wp, index) => {
            if (index < wps.length - 1) {
                const endLngLat: mapboxgl.LngLat = new mapboxgl.LngLat(wps[index + 1].longitude, wps[index + 1].latitude);
                const distance: number = startLngLat.distanceTo(endLngLat);

                legs.push({
                    steps: [
                        {
                            maneuver: { location: [0, 0], instruction: "" },
                            geometry: {
                                coordinates: [
                                    startLngLat.toArray(),
                                    endLngLat.toArray()
                                ]
                            },
                            duration: 0,
                            distance: distance,
                            name: wp.name!
                        },
                    ],
                    duration: 0,
                    distance: distance
                })
                startLngLat = endLngLat;
                cumulativeDistance += distance;
            }
        });

        return {
            geometry: {
                coordinates: [],
                type: "LineString"
            },
            legs: legs,
            distance: cumulativeDistance,
            duration: 0,
            weight_name: "",
            weight: 0
        }
    }

    /**
     * Updates the labels (names) of waypoints that are missing or have empty names.
     *
     * This method attempts to assign meaningful names to waypoints by:
     * 1. Using existing route data, if available, to extract step names from route legs.
     * 2. If route data is not available, it tries to:
     *    - Retrieve a feature name using Mapbox Assist's `getFeatureByLngLat`.
     *    - Fallback to searching for features using a `mapboxgl.Point` object.
     *    - As a last resort, make an HTTP request to the Mapbox Directions API to obtain a step name.
     * 3. If no name can be determined, assigns a default label with an incremented index.
     *
     * @param waypoints - The array of waypoints to update.
     * @returns A promise that resolves to the updated array of waypoints with labels assigned.
     * @throws Will throw an error if updating waypoint labels fails.
     */
    async updateWaypointLabels(waypoints: WayPoints): Promise<WayPoints> {
        try {
            const missingLabels = waypoints
                .map((wp, index) => (!wp.name || wp.name.trim() === "") ? { wp, index } : null)
                .filter(Boolean) as { wp: Waypoint; index: number }[];
            if (missingLabels.length === 0) return waypoints; // No updates needed
            const requests = missingLabels.map(async ({ wp }) => {
                const foundFeatureResult = await this.featureLayerManager.findFeatureNameAtCoord([wp.longitude, wp.latitude]);
                if (foundFeatureResult.name) wp.name = foundFeatureResult.name;
            });
            const results = await Promise.all(requests);
            missingLabels.forEach(({ wp }) => {
                wp.name = wp.name || `${this.settings.pins.defaultLabel} #${waypoints.indexOf(wp) + 1}`;
            });
        } catch (error) {
            console.error('Error updating waypoint labels:', error);
            throw new Error('Failed to update waypoint labels');
        }

        return waypoints;
    }

    /**
     * Generates and updates a Mapbox GL layer specification for a route line based on the provided step coordinates.
     *
     * This method creates or updates a GeoJSON source with the given coordinates and returns a layer definition
     * object that can be used to render the route on the map. If the source already exists, it updates its data;
     * otherwise, it creates a new source.
     *
     * @param stepCoordinates - An array of coordinates representing the route steps to be displayed as a line.
     * @returns A `LayerDefinition` object containing the source and layer configuration for the route.
     */
    private getRouteLayerSpecification(stepCoordinates: CoordinatesArray): LayerDefinition {
        const geojsonData: FeatureCollection<LineString> = {
            type: "FeatureCollection",
            features: [
                {
                    type: "Feature",
                    properties: { type: "line" },
                    geometry: {
                        type: "LineString",
                        coordinates: stepCoordinates
                    }
                }
            ]
        };

        const source = this.map.getSource(MAPBOX.ROUTE_SOURCE_ID) as mapboxgl.GeoJSONSource;
        if (source) {
            // Update existing source
            source.setData(geojsonData);
        } else {
            // Create new source
            this.map.addSource(MAPBOX.ROUTE_SOURCE_ID, {
                type: "geojson",
                data: geojsonData
            });
        }

        return {
            source: {
                id: MAPBOX.ROUTE_SOURCE_ID,
                geoJsonData: geojsonData
            },
            layer: {
                id: MAPBOX.ROUTE_LAYER_ID,
                type: "line",
                metadata: { route: true },
                source: MAPBOX.ROUTE_SOURCE_ID,
                layout: {
                    "line-join": "round",
                    "line-cap": "round",
                },
                paint: {
                    "line-color": this.settings.line.color,
                    "line-width": this.settings.line.width,
                    "line-opacity": this.settings.line.opacity
                }
            }
        };
    }

    /**
     * Generates a Mapbox layer specification for displaying route endpoints (start and end points) as circle markers.
     *
     * This method creates or updates a GeoJSON source containing two point features: one for the start and one for the end coordinate.
     * It then returns a layer definition that visualizes these points with customizable circle radius and color, based on the endpoint type.
     *
     * @param start - The coordinates of the route's starting point.
     * @param end - The coordinates of the route's ending point.
     * @returns A `LayerDefinition` object containing the source and layer configuration for the route endpoints.
     */
    private getEndpointLayerSpecification(start: Coordinates, end: Coordinates): LayerDefinition {
        const geojsonData: FeatureCollection<GeoJsonPoint> = {
            type: "FeatureCollection",
            features: [
                {
                    type: "Feature",
                    properties: { type: "start" },
                    geometry: {
                        type: "Point",
                        coordinates: start
                    }
                },
                {
                    type: "Feature",
                    properties: { type: "end" },
                    geometry: {
                        type: "Point",
                        coordinates: end
                    }
                }
            ]
        };

        const source = this.map.getSource(MAPBOX.ROUTE_ENDPOINTS_SOURCE_ID) as mapboxgl.GeoJSONSource;
        if (source) {
            // Update existing source
            source.setData(geojsonData);
        } else {
            // Create new source
            this.map.addSource(MAPBOX.ROUTE_ENDPOINTS_SOURCE_ID, {
                type: "geojson",
                data: geojsonData
            });
        }

        return {
            source: {
                id: MAPBOX.ROUTE_ENDPOINTS_SOURCE_ID,
                geoJsonData: geojsonData
            },
            layer: {
                id: MAPBOX.ROUTE_ENDPOINTS_LAYER_ID,
                type: "circle",
                metadata: { route: true },
                source: MAPBOX.ROUTE_ENDPOINTS_SOURCE_ID,
                paint: {
                    "circle-radius": this.settings.endPoints.radius,
                    "circle-color": [
                        "match",
                        ["get", "type"], // Match based on the 'type' property
                        "start", this.settings.endPoints.startColor,
                        "end", this.settings.endPoints.endColor,
                        "transparent" // Default color (if needed)
                    ],
                    "circle-pitch-alignment": "map",
                    "circle-pitch-scale": "viewport"
                }
            }
        }
    }

    /**
     * Updates or creates the GeoJSON source for waypoint pins on the map.
     *
     * Filters the provided waypoints (or the instance's waypoints by default) to include only those with `showPin` set to true,
     * then constructs a GeoJSON FeatureCollection of mapboxgl.Point features for each visible waypoint.
     * Each feature includes the waypoint's name and routability in its properties.
     * The resulting GeoJSON data is set as the data for the map source identified by `WAYPOINTS_SOURCE_ID`.
     * If the source already exists, its data is updated; otherwise, a new source is added to the map.
     *
     * @param waypoints - An optional array of waypoints to use. Defaults to the instance's `waypoints` property.
     * @returns The constructed GeoJSON FeatureCollection representing the visible waypoints.
     */
    updateWaypointLayerSource(waypoints: WayPoints = this.waypoints): FeatureCollection<GeoJsonPoint> {
        const geojsonData: FeatureCollection<GeoJsonPoint> = {
            type: "FeatureCollection",
            features: waypoints
                .filter(wp => wp.showPin)
                .map((wp, index) => ({
                    type: "Feature",
                    id: index,
                    properties: {
                        name: wp.name,
                        isRoutable: wp.isRoutable !== false
                    },
                    geometry: {
                        type: "Point",
                        coordinates: [wp.longitude, wp.latitude]
                    }
                }))
        };
        // Add or update source
        if (this.map.getSource(MAPBOX.WAYPOINTS_SOURCE_ID)) {
            (this.map.getSource(MAPBOX.WAYPOINTS_SOURCE_ID) as mapboxgl.GeoJSONSource).setData(geojsonData);
        } else {
            this.map.addSource(MAPBOX.WAYPOINTS_SOURCE_ID, { type: "geojson", data: geojsonData });
        }

        return geojsonData;
    }

    /**
     * Configures and adds the waypoint layer to the map if it does not already exist.
     *
     * This method updates the GeoJSON source for waypoints, defines the layer specification
     * with appropriate layout and paint properties (such as icon image, size, color, and opacity),
     * and adds the layer to the map. It also initializes waypoint markers and sets up
     * interaction handlers for waypoints.
     *
     * @private
     */
    private getWaypointLayerSpecification(): void {
        const geojsonData: FeatureCollection<GeoJsonPoint> = this.updateWaypointLayerSource();
        if (!this.map.getLayer(MAPBOX.WAYPOINTS_LAYER_ID)) {
            const layerDefinition: LayerDefinition = {
                source: {
                    id: MAPBOX.WAYPOINTS_SOURCE_ID,
                    geoJsonData: geojsonData
                },
                layer: {
                    id: MAPBOX.WAYPOINTS_LAYER_ID,
                    type: "symbol",
                    source: MAPBOX.WAYPOINTS_SOURCE_ID,
                    layout: {
                        "icon-image": this.settings.pins.icon.id,
                        "icon-size": this.settings.pins.size,
                        "icon-allow-overlap": true,
                        "icon-ignore-placement": true,
                        "icon-rotation-alignment": "viewport",
                        "icon-anchor": "bottom"
                    },
                    paint: {
                        "icon-opacity": ["case", ["boolean", ["feature-state", "hover"], false], 1, 0.7],
                        "icon-color": ["case", ["==", ["get", "isRoutable"], false], this.settings.pins.color.notRoutable, this.settings.pins.color.default]
                    }
                }
            }
            this.map.addLayer(layerDefinition.layer);
            this.loadWaypointMarker();
            this.addWaypointInteraction();
        }
    }

    /**
     * Loads a waypoint marker icon onto the map if it hasn't been loaded already.
     *
     * This method checks if the waypoint marker image (specified by `this.settings.pins.icon.id`)
     * is already present in the map's image registry. If not, it attempts to load the image from
     * the provided source (`icon.src`). Upon successful loading, the image is added to the map
     * with the specified ID and SDF (Signed Distance Field) enabled for better rendering.
     *
     * If an error occurs during image loading, an error message is logged to the console.
     *
     * @private
     */
    private loadWaypointMarker(): void {
        const icon = this.settings.pins.icon
        if (!this.map.hasImage(icon.id)) {
            this.map.loadImage(icon.src, (error, image) => {
                if (error) {
                    console.error('Waypoint Marker already loaded');
                    return;
                }
                if (!this.map.hasImage(icon.id))
                    this.map.addImage(icon.id, (image as ImageData | ImageBitmap | HTMLImageElement), { sdf: true });
            });
        }
    }

    /**
     * Adds mouse interaction handlers for waypoint features on the map.
     *
     * This method sets up event listeners for mouse enter and leave events on the waypoints layer.
     * When the mouse enters a waypoint feature, it highlights the feature and changes the cursor to a pointer.
     * When the mouse leaves, it removes the highlight and resets the cursor.
     *
     * Handlers are stored as instance properties for later removal if needed.
     *
     * @private
     */
    private addWaypointInteraction(): void {
        // Define handlers and store references
        this.mouseenterHandler = (e: mapboxgl.MapMouseEvent) => {
            if (!e.features || e.features.length === 0) return;
            const featureId = e.features[0].id;
            if (featureId !== undefined) {
                this.hoveredFeatureId = featureId;
                this.map.setFeatureState({ source: MAPBOX.WAYPOINTS_SOURCE_ID, id: featureId }, { hover: true });
            }
            this.map.getCanvas().style.cursor = "pointer";
        };

        this.mouseleaveHandler = () => {
            if (this.hoveredFeatureId !== null) {
                this.map.setFeatureState({ source: MAPBOX.WAYPOINTS_SOURCE_ID, id: this.hoveredFeatureId }, { hover: false });
                this.hoveredFeatureId = null;
            }
            this.map.getCanvas().style.cursor = "";
        };
        // Add event listeners
        this.map.on("mouseenter", MAPBOX.WAYPOINTS_LAYER_ID, this.mouseenterHandler);
        this.map.on("mouseleave", MAPBOX.WAYPOINTS_LAYER_ID, this.mouseleaveHandler);
    }

    /**
     * Removes event listeners related to waypoint interactions from the map.
     *
     * This method detaches the 'mouseenter' and 'mouseleave' event handlers from the map,
     * if they are currently set, and resets their references to `undefined`.
     * It is typically used to clean up event listeners when waypoint interaction is no longer needed.
     */
    private removeWaypointInteraction(): void {
        if (this.mouseenterHandler) {
            this.map.off("mouseenter", this.mouseenterHandler);
            this.mouseenterHandler = undefined;
        }
        if (this.mouseleaveHandler) {
            this.map.off("mouseleave", MAPBOX.WAYPOINTS_LAYER_ID, this.mouseleaveHandler);
            this.mouseleaveHandler = undefined;
        }
    }

}
